-- Schema for Domain: compliance | Business: Life Insurance | Version: v1_ecm
-- Generated on: 2026-05-04 03:46:12

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `life_insurance_ecm`.`compliance` COMMENT 'Governs regulatory compliance obligations across all jurisdictions — NAIC, state DOI filings, SEC/FINRA for variable products, IRS 7702/72 tax compliance, AML/BSA/KYC (FinCEN), HIPAA privacy, SOX controls, DOL fiduciary (ERISA), and ORSA/ERM reporting. Owns regulatory filing calendars, market conduct examination records, suitability reviews, examination findings, remediation tracking, compliance attestation workflows, and compliance training records.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`regulatory_obligation` (
    `regulatory_obligation_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory obligation record in the master compliance registry. Serves as the primary key for all downstream joins and compliance tracking workflows.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Regulatory obligations apply to specific legal entities based on domicile state, licensed jurisdictions, lines of business. Obligation tracking must be entity-specific for compliance management.',
    `comm_template_id` BIGINT COMMENT 'Foreign key linking to correspondence.comm_template. Business justification: Regulatory obligations mandate specific customer notices (free-look periods, policy delivery, annual disclosures). Real business process: compliance-driven communication template management ensuring r',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: A regulatory_obligation implements or is governed by a specific state_regulation. This FK establishes the relationship between the obligation and the state-specific regulatory requirement it fulfills.',
    `tax_provision_id` BIGINT COMMENT 'Foreign key linking to finance.tax_provision. Business justification: Certain regulatory obligations (IRC 7702 compliance, ERISA qualified plan requirements) directly impact tax treatment of insurance products and tax provision calculations (DAC tax, reserve deductions)',
    `aml_bsa_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to AML/BSA compliance programs, including KYC, Suspicious Activity Reports (SAR), Currency Transaction Reports (CTR), or FinCEN program requirements. Drives routing to the AML compliance team.',
    `applicable_product_lines` STRING COMMENT 'Pipe-delimited list of insurance product lines to which this obligation applies (e.g., WL|UL|IUL|VUL|FIA|SPIA|LTC|DI). Null or ALL for enterprise-wide obligations. Enables scoping of compliance activities to relevant business units and product portfolios.',
    `applicable_states` STRING COMMENT 'Pipe-delimited list of US state or territory codes (2-letter USPS abbreviations) where this obligation applies (e.g., CA|NY|TX|FL). Null or ALL for federal obligations applicable in all jurisdictions. Used to scope market conduct and state DOI filing requirements.',
    `compliance_domain` STRING COMMENT 'Primary compliance program domain to which this obligation belongs. Drives assignment to the appropriate compliance team and reporting hierarchy. Examples: AML_BSA (Anti-Money Laundering/Bank Secrecy Act), KYC (Know Your Customer), HIPAA (health data privacy), SOX (Sarbanes-Oxley financial controls), ERISA_DOL (fiduciary/retirement), tax_compliance (IRS 7702/72), market_conduct (NAIC/state DOI), solvency (RBC/ORSA/ERM), suitability (FINRA), privacy (state privacy laws). [ENUM-REF-CANDIDATE: AML_BSA|KYC|HIPAA|SOX|ERISA_DOL|tax_compliance|market_conduct|solvency|suitability|privacy — 10 candidates stripped; promote to reference product]',
    `compliance_owner` STRING COMMENT 'Full name or employee identifier of the designated compliance officer or manager who owns accountability for this obligation. This individual is responsible for ensuring timely and accurate fulfillment and is the primary escalation contact.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this regulatory obligation record was first created in the compliance registry. Provides the audit trail entry point for the obligation lifecycle and supports SOX IT general controls documentation.',
    `effective_date` DATE COMMENT 'The date on which this regulatory obligation first became applicable to the company. Marks the start of the compliance obligation lifecycle. Used to determine historical applicability and retroactive filing requirements.',
    `escalation_contact` STRING COMMENT 'Full name or employee identifier of the senior officer or executive to whom this obligation is escalated if the internal preparation deadline is missed or a compliance risk is identified. Typically the Chief Compliance Officer or General Counsel.',
    `escalation_threshold_days` STRING COMMENT 'Number of calendar days before the statutory due date at which an automated escalation alert is triggered if the obligation has not been completed. Drives the compliance calendar alert engine and executive notification workflows.',
    `expiration_date` DATE COMMENT 'The date on which this regulatory obligation ceases to apply, if applicable. Null for open-ended, ongoing obligations. Populated for time-limited regulations, sunset provisions, or temporary regulatory waivers.',
    `filing_frequency` STRING COMMENT 'How often this regulatory obligation must be fulfilled. Drives the compliance calendar generation logic and deadline scheduling. ad_hoc = triggered by a specific business event (e.g., material change, acquisition); event_triggered = triggered by a policyholder or claim event. [ENUM-REF-CANDIDATE: annual|semi_annual|quarterly|monthly|ad_hoc|event_triggered|biennial — 7 candidates stripped; promote to reference product]',
    `filing_period_end_date` DATE COMMENT 'The end date of the reporting or filing period covered by this obligation instance (e.g., December 31 for an annual filing). Together with filing_period_start_date, defines the data scope for the filing.',
    `filing_period_start_date` DATE COMMENT 'The start date of the reporting or filing period covered by this obligation instance (e.g., January 1 for an annual filing). Defines the data scope for the filing and aligns with the statutory reporting period.',
    `governing_body` STRING COMMENT 'Name of the regulatory authority or governing body that mandates this obligation (e.g., NAIC, SEC, FINRA, IRS, DOL, FinCEN, FASB, State DOI — California, IAIS). Drives routing of filings and escalation contacts. [ENUM-REF-CANDIDATE: NAIC|SEC|FINRA|IRS|DOL|FinCEN|FASB|State DOI|IAIS|ACORD — promote to reference product]',
    `grace_period_days` STRING COMMENT 'Number of calendar days after the statutory due date within which the obligation may still be fulfilled without incurring a penalty, as permitted by the governing body. Zero if no grace period is allowed. Used in escalation threshold calculations.',
    `hipaa_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation involves HIPAA Privacy Rule or Security Rule compliance, including protected health information (PHI) handling, breach notification, or business associate agreement requirements.',
    `internal_preparation_deadline` DATE COMMENT 'Enterprise-set internal deadline for completing all preparation, review, and approval activities prior to the statutory due date. Provides buffer time for quality review, legal sign-off, and executive attestation. Typically set 5–15 business days before the statutory due date.',
    `is_attestation_required` BOOLEAN COMMENT 'Indicates whether this obligation requires a formal officer or executive attestation (e.g., SOX CEO/CFO certification, ORSA officer sign-off). When true, the compliance workflow must include an attestation step before submission.',
    `is_external_filing` BOOLEAN COMMENT 'Indicates whether this obligation requires submission of a document or report to an external regulatory body (true) or is an internal compliance activity only (false), such as an internal audit or training completion record.',
    `is_material_obligation` BOOLEAN COMMENT 'Indicates whether this obligation is classified as material for SOX, ORSA, or ERM reporting purposes. Material obligations receive heightened monitoring, executive visibility, and are included in the Board-level compliance dashboard.',
    `jurisdiction_type` STRING COMMENT 'Indicates whether this obligation is imposed at the federal, state, multi-state, or international level. Drives routing to the appropriate legal and compliance team and determines which state DOI contacts are relevant.. Valid values are `federal|state|multi_state|international`',
    `last_amended_date` DATE COMMENT 'The date on which the underlying regulation or rule governing this obligation was most recently amended or updated by the governing body. Triggers a compliance review to assess whether the obligation scope, format, or deadline has changed.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this regulatory obligation record was most recently modified in the compliance registry. Used to detect stale records, trigger re-review workflows, and support audit trail requirements under SOX and NAIC market conduct standards.',
    `ldti_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to FASB ASC 944-40 Long Duration Targeted Improvements (LDTI) accounting standard compliance, including updated reserve calculations, discount rate assumptions, and enhanced disclosures for long-duration insurance contracts.',
    `obligation_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this regulatory obligation within the enterprise compliance calendar (e.g., NAIC-ORSA-ANN, IRS-7702-QTR, SEC-N-CEN-ANN). Used as the business-facing identifier in filings, dashboards, and audit correspondence.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `obligation_name` STRING COMMENT 'Full descriptive name of the regulatory obligation as recognized by the governing body (e.g., Annual ORSA Summary Report, Form N-CEN Annual Report, NAIC Risk-Based Capital Report). Used in compliance calendars, executive dashboards, and regulatory correspondence.',
    `obligation_notes` STRING COMMENT 'Free-text field for compliance team annotations, regulatory guidance interpretations, special instructions, or contextual notes relevant to fulfilling this obligation. May include references to regulatory guidance letters, no-action letters, or internal legal opinions.',
    `obligation_status` STRING COMMENT 'Current lifecycle status of the regulatory obligation within the enterprise compliance registry. active = currently enforceable; suspended = temporarily waived by regulator; retired = no longer applicable; pending_effective = enacted but not yet in force; under_review = applicability being assessed by compliance team.. Valid values are `active|suspended|retired|pending_effective|under_review`',
    `obligation_type` STRING COMMENT 'Classification of the nature of the compliance obligation. filing = periodic regulatory report submission; examination = market conduct or financial exam; attestation = SOX/officer certification; disclosure = required customer or public disclosure; training = mandatory compliance training; audit = internal or external audit; notification = event-triggered regulatory notice; registration = product or entity registration. [ENUM-REF-CANDIDATE: filing|examination|attestation|disclosure|training|audit|notification|registration — 8 candidates stripped; promote to reference product]',
    `orsa_erm_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is part of the ORSA or ERM reporting framework, including the annual ORSA Summary Report submitted to state regulators. Used to scope the ERM compliance calendar and Board risk reporting.',
    `pbr_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is related to NAIC Principle-Based Reserving (PBR) compliance, including VM-20 (life insurance reserves), VM-21 (variable annuity reserves), and VM-31 (PBR actuarial report) requirements. Used to scope actuarial compliance activities.',
    `penalty_amount_usd` DECIMAL(18,2) COMMENT 'Maximum or standard monetary penalty in US dollars that may be assessed for non-compliance with this obligation. Used in risk quantification, ERM reporting, and prioritization of compliance resources. Null if penalty is non-monetary (e.g., license suspension).',
    `penalty_description` STRING COMMENT 'Narrative description of the regulatory penalties, fines, or sanctions that may be imposed for non-compliance or late filing (e.g., $100 per day late fee, license suspension, cease and desist order). Informs risk prioritization and escalation urgency.',
    `priority_level` STRING COMMENT 'Enterprise-assigned priority classification for this obligation based on regulatory risk, penalty severity, and business impact. critical = Board-level visibility, zero tolerance for non-compliance; high = executive escalation required if at risk; medium = standard compliance monitoring; low = routine administrative obligation.. Valid values are `critical|high|medium|low`',
    `rbc_relevance_flag` BOOLEAN COMMENT 'Indicates whether this obligation is directly related to NAIC Risk-Based Capital (RBC) reporting or solvency compliance. Used to prioritize obligations in the actuarial and finance compliance calendar and to scope RBC-related remediation activities.',
    `regulation_citation` STRING COMMENT 'Formal legal or regulatory citation for the rule or statute that creates this obligation (e.g., IRC Section 7702, NAIC Model Regulation #820, ERISA Section 404, ASC 944-40 LDTI, FinCEN 31 CFR Part 1010). Enables precise traceability to source regulation for audit and legal review.',
    `renewal_cycle_months` STRING COMMENT 'Number of months in the renewal or recurrence cycle for this obligation (e.g., 12 for annual, 3 for quarterly, 1 for monthly). Used by the compliance calendar engine to auto-generate future obligation instances. Null for one-time or event-triggered obligations.',
    `responsible_department` STRING COMMENT 'Name of the internal department or business unit primarily responsible for fulfilling this obligation (e.g., Actuarial, Legal & Compliance, Finance, Tax, Operations, Investment Management). Used for workload assignment and escalation routing.',
    `source_system` STRING COMMENT 'Name of the operational system of record from which this obligation record originates or is primarily managed (e.g., Compliance Calendar System, Policy Administration System, Actuarial Valuation System). Supports data lineage and ETL traceability in the lakehouse.',
    `statutory_due_date` DATE COMMENT 'The legally mandated deadline by which this obligation must be fulfilled as specified by the governing body or regulation. For recurring obligations, this represents the due date for the current or next filing period. Failure to meet this date may result in regulatory penalties.',
    `submission_channel` STRING COMMENT 'The required or preferred method by which this obligation must be submitted to the governing body. electronic = NAIC SERFF or similar; portal = regulator-specific web portal (e.g., SEC EDGAR, IRS e-file); api = machine-to-machine submission; paper = physical mailing.. Valid values are `electronic|paper|portal|email|api|in_person`',
    `submission_format` STRING COMMENT 'The required data format or form number for the filing submission (e.g., NAIC Annual Statement Blank, Form N-CEN, Form 5500, SAR FinCEN 111, ACORD XML). Ensures the compliance team prepares the filing in the correct format required by the governing body.',
    CONSTRAINT pk_regulatory_obligation PRIMARY KEY(`regulatory_obligation_id`)
) COMMENT 'Master registry of all regulatory obligations, filing deadlines, and compliance calendar entries applicable to Life Insurance operations across all jurisdictions. Each obligation captures the governing body, regulation citation, effective date, applicability scope (product lines, states), compliance owner, filing frequency (annual, quarterly, monthly, ad hoc), statutory due date, internal preparation deadline, grace period, escalation thresholds, responsible department, and renewal cycle. Serves as the single authoritative source for what must be done, by whom, and by when — functioning as both the obligation registry and the enterprise compliance calendar for proactive deadline management.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`regulatory_filing` (
    `regulatory_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory filing record in the compliance data product. Primary key for the regulatory_filing table.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: Some state filings are agency-specific: agency appointment/termination notifications, agency E&O coverage reporting, agency license renewals. Regulatory_filing needs agency_id to track these agency-le',
    `amended_filing_regulatory_filing_id` BIGINT COMMENT 'Reference to the original regulatory_filing_id that this record amends or corrects. Null for original filings. Enables lineage tracking across filing versions and amendment chains.',
    `employee_id` BIGINT COMMENT 'Identifier of the officer or senior compliance official who reviewed and approved the filing prior to submission. Required for SOX attestation and NAIC officer certification workflows.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory filing preparation costs (legal, actuarial, compliance staff time) are allocated to cost centers for expense tracking, budgeting, and SOX control over compliance expenditures. Standard fina',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Regulatory filings generate submission confirmations, rejection notices, and follow-up correspondence with regulators. Real business process: filing submission and response tracking workflow in life i',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Regulatory filings frequently use third-party filing services, actuarial consultants, or legal counsel for preparation and submission. Tracks outsourced filing service provider for audit trail and ven',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Some regulatory filings are policy-specific (e.g., variable product registrations, individual policy filings for large cases). Linking enables tracking of policy-level regulatory submissions and suppo',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Regulatory filings generate supporting documents (actuarial memos, board resolutions, exhibits, submission confirmations) that must be retained per regulatory requirements. Essential for audit trail a',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Filing fees, late filing penalties, and associated costs are journalized. Standard accounting practice for regulatory compliance expenses and penalty accruals.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Regulatory filings are submitted by specific legal entities (insurance companies within a holding company structure). The regulatory_filing product currently lacks a direct legal entity FK. Adding leg',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Investment-related regulatory filings (NAIC Schedule D, RBC reports, annual statement) reference specific portfolios. Real business process: statutory reporting, investment schedule preparation, portf',
    `primary_regulatory_employee_id` BIGINT COMMENT 'Identifier of the internal employee or team responsible for preparing and assembling the regulatory filing. Links to the employee or user master for accountability and SOX control documentation.',
    `producer_id` BIGINT COMMENT 'Foreign key linking to agent.producer. Business justification: State DOIs require filings for producer terminations for cause, E&O coverage lapses, and license revocations. Regulatory_filing tracks these producer-specific state notifications required by insurance',
    `rbc_calculation_id` BIGINT COMMENT 'Foreign key linking to finance.rbc_calculation. Business justification: Annual statement filings include or reference RBC calculations. Direct regulatory reporting relationship - RBC filing is often part of broader annual statement filing package to state regulators.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Regulatory filings execute specific regulatory obligations. Each filing fulfills an obligation from the master registry. The obligation defines the filing type, governing body, and jurisdiction, makin',
    `report_period_id` BIGINT COMMENT 'Foreign key linking to reporting.report_period. Business justification: Regulatory filings are prepared for standardized reporting periods (quarterly, annual). Links filing to the period definition for close calendar management and deadline tracking. Replaces denormalized',
    `report_run_id` BIGINT COMMENT 'Foreign key linking to reporting.report_run. Business justification: Regulatory filings (NAIC statements, RBC) are generated by scheduled report runs. Links filing to the execution metadata for audit trail and automated filing generation tracking.',
    `acceptance_date` DATE COMMENT 'The date on which the governing body formally accepted or acknowledged the filing as complete and compliant. Null if the filing has not yet been accepted. Distinguishes submission date from regulatory acceptance, which may differ for filings requiring review.',
    `aml_transaction_type` STRING COMMENT 'For FinCEN filings, identifies whether this is a Suspicious Activity Report (SAR) or Currency Transaction Report (CTR). Applicable only to FinCEN/BSA filings. Null for non-AML filing types. Supports AML/BSA compliance tracking.. Valid values are `SAR|CTR|other`',
    `approval_date` DATE COMMENT 'The date on which the designated approver formally signed off on the filing prior to submission. Required for SOX internal control documentation and NAIC officer certification.',
    `approver_name` STRING COMMENT 'Full name of the officer or compliance official who approved the filing. Retained for audit trail and regulatory examination purposes.',
    `board_approval_date` DATE COMMENT 'The date on which the companys Board of Directors formally approved the filing prior to submission. Required for ORSA reports and certain NAIC annual statement certifications. Null for filings that do not require board-level approval.',
    `capital_adequacy_conclusion` STRING COMMENT 'The conclusion reached in the ORSA or RBC filing regarding the insurers capital adequacy relative to its risk profile (e.g., adequate, inadequate, marginal). Applicable to ORSA and RBC-related filings. Null for non-capital filings.. Valid values are `adequate|inadequate|marginal|under_review`',
    `confirmation_reference` STRING COMMENT 'The acknowledgment or confirmation number returned by the governing bodys filing system upon successful receipt of the submission (e.g., NAIC confirmation number, SEC accession number, DOL EFAST2 confirmation, FinCEN BSA tracking number). Serves as the authoritative proof of submission.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this regulatory filing record was first created in the compliance system. Provides the audit trail entry point for the filing lifecycle. Aligns with SOX internal control documentation requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for any monetary amounts reported in this filing (e.g., USD). Primarily USD for domestic US regulatory filings. Required when penalty_amount or other monetary fields are populated.. Valid values are `^[A-Z]{3}$`',
    `days_late` STRING COMMENT 'Number of calendar days by which the filing was submitted after the statutory due date. Zero or negative if filed on time. Used to assess late-filing penalties and regulatory exposure. Calculated as submission_date minus due_date.',
    `due_date` DATE COMMENT 'The statutory or regulatory deadline by which this filing must be submitted to the governing body. Used to calculate timeliness, trigger escalation workflows, and assess late-filing penalties. Derived from the regulatory calendar for the applicable filing type and jurisdiction.',
    `erisa_plan_type` STRING COMMENT 'Classification of the ERISA-covered plan reported in this DOL Form 5500 filing (e.g., group life, 401k annuity, pension, welfare). Applicable only to ERISA filings. Null for non-ERISA filing types.. Valid values are `group_life|401k_annuity|pension|welfare|other`',
    `examination_reference` STRING COMMENT 'Reference number or identifier linking this filing to a related state DOI market conduct examination or regulatory inquiry. Applicable when the filing is submitted in response to or in connection with a regulatory examination. Null if not examination-related.',
    `fiduciary_designation` STRING COMMENT 'Name or role of the designated fiduciary responsible for the ERISA plan covered by this filing. Required for DOL Form 5500 and DOL fiduciary compliance under ERISA. Null for non-ERISA filing types.',
    `filing_channel` STRING COMMENT 'The transmission method used to submit the filing to the governing body (e.g., electronic via NAIC SERFF, SEC EDGAR, DOL EFAST2, FinCEN BSA E-Filing portal, or paper submission). Relevant for audit trail and submission confirmation tracking.. Valid values are `electronic|paper|portal|api`',
    `filing_form_name` STRING COMMENT 'The official name or designation of the regulatory form used for this filing (e.g., NAIC Life/Health Annual Statement, SEC Form N-4, IRS Form 1099-R, FinCEN Form 112 CTR, DOL Form 5500, ORSA Summary Report). Provides precise identification of the statutory instrument.',
    `filing_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the filing — either generated internally or assigned by the receiving regulatory body upon submission (e.g., NAIC filing reference, SEC accession number, DOL confirmation number). Used for tracking and correspondence with regulators.',
    `filing_status` STRING COMMENT 'Current lifecycle state of the regulatory filing submission. Tracks progression from internal preparation (draft) through submission to the regulator and final disposition (accepted, rejected, withdrawn). Drives compliance workflow and remediation tracking.. Valid values are `draft|submitted|accepted|rejected|under_review|withdrawn`',
    `filing_system_source` STRING COMMENT 'Name of the internal operational system or platform from which the filing data was sourced or generated (e.g., Policy Administration System, Actuarial Valuation System, Claims Management System). Supports data lineage and ETL traceability.',
    `filing_version` STRING COMMENT 'Version or amendment number of this filing submission (e.g., original, amendment_1, corrected). Tracks whether this is the initial submission or a subsequent amendment/correction filed with the governing body.',
    `is_amended` BOOLEAN COMMENT 'Indicates whether this filing is an amendment or correction to a previously submitted filing. True if this is an amended submission; False if this is the original filing. Used to distinguish original from corrected statutory submissions.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this regulatory filing record was most recently modified in the compliance system. Tracks the most recent status change, amendment, or data correction. Supports audit trail and SOX change management controls.',
    `late_filing_flag` BOOLEAN COMMENT 'Indicates whether this filing was submitted after the statutory due date. True if submission_date exceeds due_date; False if filed on time. Used for compliance monitoring, penalty assessment, and regulatory examination preparation.',
    `lead_state_code` STRING COMMENT 'Two-character US state code identifying the lead state regulator for ORSA filings and multi-state regulatory submissions. The lead state coordinates review among all states where the insurer is licensed. Applicable primarily to ORSA and group-level filings.. Valid values are `^[A-Z]{2}$`',
    `notes` STRING COMMENT 'Free-text field for compliance officers to record supplemental context, internal commentary, regulator correspondence notes, or remediation instructions related to this filing. Not transmitted to the regulator; for internal compliance workflow use only.',
    `orsa_risk_categories` STRING COMMENT 'Comma-separated list of risk categories assessed in the ORSA filing (e.g., insurance_risk, market_risk, credit_risk, operational_risk, liquidity_risk). Applicable only to ORSA filings. Null for non-ORSA filing types. Supports ERM and ORSA reporting requirements.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Monetary penalty assessed by the governing body for late or deficient filing, expressed in USD. Null if no penalty was assessed. Used for financial reporting, regulatory expense tracking, and SOX control monitoring.',
    `plan_sponsor_name` STRING COMMENT 'Name of the employer or organization sponsoring the retirement or group benefit plan covered by this ERISA filing (DOL Form 5500). Applicable only to ERISA filings. Null for non-ERISA filing types.',
    `preparer_name` STRING COMMENT 'Full name of the individual responsible for preparing the regulatory filing. Retained for audit trail and regulatory examination purposes even if the employee record changes.',
    `pte_reference` STRING COMMENT 'Reference number or identifier for any Prohibited Transaction Exemption (PTE) cited in the ERISA filing (e.g., PTE 84-24, PTE 2020-02). Applicable to ERISA filings where prohibited transaction exemptions are claimed. Null for non-ERISA filing types.',
    `rejection_date` DATE COMMENT 'The date on which the governing body formally rejected the filing. Populated only when filing_status is rejected. Triggers remediation workflow and resubmission tracking.',
    `rejection_reason` STRING COMMENT 'Textual description or regulator-provided code explaining why the filing was rejected. Populated when filing_status is rejected. Used to drive remediation actions and resubmission preparation.',
    `stress_test_scenarios` STRING COMMENT 'Description or comma-separated list of stress test scenarios included in the ORSA or actuarial filing (e.g., interest_rate_shock, pandemic_mortality, equity_market_decline). Applicable to ORSA and actuarial valuation filings. Null for non-ORSA filing types.',
    `submission_date` DATE COMMENT 'The actual calendar date on which the filing was transmitted to the governing body. Compared against due_date to determine timeliness and potential late-filing exposure. Populated upon successful transmission.',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time (with timezone offset) at which the filing was electronically transmitted to the governing body. Provides audit-grade evidence of timely submission, particularly for filings with intraday deadlines (e.g., FinCEN CTR 15-day rule).',
    CONSTRAINT pk_regulatory_filing PRIMARY KEY(`regulatory_filing_id`)
) COMMENT 'Transactional record of every regulatory filing submitted to governing bodies — NAIC annual/quarterly statements, state DOI market conduct filings, SEC Form N-4/N-6 for variable products, FINRA filings, IRS Form 1099-R/5498, FinCEN SAR/CTR filings, ORSA reports, ERISA Form 5500 filings, and all other statutory submissions. Captures filing type, jurisdiction, submission date, due date, filing status (draft, submitted, accepted, rejected), filing period, preparer, approver, and submission confirmation reference. For ORSA filings: includes risk categories assessed, capital adequacy conclusion, stress test scenarios, board approval date, and lead state designation. For ERISA filings: includes plan sponsor, plan type (group life, 401k annuity, pension), fiduciary designation, prohibited transaction exemption (PTE) references, and DOL filing date. Serves as the single transactional record for all regulatory submissions regardless of filing type or governing body.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`market_conduct_exam` (
    `market_conduct_exam_id` BIGINT COMMENT 'Unique surrogate identifier for each market conduct examination record in the compliance system. Primary key for this entity.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Exam response costs (legal counsel, document production, staff time, remediation) are significant and tracked by cost center for budget variance analysis and management accountability. Required for fi',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Market conduct exams generate extensive correspondence: document requests, information responses, draft report discussions, and final report submissions. Real business process: regulatory examination ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Market conduct exams routinely involve external legal counsel or compliance consultants for exam response coordination, document review, and regulatory negotiation. Tracks legal/consulting vendor supp',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Market conduct exams sample specific policies for review of sales practices, underwriting, claims, and policy administration. Linking exam to sampled policies enables tracking which policies were exam',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Market conduct exams are conducted against specific legal entities. Exam scope, findings, and penalties are entity-specific for regulatory accountability and financial statement impact.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Market conduct exams review investment practices, variable product sales, separate account management, and portfolio compliance. Real business process: regulatory examination, investment compliance re',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Market conduct exams require production of specific standardized reports (policy listings, claims handling reports). Links exam to the report definitions requested by examiners for data request fulfil',
    `appeal_filed` BOOLEAN COMMENT 'Indicates whether the company has filed a formal appeal or objection to the examination findings or enforcement action. True if an appeal has been filed; False otherwise. Triggers legal hold and appeal tracking workflow.',
    `appeal_filed_date` DATE COMMENT 'Date on which the company formally filed its appeal or objection with the state DOI or administrative tribunal. Null if no appeal has been filed. Used to track appeal timelines and regulatory response deadlines.',
    `appeal_resolution` STRING COMMENT 'Outcome of the companys formal appeal of examination findings or enforcement action. Null if no appeal was filed or appeal is still pending. Values: pending (appeal filed, awaiting decision), upheld (original findings confirmed), partially_upheld (some findings modified), overturned (findings reversed), withdrawn (company withdrew appeal).. Valid values are `pending|upheld|partially_upheld|overturned|withdrawn`',
    `cap_approval_date` DATE COMMENT 'Date on which the state DOI formally approved the companys submitted Corrective Action Plan (CAP). Null if the CAP has not yet been approved or is not required. Marks the start of the formal remediation execution period.',
    `cap_submission_date` DATE COMMENT 'Actual date on which the company submitted its Corrective Action Plan (CAP) to the state DOI. Null if the CAP has not yet been submitted. Used to track timeliness of regulatory response and compliance with DOI deadlines.',
    `cap_submission_due_date` DATE COMMENT 'Deadline by which the company must submit its Corrective Action Plan (CAP) to the state DOI. Null if no CAP is required. Triggers internal compliance workflow and executive escalation if approaching without submission.',
    `company_exam_coordinator` STRING COMMENT 'Full name of the internal company employee designated as the primary point of contact and coordinator for this market conduct examination. Responsible for document production, examiner liaison, and internal response coordination.',
    `company_legal_counsel` STRING COMMENT 'Name of the internal or external legal counsel assigned to advise the company during the market conduct examination. Responsible for legal strategy, response drafting, and appeal proceedings if applicable.',
    `company_response_due_date` DATE COMMENT 'Deadline by which the company must submit its formal written response to the draft examination report findings. Calculated from the draft report issuance date per state DOI requirements. Failure to respond by this date may result in findings being finalized without company input.',
    `corrective_action_plan_required` BOOLEAN COMMENT 'Indicates whether the state DOI has required the company to submit a formal Corrective Action Plan (CAP) as a result of examination findings. True if a CAP is required; False if no formal plan is mandated. Drives the corrective action tracking workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market conduct examination record was first created in the compliance management system. Represents the system-of-record audit trail creation event. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `critical_findings_count` STRING COMMENT 'Number of examination findings classified as critical severity — representing systemic violations, significant consumer harm, or material regulatory non-compliance requiring immediate corrective action. Supports executive reporting and regulatory escalation tracking.',
    `draft_report_date` DATE COMMENT 'Date on which the state DOI issued the preliminary draft examination report to the company for review and response. Initiates the companys formal response period, which is typically 30 days under NAIC standards.',
    `exam_close_date` DATE COMMENT 'Date on which the state DOI formally closed the examination after confirming all findings have been remediated or resolved. Represents the end of the examination lifecycle. Null if the examination is still open.',
    `exam_notes` STRING COMMENT 'Free-text field for internal compliance team notes regarding the examination, including context about regulatory relationships, strategic considerations, unusual circumstances, or coordination with other regulatory matters. Not shared with the DOI.',
    `exam_number` STRING COMMENT 'Externally-assigned examination reference number issued by the initiating state Department of Insurance (DOI). Used for correspondence, filings, and cross-referencing with the regulator. Format varies by state DOI.',
    `exam_outcome` STRING COMMENT 'Regulatory outcome or enforcement action resulting from the completed examination. Captures the most severe action taken: no_action (no violations found or all minor), corrective_action_plan (formal CAP required), consent_order (negotiated regulatory agreement), cease_and_desist (order to stop specific practices), license_suspension (temporary license action), monetary_penalty (fine assessed), restitution_ordered (consumer repayment required), multi_action (multiple enforcement actions). [ENUM-REF-CANDIDATE: no_action|corrective_action_plan|consent_order|cease_and_desist|license_suspension|monetary_penalty|restitution_ordered|multi_action — promote to reference product]',
    `exam_period_end_date` DATE COMMENT 'End date of the business activity review period covered by the examination. Defines the latest date of company records and transactions subject to examiner review.',
    `exam_period_start_date` DATE COMMENT 'Start date of the business activity review period covered by the examination. Defines the earliest date of company records and transactions subject to examiner review. Typically spans 3-5 years of prior business activity.',
    `exam_scope` STRING COMMENT 'Narrative description of the business areas, product lines, and practices subject to review in this examination. May reference specific lines of business (life, annuity, disability), functional areas (claims, underwriting, sales, billing), or regulatory concerns (suitability, AML, HIPAA). Derived from the DOI examination notice.',
    `exam_status` STRING COMMENT 'Current lifecycle status of the market conduct examination from initial notification through final closure. Tracks the examination workflow stage: notification_received (DOI notice received), in_progress (active examination underway), draft_report (preliminary findings issued), response_pending (company response to draft due), final_report (final examination report issued), closed (all findings resolved), appealed (company has filed a formal appeal). [ENUM-REF-CANDIDATE: notification_received|in_progress|draft_report|response_pending|final_report|closed|appealed — promote to reference product]',
    `exam_type` STRING COMMENT 'Classification of the market conduct examination by its scope and trigger. Routine examinations are scheduled periodic reviews; targeted examinations focus on specific business practices; multi-state examinations are coordinated across multiple state DOIs; for-cause examinations are triggered by complaints or regulatory concerns; desk examinations are conducted remotely; market analysis examinations are data-driven reviews.. Valid values are `routine|targeted|multi_state|for_cause|desk|market_analysis`',
    `final_report_date` DATE COMMENT 'Date on which the state DOI issued the final examination report incorporating company responses and examiner determinations. This is the official regulatory record of examination findings and required corrective actions.',
    `functional_areas_examined` STRING COMMENT 'Comma-separated list of business functional areas reviewed during the examination (e.g., claims_adjudication, policy_servicing, sales_practices, underwriting, billing, complaint_handling, anti_money_laundering). Supports gap analysis and remediation planning.',
    `initiating_state_code` STRING COMMENT 'Two-letter USPS state abbreviation identifying the lead state Department of Insurance that initiated and is conducting the market conduct examination. For multi-state examinations, this is the lead state coordinating the review.. Valid values are `^[A-Z]{2}$`',
    `lead_examiner_contact` STRING COMMENT 'Email address or phone number of the state DOI lead examiner for official examination correspondence. Used by the companys compliance team to coordinate document requests, schedule interviews, and submit responses.',
    `lead_examiner_name` STRING COMMENT 'Full name of the state DOI lead examiner assigned to conduct and oversee the market conduct examination. Used for correspondence, scheduling, and examination record attribution. This is a regulatory contact, not a company employee.',
    `lines_of_business` STRING COMMENT 'Comma-separated list of insurance product lines included in the examination scope (e.g., whole_life, term_life, annuity, disability_income, long_term_care). Aligns with NAIC line-of-business classifications. Supports product-level finding analysis and trend reporting.',
    `major_findings_count` STRING COMMENT 'Number of examination findings classified as major severity — representing significant but non-systemic violations requiring formal corrective action plans. Supports prioritization of remediation resources.',
    `minor_findings_count` STRING COMMENT 'Number of examination findings classified as minor severity — representing isolated or technical violations with limited consumer impact. Typically addressed through process improvements rather than formal corrective action plans.',
    `monetary_penalty_amount` DECIMAL(18,2) COMMENT 'Total monetary penalty or fine assessed by the state DOI as a result of this examination, expressed in US dollars. Null if no monetary penalty was assessed. Supports financial exposure tracking, SOX controls, and regulatory liability reporting. Classified as confidential due to business-sensitive financial exposure.',
    `notification_date` DATE COMMENT 'Date on which the company received official written notification from the state Department of Insurance of the upcoming or initiated market conduct examination. Triggers internal response timelines and document preservation obligations.',
    `onsite_end_date` DATE COMMENT 'Date on which the active on-site (or remote desk) examination phase concluded and examiners departed or ceased active record review. Marks the transition to report drafting phase.',
    `onsite_start_date` DATE COMMENT 'Date on which examiners physically arrived at company premises (or commenced remote access for desk examinations) to begin active review of records and interviews. Null for market analysis examinations that are entirely data-driven.',
    `participating_states` STRING COMMENT 'Comma-separated list of two-letter USPS state abbreviations for all states participating in a multi-state market conduct examination, excluding the initiating state. Null or empty for single-state examinations. Supports multi-state coordination tracking per NAIC protocols.',
    `prior_exam_reference` STRING COMMENT 'Examination number of the prior market conduct examination that this examination follows up on, if applicable. Null if this is not a repeat examination. Enables linkage between examination cycles for repeat-finding trend analysis.',
    `repeat_exam_indicator` BOOLEAN COMMENT 'Indicates whether this examination is a follow-up or repeat examination triggered by unresolved findings from a prior examination cycle. True if this is a repeat examination; False if it is an initial examination. Critical for repeat-finding trend analysis and regulatory escalation risk assessment.',
    `restitution_amount` DECIMAL(18,2) COMMENT 'Total amount of consumer restitution ordered by the state DOI as a result of examination findings, expressed in US dollars. Represents payments owed to policyholders harmed by identified violations. Null if no restitution was ordered. Classified as confidential due to business-sensitive financial exposure.',
    `total_findings_count` STRING COMMENT 'Total number of distinct examination findings identified across all severity levels in this examination. Provides a high-level measure of examination outcome severity and supports trend analysis across examination cycles.',
    `total_policies_examined` STRING COMMENT 'Total number of individual policy or contract records reviewed by examiners during the examination. Represents the full sample size across all functional areas and lines of business examined. Used to calculate error rates and assess statistical significance of findings.',
    `total_policies_with_findings` STRING COMMENT 'Total number of policy or contract records in which at least one examination finding was identified. Used to calculate the overall error rate (policies with findings / total policies examined) and assess the breadth of non-compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market conduct examination record was most recently modified in the compliance management system. Supports audit trail, change detection, and incremental ETL processing. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_market_conduct_exam PRIMARY KEY(`market_conduct_exam_id`)
) COMMENT 'Comprehensive record of state DOI market conduct examinations, their associated findings, and finding-level detail. Captures examination type (routine, targeted, multi-state), initiating state DOI, scope, lead examiner, examination period, status, and outcome. Includes embedded finding records: finding description, regulatory citation violated, severity classification (critical, major, minor), affected policy counts, examiner recommendations, company response, finding status (open, disputed, remediated, closed), and corrective action deadlines. Supports the full examination lifecycle from notification through finding closure and repeat-finding trend analysis across examination cycles.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`exam_finding` (
    `exam_finding_id` BIGINT COMMENT 'Unique surrogate identifier for each individual finding or deficiency identified during a market conduct examination, regulatory audit, or internal compliance review.',
    `asset_holding_id` BIGINT COMMENT 'Foreign key linking to investment.asset_holding. Business justification: Exam findings may cite specific investment holdings violating regulations (non-admitted assets, concentration violations, prohibited investments). Real business process: examination remediation, asset',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_policy. Business justification: Exam findings may identify violations of specific internal compliance policies. The finding describes the deficiency, while the policy describes the rule.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Each exam finding requires supporting evidence documents, examiner work papers, and company response documentation. Critical for finding remediation workflow and regulatory closure. Replaces text refe',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Each exam finding requires documented correspondence for company responses, remediation discussions, and regulator clarifications. Real business process: finding response and resolution documentation ',
    `guideline_id` BIGINT COMMENT 'Foreign key linking to investment.investment_guideline. Business justification: Exam findings identify violations of investment guidelines (policy breaches, limit exceedances, unauthorized investments). Real business process: regulatory examination, guideline compliance assessmen',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Exam findings often cite specific policy examples as evidence of deficiencies. Linking enables tracking which policies exhibited the deficiency, supports remediation verification, and enables regulato',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Exam findings resulting in penalties, consumer restitution, or remediation costs generate journal entries. Finance must track exam-related expenses for financial statement accuracy and regulatory repo',
    `market_conduct_exam_id` BIGINT COMMENT 'Reference to the parent market conduct examination or regulatory audit under which this finding was raised.',
    `prior_finding_exam_finding_id` BIGINT COMMENT 'Reference to the earlier exam_finding record that this finding repeats or is related to, enabling repeat-finding lineage and trend analysis.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Exam findings may identify failures to meet regulatory obligations. The finding describes the deficiency, while the obligation describes the requirement.',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Exam findings cite deficiencies in specific reports (e.g., incomplete Annual Statement schedules). Links finding to the report that had the issue for remediation tracking and report quality improvemen',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Market conduct exam findings often cite specific commission schedules as evidence of improper incentives, anti-rebating violations, or excessive compensation. Real business process: regulatory examina',
    `actual_penalty_amount` DECIMAL(18,2) COMMENT 'Actual monetary penalty or fine levied by the regulatory authority as a result of this finding (USD). Null if no penalty was assessed.',
    `actual_remediation_date` DATE COMMENT 'Date on which the company completed all corrective actions and the finding was substantively remediated, used to measure remediation cycle time against target.',
    `affected_business_process` STRING COMMENT 'The core business process or operational area implicated by the finding (e.g., Policy Underwriting and Risk Assessment, Premium Billing and Collection, Claims Adjudication and Settlement, Annuity Contract Administration, Agent and Broker Commission Management). [ENUM-REF-CANDIDATE: policy_underwriting|new_business_application|premium_billing|claims_adjudication|annuity_administration|policy_servicing|reinsurance_treaty|actuarial_valuation|commission_management|investment_portfolio — promote to reference product]',
    `affected_data_domain` STRING COMMENT 'The primary data domain impacted by the finding, used to route remediation ownership and cross-domain impact analysis. [ENUM-REF-CANDIDATE: policyholder|policy|underwriting|claims|billing|annuity|reinsurance|actuarial|investment|agent_distribution|product|compliance|finance|commission|document_management — 15 candidates stripped; promote to reference product]',
    `aml_bsa_related` BOOLEAN COMMENT 'Indicates whether this finding relates to AML/BSA compliance obligations, including KYC deficiencies, suspicious activity reporting failures, or FinCEN regulatory requirements.',
    `closure_date` DATE COMMENT 'Date on which the examining authority or internal compliance function formally accepted the remediation and closed the finding.',
    `company_response` STRING COMMENT 'Official company response to the finding, including acceptance, dispute rationale, or proposed corrective action plan submitted to the examining authority.',
    `compliance_attestation_required` BOOLEAN COMMENT 'Indicates whether a formal compliance attestation from a senior officer or compliance officer is required to close this finding, as mandated by the examining authority or internal governance policy.',
    `consumer_restitution_amount` DECIMAL(18,2) COMMENT 'Total monetary restitution ordered or voluntarily paid to affected policyholders or annuity contract holders as a result of this finding (USD).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this exam finding record was first created in the compliance management system, used for audit trail and data lineage.',
    `escalation_level` STRING COMMENT 'Current escalation tier for this finding based on severity, age, or regulatory sensitivity: none (routine tracking), management (department head notified), executive (C-suite involvement), board (board audit committee notified), regulator (formal regulatory escalation).. Valid values are `none|management|executive|board|regulator`',
    `estimated_financial_exposure` DECIMAL(18,2) COMMENT 'Estimated monetary exposure or potential liability associated with the finding, including potential regulatory fines, consumer restitution, or remediation costs (USD). Used for ERM and RBC impact assessment.',
    `examination_period_end_date` DATE COMMENT 'End date of the examination or audit period during which the underlying conduct or deficiency occurred.',
    `examination_period_start_date` DATE COMMENT 'Start date of the examination or audit period during which the underlying conduct or deficiency occurred, defining the scope of the review.',
    `examination_report_reference` STRING COMMENT 'Document reference number or citation pointing to the official examination report, audit report, or internal compliance review document in which this finding is formally recorded.',
    `examiner_name` STRING COMMENT 'Full name of the lead examiner or auditor from the regulatory authority or internal compliance team who identified and documented this finding.',
    `examiner_organization` STRING COMMENT 'Name of the organization or agency the examiner represents (e.g., Texas Department of Insurance, FINRA District 6, Internal Audit Division).',
    `examiner_recommendation` STRING COMMENT 'Formal recommendation or corrective action prescribed by the examiner or auditor to resolve the finding, as stated in the examination report.',
    `finding_description` STRING COMMENT 'Detailed narrative description of the finding, deficiency, or violation as documented by the examiner or internal compliance reviewer, including factual basis and observed conduct.',
    `finding_identified_date` DATE COMMENT 'The real-world date on which the examiner or auditor first identified and documented this finding during the examination or review period.',
    `finding_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to this finding by the examining authority or internal compliance team, used in official correspondence and remediation tracking (e.g., NAIC-2024-F00123).. Valid values are `^[A-Z]{2,6}-[0-9]{4}-F[0-9]{3,5}$`',
    `finding_status` STRING COMMENT 'Current workflow status of the finding in the remediation lifecycle: open (active deficiency), disputed (company contests the finding), remediated (corrective action completed), closed (examiner accepted resolution), pending_verification (awaiting examiner confirmation).. Valid values are `open|disputed|remediated|closed|pending_verification`',
    `finding_title` STRING COMMENT 'Short, descriptive title summarizing the nature of the finding or deficiency (e.g., Failure to Provide Required Policy Disclosure Within Statutory Timeframe).',
    `finding_type` STRING COMMENT 'Category of examination or review that produced this finding. [ENUM-REF-CANDIDATE: market_conduct|financial_examination|internal_audit|regulatory_audit|sox_control|aml_bsa|hipaa_privacy|finra_review|dol_erisa — promote to reference product]',
    `hipaa_related` BOOLEAN COMMENT 'Indicates whether this finding involves a HIPAA privacy or security rule violation related to protected health information (PHI) accessed or processed during underwriting, claims, or policy servicing.',
    `impacted_policy_count` STRING COMMENT 'Number of insurance policies or annuity contracts directly affected by the deficiency identified in this finding, used to assess consumer harm scope and remediation effort.',
    `impacted_transaction_count` STRING COMMENT 'Number of individual transactions (e.g., premium payments, claims, disbursements) directly affected by the deficiency, used alongside impacted_policy_count for full scope assessment.',
    `is_repeat_finding` BOOLEAN COMMENT 'Indicates whether this finding is a recurrence of a previously identified deficiency from a prior examination cycle, used for repeat-finding analysis and escalation prioritization.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the jurisdiction in which the finding applies or was raised by a State Department of Insurance (DOI) or other state-level regulator.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this exam finding record, used for change tracking, audit trail, and incremental data pipeline processing.',
    `regulatory_authority` STRING COMMENT 'The governing body or regulatory authority that identified or has jurisdiction over this finding (e.g., NAIC, state DOI, SEC, FINRA, IRS, DOL, FinCEN). [ENUM-REF-CANDIDATE: NAIC|state_doi|SEC|FINRA|IRS|DOL|FASB|FinCEN|IAIS|ACORD — 10 candidates stripped; promote to reference product]',
    `regulatory_citation` STRING COMMENT 'Specific statute, regulation, rule, or code section violated or at issue (e.g., NAIC Model Regulation 641, IRC Section 7702, HIPAA 45 CFR §164.502, SOX Section 404, FINRA Rule 2111 Suitability).',
    `remediation_owner` STRING COMMENT 'Name or identifier of the internal business owner or department responsible for executing the remediation plan and driving the finding to closure.',
    `remediation_plan` STRING COMMENT 'Detailed description of the corrective action plan developed by the company to address the finding, including process changes, system updates, training, or policy revisions.',
    `severity_classification` STRING COMMENT 'Risk-based severity level assigned to the finding: critical (systemic violation with significant consumer harm or regulatory penalty risk), major (material deficiency requiring prompt remediation), minor (isolated or low-impact deficiency), informational (observation without formal violation).. Valid values are `critical|major|minor|informational`',
    `sox_control_reference` STRING COMMENT 'Reference to the specific SOX internal control identifier or control objective that this finding relates to, used for SOX Section 302/404 compliance reporting and control deficiency tracking.',
    `suitability_review_required` BOOLEAN COMMENT 'Indicates whether this finding requires a suitability review of affected transactions or policies under FINRA Rule 2111, DOL fiduciary standards, or NAIC Suitability in Annuity Transactions Model Regulation.',
    `target_remediation_date` DATE COMMENT 'Committed target date by which the company plans to complete all corrective actions and submit evidence of remediation to the examining authority.',
    `training_required` BOOLEAN COMMENT 'Indicates whether mandatory compliance training has been identified as part of the corrective action plan for this finding, applicable to affected business units or agents.',
    CONSTRAINT pk_exam_finding PRIMARY KEY(`exam_finding_id`)
) COMMENT 'Individual finding or deficiency identified during a market conduct examination, regulatory audit, or internal compliance review. Captures finding description, regulatory citation violated, severity classification (critical, major, minor), affected business process, number of impacted policies or transactions, examiner recommendation, company response, and finding status (open, disputed, remediated, closed). Supports remediation tracking and repeat-finding analysis.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`remediation_plan` (
    `remediation_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the remediation plan record in the compliance tracking system. Primary key for this entity.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Remediation plans require documented validation evidence, corrective action documentation, and regulatory acceptance letters. Essential for CAP tracking and regulatory closure process. Replaces text r',
    `compliance_breach_id` BIGINT COMMENT 'Foreign key linking to investment.compliance_breach. Business justification: Remediation plans address internal investment compliance breaches (not just exam findings). Real business process: breach remediation, corrective action tracking, investment committee oversight. Essen',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Remediation costs (system changes, process improvements, training, restitution) must be budgeted and tracked by responsible cost center. Finance teams need this for expense forecasting and actual-vs-b',
    `exam_finding_id` BIGINT COMMENT 'Reference to the examination finding, audit observation, or self-identified compliance deficiency that triggered the creation of this remediation plan.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Remediation plans often require vendor implementation—system changes, process redesign, training delivery, or technology deployment. Tracks vendor responsible for delivering remediation solution compo',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Remediation plans may require policy-level corrections (e.g., premium adjustments, beneficiary corrections, illustration re-delivery). Linking enables tracking affected policies, supports remediation ',
    `issue_id` BIGINT COMMENT 'Foreign key linking to compliance.issue. Business justification: A remediation_plan is created to address a compliance issue. While remediation_plan already references exam_finding and market_conduct_exam (which are specific types of issues), it should also be able',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Remediation costs (system changes, process improvements, restitution) are journalized as incurred. Finance needs to track actual vs estimated costs for accrual accuracy and budget variance analysis.',
    `market_conduct_exam_id` BIGINT COMMENT 'Reference to the regulatory examination, audit engagement, or compliance review that produced the finding requiring remediation.',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Remediation plans require ongoing correspondence with regulators: progress updates, extension requests, completion notifications, and validation evidence submissions. Real business process: corrective',
    `employee_id` BIGINT COMMENT 'Reference to the internal employee or organizational unit accountable for executing and completing the remediation plan. The responsible owner is the primary point of contact for status updates and regulatory inquiries.',
    `prior_plan_remediation_plan_id` BIGINT COMMENT 'Reference to the previous remediation plan for the same or related deficiency, when recurrence_indicator is true. Enables lineage tracking of repeat findings and demonstrates the history of compliance gap closure attempts to regulators.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Remediation plans address failures to meet regulatory obligations. The obligation defines the regulatory deadline that the remediation must meet.',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Remediation plans for reporting deficiencies target specific report definitions needing correction. Links plan to the report being remediated for corrective action tracking in exam responses and audit',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Remediation plans may require modification or elimination of specific commission schedules found to violate regulations (excessive rates, improper incentives, anti-rebating violations). Business proce',
    `actual_completion_date` DATE COMMENT 'The date on which all corrective actions were fully implemented and the remediation plan was operationally closed. Null until completion is achieved. Used to measure on-time performance against target completion date.',
    `affected_business_domain` STRING COMMENT 'The primary business domain or operational area impacted by the compliance deficiency. Used to route remediation ownership and for cross-domain compliance gap analysis. [ENUM-REF-CANDIDATE: policy|underwriting|claims|billing|annuity|reinsurance|actuarial|investment|distribution|compliance|finance|product — promote to reference product]',
    `affected_product_line` STRING COMMENT 'The insurance or annuity product line(s) impacted by the compliance deficiency (e.g., Whole Life, Term Life, Universal Life, Fixed Indexed Annuity, Variable Universal Life). Null if the deficiency is enterprise-wide or not product-specific.',
    `board_notification_required` BOOLEAN COMMENT 'Indicates whether the Board of Directors or Audit Committee must be formally notified of this compliance deficiency and remediation plan per SOX, ORSA, or state DOI requirements. Drives governance reporting workflows.',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance officers to record supplementary observations, regulatory correspondence summaries, interim status updates, or contextual information not captured in structured fields. Supports the full audit narrative.',
    `corrective_action_description` STRING COMMENT 'Detailed description of the specific corrective actions, process changes, system enhancements, or control improvements planned or implemented to address the identified compliance deficiency and prevent recurrence.',
    `corrective_action_type` STRING COMMENT 'Classification of the primary corrective action approach being taken. Used for portfolio analysis of remediation strategies across the enterprise. [ENUM-REF-CANDIDATE: process_change|system_enhancement|policy_update|training|control_implementation|staffing|vendor_remediation|monitoring_enhancement — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this remediation plan record was first created in the compliance tracking system. Provides the audit trail entry point for the full lifecycle of the remediation obligation.',
    `deficiency_description` STRING COMMENT 'Detailed narrative description of the compliance deficiency, gap, or violation identified. Captures the nature of the non-compliance, the regulatory requirement violated, and the scope of impact on policyholders or business operations.',
    `escalation_required` BOOLEAN COMMENT 'Indicates whether this remediation plan requires escalation to senior management, the Board of Directors, or regulatory authorities due to severity, financial exposure, or regulatory mandate. Triggers escalation workflow in the compliance management system.',
    `estimated_policyholder_impact_count` STRING COMMENT 'Estimated number of policyholders or contract holders potentially affected by the compliance deficiency. Used for regulatory reporting, consumer harm assessments, and prioritization of remediation urgency.',
    `financial_exposure_amount` DECIMAL(18,2) COMMENT 'Estimated financial exposure or potential liability associated with the compliance deficiency, expressed in USD. Includes potential regulatory fines, restitution to policyholders, and remediation costs. Used for risk quantification and ERM reporting.',
    `jurisdiction_code` STRING COMMENT 'Two- or three-character code identifying the regulatory jurisdiction (US state, territory, or federal) under which the remediation obligation arises. Uses standard USPS state abbreviations or FED for federal-level requirements.. Valid values are `^[A-Z]{2,3}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this remediation plan record was most recently modified. Used for change tracking, audit trail maintenance, and incremental data pipeline processing in the Databricks Silver layer.',
    `plan_number` STRING COMMENT 'Externally-known, human-readable business identifier for the remediation plan, used in regulatory correspondence, audit reports, and cross-system references. Format: REM-{YYYY}-{NNNNNN}.. Valid values are `^REM-[0-9]{4}-[0-9]{6}$`',
    `plan_open_date` DATE COMMENT 'The business date on which the remediation plan was formally opened and accepted as a compliance obligation. Represents the start of the remediation lifecycle and is used to calculate aging and regulatory deadline compliance.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the remediation plan. Tracks progression from initial planning through corrective action execution to regulatory acceptance. [ENUM-REF-CANDIDATE: planned|in_progress|completed|validated|closed|cancelled — promote to reference product]. Valid values are `planned|in_progress|completed|validated|closed|cancelled`',
    `plan_title` STRING COMMENT 'Short, descriptive title summarizing the nature of the compliance deficiency and the corrective action being taken. Used in dashboards, reports, and regulatory submissions.',
    `plan_type` STRING COMMENT 'Classification of the remediation plan by the source of the triggering deficiency. Distinguishes between plans arising from regulatory examinations, internal audits, SOX control failures, market conduct reviews, or self-identified gaps. [ENUM-REF-CANDIDATE: regulatory_exam|internal_audit|self_identified|sox_control|market_conduct|aml_bsa|hipaa|erisa — promote to reference product]. Valid values are `regulatory_exam|internal_audit|self_identified|sox_control|market_conduct`',
    `priority_level` STRING COMMENT 'Operational priority assigned to the remediation plan, which may differ from severity level based on regulatory deadlines, resource constraints, or strategic risk appetite. Drives scheduling and resource allocation decisions.. Valid values are `urgent|high|medium|low`',
    `recurrence_indicator` BOOLEAN COMMENT 'Indicates whether this compliance deficiency is a repeat finding from a prior examination or audit cycle. Repeat findings typically receive heightened regulatory scrutiny and may result in escalated enforcement actions under NAIC and state DOI standards.',
    `regulator_reference_number` STRING COMMENT 'The reference number or docket number assigned by the regulatory authority (state DOI, NAIC, SEC, FinCEN, etc.) to track this remediation obligation in their examination or enforcement records. Used for cross-referencing regulatory correspondence.',
    `regulatory_acceptance_date` DATE COMMENT 'The date on which the regulator or examining authority formally accepted the remediation plan as satisfactorily completed. Null until regulatory acceptance is received. Marks the end of the regulatory obligation lifecycle.',
    `regulatory_acceptance_status` STRING COMMENT 'Status of the regulators or examining authoritys formal acceptance of the remediation plan closure. Tracks whether the state DOI, NAIC, SEC, FinCEN, or other governing body has acknowledged that the deficiency has been satisfactorily resolved.. Valid values are `pending|accepted|rejected|under_review`',
    `regulatory_framework` STRING COMMENT 'Primary regulatory or compliance framework under which this remediation plan is required. Identifies the governing body or standard driving the corrective action obligation. [ENUM-REF-CANDIDATE: NAIC|SOX|HIPAA|AML_BSA|ERISA|SEC_FINRA|IRS_7702|ORSA|STATE_DOI|IFRS — promote to reference product]',
    `remediation_cost_amount` DECIMAL(18,2) COMMENT 'Actual or estimated cost incurred to implement the corrective actions under this remediation plan, expressed in USD. Includes internal labor, system changes, third-party consulting, and training costs. Used for compliance budget management.',
    `responsible_department` STRING COMMENT 'Name of the business unit or department accountable for executing the remediation plan. Used for enterprise-wide compliance gap analysis and departmental accountability reporting.',
    `responsible_owner_name` STRING COMMENT 'Full name of the individual accountable for executing the remediation plan. Retained as a denormalized field for regulatory reporting and audit trail purposes where the employee record may change over time.',
    `revised_target_date` DATE COMMENT 'Updated target completion date when the original target date has been formally extended due to scope changes, resource constraints, or regulatory negotiation. Null if no revision has occurred.',
    `root_cause_category` STRING COMMENT 'Categorical classification of the root cause to enable enterprise-wide trend analysis and systemic issue identification across remediation plans. [ENUM-REF-CANDIDATE: process_gap|system_failure|training_deficiency|control_weakness|data_quality|staffing|vendor_failure|policy_gap — promote to reference product]',
    `root_cause_description` STRING COMMENT 'Formal root cause analysis narrative identifying the underlying process, system, control, or organizational failure that led to the compliance deficiency. Essential for preventing recurrence and demonstrating thoroughness to regulators.',
    `severity_level` STRING COMMENT 'Risk-based severity rating of the underlying compliance deficiency, used to prioritize remediation efforts and escalation thresholds. Critical findings typically require immediate regulatory notification under NAIC and state DOI standards.. Valid values are `critical|high|medium|low`',
    `target_completion_date` DATE COMMENT 'The committed date by which all corrective actions under this remediation plan are expected to be fully implemented and validated. May be set by regulatory mandate or internal commitment to the examining authority.',
    `validation_date` DATE COMMENT 'The date on which the validation of corrective action effectiveness was completed and documented. Null until validation is performed. Distinct from actual completion date, as validation may occur after implementation.',
    `validation_method` STRING COMMENT 'The approach used to verify that corrective actions have been effectively implemented and the compliance deficiency has been resolved. Determines the rigor and independence of the closure evidence. [ENUM-REF-CANDIDATE: internal_testing|independent_review|regulatory_inspection|third_party_audit|management_attestation|continuous_monitoring — promote to reference product]. Valid values are `internal_testing|independent_review|regulatory_inspection|third_party_audit|management_attestation`',
    `validation_outcome` STRING COMMENT 'Result of the validation testing or review confirming whether the corrective actions have been effectively implemented and the deficiency has been resolved. A failed or partially passed outcome requires additional remediation.. Valid values are `passed|failed|partially_passed|pending`',
    CONSTRAINT pk_remediation_plan PRIMARY KEY(`remediation_plan_id`)
) COMMENT 'Formal remediation plan created in response to exam findings, audit observations, or self-identified compliance deficiencies. Tracks root cause analysis, corrective action description, responsible owner, target completion date, actual completion date, remediation status (planned, in-progress, completed, validated), validation method, and regulatory acceptance status. Enables enterprise-wide tracking of compliance gap closure.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`suitability_review` (
    `suitability_review_id` BIGINT COMMENT 'Primary key for suitability_review',
    `bonus_program_id` BIGINT COMMENT 'Foreign key linking to commission.bonus_program. Business justification: Suitability reviews assess whether bonus programs created incentives for unsuitable recommendations (sales contests favoring high-commission products, bonuses tied to specific product sales). Business',
    `employee_id` BIGINT COMMENT 'Reference to the compliance supervisor or principal who performed the supervisory review of the suitability determination.',
    `in_force_policy_id` BIGINT COMMENT 'Reference to the life insurance policy or annuity contract that is the subject of this suitability review.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Suitability reviews generate documented worksheets, client acknowledgments, and supervisory review sign-offs required by Reg BI and state suitability regulations. Critical for compliance audit defense',
    `license_id` BIGINT COMMENT 'Foreign key linking to agent.license. Business justification: Suitability reviews must verify producer held valid license in jurisdiction at time of sale, with correct line of authority for product sold. License_id links review to specific license record for com',
    `party_id` BIGINT COMMENT 'Reference to the policyholder or annuity contract owner whose financial profile and suitability is being assessed at the time of sale.',
    `plan_id` BIGINT COMMENT 'Reference to the insurance or annuity product recommended and sold, used to assess product-specific suitability criteria.',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or broker who conducted the sale and is responsible for the suitability determination.',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Suitability reviews are documented in standardized reports for regulatory exams and internal audits. Links review to the report definition for suitability compliance monitoring and reporting.',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Suitability reviews evaluate whether commission structure incentivized unsuitable sales (excessive FYC rates, high bonuses for specific products). Real business process: compliance review links produc',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Suitability reviews must comply with state-specific suitability and best-interest regulations. The review describes the assessment, while the regulation describes the state-specific rules.',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Suitability reviews are performed ON applications during underwriting. Regulatory requirement to validate product suitability before issue. Natural 1:N (one application may have multiple suitability r',
    `decision_id` BIGINT COMMENT 'Foreign key linking to underwriting.decision. Business justification: Final underwriting decisions must reference the suitability review that validated the sale. Regulatory requirement: cannot issue policy without documented suitability determination. Links compliance v',
    `aml_kyc_verified_flag` BOOLEAN COMMENT 'Indicates whether AML/KYC verification was completed for this transaction, confirming the clients identity and source of funds in compliance with FinCEN BSA requirements.',
    `annual_income` DECIMAL(18,2) COMMENT 'Clients total annual income in USD at the time of the suitability review, as self-reported on the suitability questionnaire. Used to assess affordability of premiums and appropriateness of product.',
    `client_acknowledgment_date` DATE COMMENT 'The date on which the client signed or electronically acknowledged the suitability questionnaire and disclosure documents.',
    `client_acknowledgment_flag` BOOLEAN COMMENT 'Indicates whether the client has signed or electronically acknowledged the suitability questionnaire and associated disclosures, confirming the accuracy of the financial profile information provided.',
    `client_age` STRING COMMENT 'Age of the policyholder in whole years at the time of the suitability review. Critical factor in determining product appropriateness, particularly for annuity surrender periods relative to life expectancy.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this suitability review record was first created in the system, used for audit trail and SOX compliance tracking.',
    `determination_rationale` STRING COMMENT 'Narrative explanation provided by the agent or compliance reviewer documenting the basis for the suitability determination, including how the product aligns with the clients financial profile, objectives, and risk tolerance.',
    `disclosure_provided_flag` BOOLEAN COMMENT 'Indicates whether all required regulatory disclosures (e.g., NAIC Buyers Guide, product prospectus for variable products, fee disclosure) were provided to the client prior to or at the time of sale.',
    `existing_insurance_coverage` BOOLEAN COMMENT 'Indicates whether the client has existing life insurance or annuity coverage at the time of the suitability review, relevant for replacement analysis and concentration assessment.',
    `finra_reg_bi_applicable_flag` BOOLEAN COMMENT 'Indicates whether SEC Regulation Best Interest (Reg BI) applies to this transaction, typically for variable product sales through registered broker-dealers.',
    `investment_amount` DECIMAL(18,2) COMMENT 'The premium or investment amount in USD placed into the recommended product at the time of sale. Used to assess concentration risk relative to the clients total liquid net worth.',
    `investment_objective` STRING COMMENT 'Clients primary investment objective as stated on the suitability questionnaire. Drives product recommendation alignment analysis.. Valid values are `income|growth|preservation|tax_deferral|legacy`',
    `investment_time_horizon` STRING COMMENT 'Clients stated investment time horizon: short_term (under 3 years), medium_term (3–10 years), long_term (over 10 years). Must be compatible with product surrender charge period.. Valid values are `short_term|medium_term|long_term`',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether the transaction involves a tax-free 1035 exchange of an existing insurance or annuity contract, requiring additional suitability analysis of surrender charges, tax implications, and benefit comparisons.',
    `is_replacement` BOOLEAN COMMENT 'Indicates whether this sale involves the replacement of an existing life insurance policy or annuity contract, triggering additional disclosure and suitability requirements under NAIC Model Regulation #613.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state code of the jurisdiction in which the sale transaction occurred, determining applicable state DOI suitability rules and disclosure requirements.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this suitability review record was most recently modified, supporting audit trail requirements and change tracking for regulatory examination purposes.',
    `liquid_net_worth` DECIMAL(18,2) COMMENT 'Clients liquid net worth in USD (readily accessible assets excluding illiquid holdings such as real estate and retirement accounts) at the time of review. Critical for assessing ability to meet surrender charges and liquidity needs.',
    `net_worth` DECIMAL(18,2) COMMENT 'Clients total net worth in USD (assets minus liabilities) at the time of the suitability review, as self-reported. Used to evaluate financial capacity and product suitability relative to overall wealth.',
    `override_flag` BOOLEAN COMMENT 'Indicates whether the client elected to proceed with the transaction despite a not_suitable or conditionally_suitable determination, exercising their right to override the recommendation. Requires documented client acknowledgment.',
    `override_reason` STRING COMMENT 'Documented reason provided by the client for proceeding with the transaction despite a non-suitable or conditional determination. Required when override_flag is True.',
    `product_type` STRING COMMENT 'The type of insurance or annuity product recommended. Uses industry-standard abbreviations: FIA (Fixed Indexed Annuity), VUL (Variable Universal Life), UL (Universal Life), WL (Whole Life), IUL (Indexed Universal Life), SPIA (Single Premium Immediate Annuity), DI (Disability Income), LTC (Long-Term Care), term (Term Life). [ENUM-REF-CANDIDATE: FIA|VUL|UL|WL|IUL|SPIA|DI|LTC|term|GMWB|GMIB|GMAB — promote to reference product]',
    `regulatory_framework` STRING COMMENT 'The primary regulatory framework governing this suitability review. NAIC_275 for annuity suitability; DOL_ERISA for employer-sponsored plan sales; SEC_FINRA for variable product sales; STATE_DOI for state-specific requirements; BEST_INTEREST for Reg BI compliance.. Valid values are `NAIC_275|DOL_ERISA|SEC_FINRA|STATE_DOI|BEST_INTEREST`',
    `remediation_due_date` DATE COMMENT 'The deadline by which required remediation actions must be completed. Populated when remediation_required_flag is True.',
    `remediation_required_flag` BOOLEAN COMMENT 'Indicates whether a compliance remediation action is required as a result of this suitability review, such as policy rescission, refund, or corrective disclosure.',
    `review_date` DATE COMMENT 'The calendar date on which the suitability review was conducted, corresponding to the point-of-sale (POS) transaction date.',
    `review_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this suitability review at initiation, used for correspondence, audit trails, and regulatory filings. Format: SR-YYYY-NNNNNN.. Valid values are `^SR-[0-9]{4}-[0-9]{6}$`',
    `review_status` STRING COMMENT 'Current workflow status of the suitability review. suitable indicates the product is appropriate for the client; not_suitable triggers mandatory remediation; needs_review requires supervisory escalation; escalated indicates referral to compliance; withdrawn indicates the transaction was cancelled.. Valid values are `pending|suitable|not_suitable|needs_review|escalated|withdrawn`',
    `review_type` STRING COMMENT 'Classification of the review type. initial for new sales; replacement for policy replacements per NAIC Model #613; exchange for 1035 tax-free exchanges; periodic for ongoing best-interest reviews; supervisory for principal-level reviews.. Valid values are `initial|replacement|exchange|periodic|supervisory`',
    `risk_tolerance` STRING COMMENT 'Clients self-reported investment risk tolerance as captured on the suitability questionnaire. Determines appropriate product risk profile alignment.. Valid values are `conservative|moderate|moderately_aggressive|aggressive`',
    `source_of_funds` STRING COMMENT 'The origin of the funds used to purchase the product. Required for AML/BSA compliance and suitability analysis. [ENUM-REF-CANDIDATE: savings|retirement_account|inheritance|proceeds_from_sale|existing_policy|business_income|gift|other — promote to reference product]. Valid values are `savings|retirement_account|inheritance|proceeds_from_sale|existing_policy|other`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this suitability review record originated (e.g., CRM for Salesforce Financial Services Cloud, POLICY_ADMIN for Policy Administration System, COMPLIANCE_WB for compliance workbench).. Valid values are `CRM|POLICY_ADMIN|UNDERWRITING|ANNUITY_ADMIN|COMPLIANCE_WB`',
    `suitability_determination` STRING COMMENT 'The formal suitability determination made by the reviewing agent: suitable confirms the product meets the clients needs; not_suitable prohibits the sale; conditionally_suitable requires additional disclosures or client acknowledgment.. Valid values are `suitable|not_suitable|conditionally_suitable`',
    `supervisory_notes` STRING COMMENT 'Free-text notes entered by the supervising principal documenting the basis for the supervisory review outcome, including any conditions, concerns, or required follow-up actions.',
    `supervisory_review_date` DATE COMMENT 'The date on which the supervisory or principal review of the suitability determination was completed.',
    `supervisory_review_outcome` STRING COMMENT 'The outcome of the principal or supervisory compliance review of the suitability determination. approved confirms the sale may proceed; rejected halts the transaction; returned_for_revision requires agent to update the analysis; escalated refers to senior compliance.. Valid values are `approved|rejected|returned_for_revision|escalated`',
    `tax_status` STRING COMMENT 'Tax qualification status of the funds used to purchase the product. qualified indicates pre-tax retirement funds (IRA, 401k); non_qualified indicates after-tax funds; roth indicates Roth IRA funds. Affects IRC Section 72 tax treatment and suitability of tax-deferred products.. Valid values are `qualified|non_qualified|roth|unknown`',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether the recommended product is a variable insurance or annuity product (e.g., VUL, variable annuity), triggering additional SEC/FINRA oversight, prospectus delivery, and suitability requirements.',
    CONSTRAINT pk_suitability_review PRIMARY KEY(`suitability_review_id`)
) COMMENT 'Record of suitability and best-interest review conducted for annuity and life insurance sales transactions per NAIC Suitability in Annuity Transactions Model Regulation (#275) and DOL fiduciary standards. Captures policyholder financial profile at time of sale, product recommended, suitability determination (suitable, not suitable, needs review), reviewing agent, supervisory review outcome, and any required disclosures provided. Critical for FINRA and SEC oversight of variable product sales.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`aml_case` (
    `aml_case_id` BIGINT COMMENT 'Unique system-generated identifier for the AML/BSA investigation case record. Primary key for this entity.',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: AML investigations may reveal agency-level patterns: multiple producers within same agency involved in premium financing schemes, STOLI rings, or structured transactions. Agency context is critical fo',
    `aml_alert_id` BIGINT COMMENT 'Reference identifier of the automated transaction monitoring alert that triggered this case, if applicable. Links back to the originating alert in the AML transaction monitoring system for audit trail purposes. Null for manually initiated cases.',
    `asset_holding_id` BIGINT COMMENT 'Foreign key linking to investment.asset_holding. Business justification: AML cases may investigate suspicious investment holdings (shell company securities, high-risk jurisdictions, sanctions screening hits). Real business process: beneficial ownership investigation, OFAC ',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: AML investigations generate customer information requests, account restriction notices, and law enforcement correspondence. Real business process: AML investigation documentation and customer communic',
    `employee_id` BIGINT COMMENT 'Reference to the compliance investigator or analyst assigned as the primary owner of this AML/BSA case. Drives workflow routing, SLA tracking, and accountability for FinCEN filing deadlines.',
    `financial_uw_review_id` BIGINT COMMENT 'Foreign key linking to underwriting.financial_uw_review. Business justification: Financial underwriting reviews that detect money laundering indicators (structuring, unexplained wealth, over-insurance) trigger AML cases. Business process: financial crime detection during underwrit',
    `in_force_policy_id` BIGINT COMMENT 'Reference to the specific life insurance or annuity policy record that is the subject of or linked to this AML/BSA investigation. Null if the case is not tied to a specific policy.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: AML cases require documented investigation evidence, transaction records, and narrative support for SAR filings. Essential for AML case management, FinCEN reporting, and regulatory examination defense',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: AML cases resulting in asset seizure, restitution payments, or regulatory penalties generate journal entries. Finance must track financial impact of AML cases for regulatory reporting and financial st',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: AML cases are investigated and SAR filings made by specific legal entities. FinCEN filing requirement is entity-specific - each entity must have own AML program and file own SARs.',
    `rule_id` BIGINT COMMENT 'Identifier of the automated transaction monitoring rule or scenario that generated the alert triggering this case. Used for rule effectiveness analysis, false positive rate tracking, and AML model governance. Null for manually initiated cases.',
    `party_id` BIGINT COMMENT 'Reference to the policyholder record associated with this AML/BSA case, when the subject is a policyholder or the suspicious activity is linked to a specific policy contract.',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or broker associated with this AML/BSA case, when the subject or a contributing party is an agent. Used for producer conduct investigations and STOLI case tracking.',
    `report_run_id` BIGINT COMMENT 'Foreign key linking to reporting.report_run. Business justification: AML cases trigger generation of transaction history reports for FinCEN filing or internal investigation. Links case to the report run for AML investigation and suspicious activity reporting automation',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: AML investigations frequently use third-party screening services (OFAC, sanctions, adverse media), forensic consultants, or compliance technology vendors. Tracks vendor providing AML screening or inve',
    `stoli_review_id` BIGINT COMMENT 'Foreign key linking to underwriting.stoli_review. Business justification: STOLI investigations frequently escalate to formal AML cases when investor-owned life insurance patterns are detected. Business process: STOLI-to-AML escalation workflow. Links compliance AML investig',
    `trade_id` BIGINT COMMENT 'Foreign key linking to investment.trade. Business justification: AML cases investigate suspicious trading activity (premium financing, STOLI indicators, rapid surrenders, unusual investment patterns). Real business process: suspicious activity investigation, SAR fi',
    `investment_transaction_id` BIGINT COMMENT 'Reference to the primary financial transaction that triggered or is the focal point of this AML/BSA investigation, such as a large cash premium payment, suspicious withdrawal, or 1035 exchange.',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: AML cases are opened when applications exhibit suspicious indicators (high STOLI scores, premium financing, unusual ownership). Business process: AML investigation triggered by new business red flags ',
    `activity_end_date` DATE COMMENT 'Latest date of the suspicious activity or transaction pattern under investigation. Together with activity_start_date, defines the full activity period reported on FinCEN SAR filings.',
    `activity_start_date` DATE COMMENT 'Earliest date of the suspicious activity or transaction pattern under investigation. Used to define the activity period reported on FinCEN SAR filings and to scope the investigation lookback window.',
    `case_closed_timestamp` TIMESTAMP COMMENT 'Date and time when the AML/BSA investigation case was formally closed, either after FinCEN filing, no-filing determination, or referral to law enforcement. Null for open or in-progress cases.',
    `case_number` STRING COMMENT 'Externally-known, human-readable business identifier for the AML/BSA case, used in correspondence, FinCEN filings, and regulatory communications. Format: AML-YYYY-NNNNNN.. Valid values are `^AML-[0-9]{4}-[0-9]{6}$`',
    `case_opened_timestamp` TIMESTAMP COMMENT 'Date and time when the AML/BSA investigation case was formally opened and entered into the case management system. This is the principal business event timestamp for the case lifecycle and is used to calculate FinCEN filing deadline compliance (SAR must be filed within 30 days of detection).',
    `case_priority` STRING COMMENT 'Risk-based priority level assigned to the case, driving investigator workload management and escalation timelines. CRITICAL cases typically involve OFAC hits or law enforcement referrals.. Valid values are `LOW|MEDIUM|HIGH|CRITICAL`',
    `case_status` STRING COMMENT 'Current workflow lifecycle status of the AML/BSA investigation case. OPEN = newly initiated; UNDER_REVIEW = active investigation in progress; PENDING_FILING = investigation complete, awaiting FinCEN submission; FILED = SAR/CTR submitted to FinCEN; CLOSED = case resolved with no filing or post-filing closure; ESCALATED = referred to law enforcement or senior compliance.. Valid values are `OPEN|UNDER_REVIEW|PENDING_FILING|FILED|CLOSED|ESCALATED`',
    `case_type` STRING COMMENT 'Classification of the AML/BSA investigation case by regulatory obligation or suspicious activity pattern. SAR = Suspicious Activity Report; CTR = Currency Transaction Report; STRUCTURING = deliberate transaction structuring to evade reporting thresholds; STOLI = Stranger-Originated Life Insurance fraud; OFAC = Office of Foreign Assets Control screening hit; KYC_REMEDIATION = Know Your Customer remediation case. [ENUM-REF-CANDIDATE: SAR|CTR|STRUCTURING|STOLI|OFAC|KYC_REMEDIATION|OTHER — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this AML case record was first created in the compliance case management system. Used for audit trail and data lineage tracking per SOX controls.',
    `detection_date` DATE COMMENT 'Calendar date on which the suspicious activity or transaction was first detected or identified, which may precede the formal case opening date. Critical for calculating the 30-day SAR filing deadline from the date of initial detection per FinCEN requirements.',
    `disposition` STRING COMMENT 'Final or current disposition outcome of the AML/BSA investigation case. SAR_FILED = Suspicious Activity Report submitted to FinCEN; CTR_FILED = Currency Transaction Report submitted; NO_ACTION = investigation concluded with no suspicious activity confirmed; LAW_ENFORCEMENT_REFERRED = case escalated to law enforcement; POLICY_TERMINATED = associated policy cancelled due to AML findings; CLAIM_DENIED = associated claim denied due to AML findings; PENDING = disposition not yet determined. [ENUM-REF-CANDIDATE: SAR_FILED|CTR_FILED|NO_ACTION|LAW_ENFORCEMENT_REFERRED|POLICY_TERMINATED|CLAIM_DENIED|PENDING — 7 candidates stripped; promote to reference product]',
    `disposition_notes` STRING COMMENT 'Free-text narrative documenting the rationale for the case disposition, investigative findings summary, and any actions taken. Required for regulatory examination evidence and internal audit trail. Subject to SAR confidentiality provisions — must not be disclosed to the subject.',
    `fincen_filed_date` DATE COMMENT 'Date on which the SAR or CTR was successfully submitted to FinCEN via the BSA E-Filing System. Used to verify compliance with the 30-day (or 60-day) SAR filing deadline and for regulatory examination evidence.',
    `fincen_filing_type` STRING COMMENT 'Type of regulatory report filed with FinCEN as a result of this AML/BSA case. SAR = Suspicious Activity Report (FinCEN Form 111); CTR = Currency Transaction Report (FinCEN Form 112); FBAR = Foreign Bank Account Report; NONE = case closed with no filing required after investigation.. Valid values are `SAR|CTR|FBAR|NONE`',
    `fincen_reference_number` STRING COMMENT 'Confirmation reference number assigned by FinCEN upon successful submission of a SAR or CTR filing. Used to track filing status, respond to law enforcement requests, and demonstrate regulatory compliance. Null until filing is submitted and acknowledged.',
    `initiation_source` STRING COMMENT 'Origin channel that triggered the creation of this AML/BSA case. AUTOMATED_ALERT = transaction monitoring system rule fired; MANUAL_REFERRAL = compliance officer or business unit referral; LAW_ENFORCEMENT = subpoena or law enforcement request; REGULATORY_EXAM = identified during state DOI or FinCEN examination; INTERNAL_AUDIT = identified during SOX or internal audit review; AGENT_REFERRAL = agent or broker flagged suspicious activity.. Valid values are `AUTOMATED_ALERT|MANUAL_REFERRAL|LAW_ENFORCEMENT|REGULATORY_EXAM|INTERNAL_AUDIT|AGENT_REFERRAL`',
    `jurisdiction` STRING COMMENT 'Two or three-letter code identifying the primary regulatory jurisdiction governing this AML case (e.g., US state code or federal jurisdiction code). Determines applicable state DOI reporting requirements and law enforcement referral protocols.. Valid values are `^[A-Z]{2,3}$`',
    `kyc_review_required` BOOLEAN COMMENT 'Indicates whether this AML case has triggered a mandatory KYC enhanced due diligence (EDD) review for the subject policyholder or agent. True = KYC/EDD review required; False = standard KYC sufficient.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to this AML case record. Supports audit trail requirements and change tracking for regulatory examination purposes.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency to which this case was referred, if applicable (e.g., FBI, DEA, IRS-CI, State Attorney General). Null when law_enforcement_referral is False.',
    `law_enforcement_referral` BOOLEAN COMMENT 'Indicates whether this AML/BSA case has been referred to law enforcement agencies (e.g., FBI, DEA, IRS Criminal Investigation, state law enforcement). True = referral made; False = no referral.',
    `ofac_match_reference` STRING COMMENT 'Reference identifier or SDN entry name from the OFAC screening system when a potential or confirmed match is identified. Used for escalation documentation and regulatory reporting. Null when screening status is CLEAR or NOT_SCREENED.',
    `ofac_screening_status` STRING COMMENT 'Result of OFAC Specially Designated Nationals (SDN) and sanctions list screening for the case subject. CONFIRMED_MATCH requires immediate case escalation and potential transaction blocking per OFAC compliance obligations.. Valid values are `NOT_SCREENED|CLEAR|POTENTIAL_MATCH|CONFIRMED_MATCH|FALSE_POSITIVE`',
    `related_case_number` STRING COMMENT 'Case number of a related or linked AML/BSA case, used to associate cases involving the same subject, transaction network, or suspicious activity pattern. Supports network analysis and typology identification for complex money laundering schemes.',
    `risk_score` DECIMAL(18,2) COMMENT 'Quantitative risk score assigned to this AML case by the transaction monitoring system or compliance analyst, typically on a scale of 0-100. Higher scores indicate greater money laundering risk and drive case prioritization. Used for risk-based AML program management.',
    `sar_confidentiality_flag` BOOLEAN COMMENT 'Indicates whether this case is subject to SAR confidentiality provisions under the BSA, prohibiting disclosure of the SAR filing or its existence to the subject of the report. True = SAR filed and confidentiality applies; False = no SAR filed or confidentiality not applicable.',
    `sar_filing_deadline` DATE COMMENT 'Regulatory deadline by which the SAR must be submitted to FinCEN, calculated as 30 days from the detection date (or 60 days if no subject is identified). Drives compliance SLA monitoring and escalation workflows.',
    `subject_date_of_birth` DATE COMMENT 'Date of birth of the individual subject under investigation, required for identity verification, OFAC screening, and FinCEN SAR filing. Null for entity (non-individual) subjects.',
    `subject_name` STRING COMMENT 'Full legal name of the primary individual or entity under investigation in this AML/BSA case, as reported on FinCEN SAR/CTR filings. Required for regulatory filing and OFAC screening.',
    `subject_tax_number` STRING COMMENT 'Social Security Number (SSN) or Employer Identification Number (EIN) / Taxpayer Identification Number (TIN) of the AML case subject, used for FinCEN SAR/CTR filing and OFAC screening. Stored encrypted per HIPAA and IRS data security requirements.',
    `subject_type` STRING COMMENT 'Classification of the primary subject under investigation. Identifies whether the suspicious activity is associated with a policyholder, licensed agent/broker, policy beneficiary, unrelated third party, or a legal entity (trust, corporation).. Valid values are `POLICYHOLDER|AGENT|BENEFICIARY|THIRD_PARTY|ENTITY`',
    `suspicious_activity_type` STRING COMMENT 'Specific category of suspicious activity identified in the investigation, aligned with FinCEN SAR activity type classifications. Examples include: CASH_TRANSACTION, STRUCTURING, MONEY_LAUNDERING, FRAUD, TERRORIST_FINANCING, INSURANCE_FRAUD, STOLI, IDENTITY_THEFT, ELDER_FINANCIAL_ABUSE. [ENUM-REF-CANDIDATE: CASH_TRANSACTION|STRUCTURING|MONEY_LAUNDERING|FRAUD|TERRORIST_FINANCING|INSURANCE_FRAUD|STOLI|IDENTITY_THEFT|ELDER_FINANCIAL_ABUSE — promote to reference product]',
    `transaction_amount` DECIMAL(18,2) COMMENT 'Total dollar amount of the suspicious transaction(s) under investigation. For CTR cases, this is the cash transaction amount exceeding the $10,000 reporting threshold. For SAR cases, this is the aggregate amount of suspicious activity. Reported on FinCEN filings.',
    `transaction_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the suspicious transaction amount. Typically USD for domestic cases; foreign currency cases may indicate additional money laundering risk.. Valid values are `^[A-Z]{3}$`',
    CONSTRAINT pk_aml_case PRIMARY KEY(`aml_case_id`)
) COMMENT 'Operational record of an Anti-Money Laundering (AML) or Bank Secrecy Act (BSA) investigation case initiated by automated transaction monitoring alerts or manual referrals. Captures case type (SAR, CTR, structuring, STOLI), subject policyholder or agent, triggering transaction details, case status (open, under review, filed, closed), assigned investigator, FinCEN filing reference, and disposition. Supports FinCEN SAR/CTR filing obligations and OFAC screening outcomes.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`privacy_incident` (
    `privacy_incident_id` BIGINT COMMENT 'Unique system-generated identifier for the privacy incident record. Primary key for this entity.',
    `outbound_notice_id` BIGINT COMMENT 'Foreign key linking to correspondence.outbound_notice. Business justification: Privacy breaches require legally mandated notifications to affected individuals, HHS, state attorneys general, and DOI per HIPAA and state breach laws. Real business process: breach notification compl',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_policy. Business justification: Privacy incidents may violate specific HIPAA/privacy policies. The incident describes the event, while the policy describes the rule that was violated.',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Privacy incidents often involve specific policy records (e.g., unauthorized access, data breach). Linking enables tracking which policies were affected, supports breach notification requirements under',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Privacy incidents generate incident reports, breach notification letters, HHS notifications, and remediation documentation required by HIPAA and state breach laws. Critical for breach response workflo',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Privacy breaches often involve business associate vendors (TPAs, cloud providers, service bureaus). Tracks vendor involved in breach for BAA enforcement, notification coordination, and root cause anal',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Privacy breaches result in penalties, legal costs, notification costs, credit monitoring expenses that must be journalized. Finance needs to track actual financial impact for reserve adequacy and disc',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Privacy incidents are reported by the legal entity responsible for the data. HIPAA and state breach notification laws require entity-specific reporting and accountability.',
    `mib_inquiry_id` BIGINT COMMENT 'Foreign key linking to underwriting.mib_inquiry. Business justification: MIB inquiries involve consumer report data; unauthorized access or disclosure triggers privacy incident reporting. FCRA/privacy requirement: breach tracking for MIB data. Links privacy incident to spe',
    `paramedical_exam_id` BIGINT COMMENT 'Foreign key linking to underwriting.paramedical_exam. Business justification: Paramedical exam results contain PHI; breaches (lost specimens, unauthorized access to lab results) require incident tracking. HIPAA requirement: breach notification for medical examination data. Link',
    `party_id` BIGINT COMMENT 'Reference to the primary policyholder whose Protected Health Information (PHI) or Personally Identifiable Information (PII) was involved in the incident. Links to the policyholder master record.',
    `employee_id` BIGINT COMMENT 'Identifier of the employee or workforce member who first reported the privacy incident to the compliance office. Supports workforce accountability and HIPAA workforce training tracking.',
    `producer_id` BIGINT COMMENT 'Foreign key linking to agent.producer. Business justification: Privacy incidents often involve producer actions: unauthorized PHI access, lost/stolen devices with customer data, email breaches. HIPAA breach investigations require tracking which producer caused or',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Privacy incidents require generation of breach notification reports and regulatory filings. Links incident to the report definition for data breach response and notification reporting workflow.',
    `aps_record_id` BIGINT COMMENT 'Foreign key linking to underwriting.aps_record. Business justification: APS records contain highly sensitive PHI; breaches involving APS documents (lost records, unauthorized disclosure) must be tracked. HIPAA requirement: breach notification for attending physician state',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Privacy breaches during underwriting (unauthorized PHI access, lost medical records) must be tracked against the application. HIPAA requirement: breach notification tied to affected individuals appli',
    `affected_individuals_count` STRING COMMENT 'Number of individuals whose PHI or PII was involved in the privacy incident. Determines notification thresholds: incidents affecting 500+ individuals in a state require immediate HHS OCR notification; 500+ total triggers media notification.',
    `breach_determination_date` DATE COMMENT 'Date on which the formal breach determination was made following completion of the four-factor risk assessment. Relevant for calculating notification deadlines under HIPAA and state breach notification laws.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the privacy incident record was first created in the compliance management system. Supports audit trail and data lineage requirements.',
    `data_format` STRING COMMENT 'Format of the data involved in the privacy incident — electronic (digital files, databases, emails), paper (physical documents), verbal (oral disclosure), or mixed. Influences remediation approach and risk assessment scoring.. Valid values are `electronic|paper|verbal|mixed`',
    `discovery_date` DATE COMMENT 'The date on which the covered entity or business associate first became aware of the potential privacy incident. Starts the 60-day HIPAA breach notification clock under 45 CFR § 164.412.',
    `doi_notification_date` DATE COMMENT 'Date on which notification was submitted to the State Department of Insurance. Under the NAIC model law, notification is generally required within 72 hours of determining a cybersecurity event.',
    `doi_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the State Department of Insurance is required under the NAIC Insurance Data Security Model Law or state-specific insurance data security regulations.',
    `hhs_notification_date` DATE COMMENT 'Date on which notification was submitted to HHS OCR via the breach reporting portal. Must occur within 60 days of discovery for breaches affecting 500+ individuals, or by March 1 of the following year for smaller breaches.',
    `hhs_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the U.S. Department of Health and Human Services Office for Civil Rights (HHS OCR) is required. True for all confirmed HIPAA breaches; breaches affecting 500+ individuals require immediate notification, others are reported annually.',
    `incident_date` DATE COMMENT 'The date on which the privacy incident actually occurred or is estimated to have begun. May differ from discovery_date when incidents are discovered after the fact. Required for HHS OCR annual breach report.',
    `incident_description` STRING COMMENT 'Detailed narrative description of the privacy incident — what happened, how it was discovered, what data was involved, and the circumstances of the unauthorized access or disclosure. Core documentation for regulatory submissions and internal investigations.',
    `incident_end_date` DATE COMMENT 'The date on which the privacy incident ceased or was contained. Used to calculate exposure duration and assess scope of harm for breach risk assessment.',
    `incident_location` STRING COMMENT 'Physical or logical location where the privacy incident occurred (e.g., home office, branch office name, cloud environment, third-party vendor site). Used for root cause analysis and remediation targeting.',
    `incident_reference_number` STRING COMMENT 'Human-readable, externally referenceable identifier assigned to the privacy incident at intake (e.g., PI-2024-000123). Used in regulatory correspondence, HHS OCR submissions, and state AG notifications.. Valid values are `^PI-[0-9]{4}-[0-9]{6}$`',
    `incident_status` STRING COMMENT 'Current workflow state of the privacy incident through its lifecycle — from initial intake through investigation, breach determination, notification, and closure. [ENUM-REF-CANDIDATE: open|under_investigation|breach_confirmed|no_breach_determined|notified|closed|reopened — promote to reference product]',
    `incident_type` STRING COMMENT 'Classification of the nature of the privacy incident as defined by HHS OCR breach reporting categories. Drives notification obligations and remediation workflows. [ENUM-REF-CANDIDATE: unauthorized_access|unauthorized_disclosure|lost_device|stolen_device|hacking_it_incident|improper_disposal|mailing_error|other — promote to reference product]',
    `includes_financial_account` BOOLEAN COMMENT 'Indicates whether financial account numbers, payment card data, or banking information were among the data elements exposed. Triggers PCI DSS notification obligations and heightened state breach law requirements.',
    `includes_health_information` BOOLEAN COMMENT 'Indicates whether Protected Health Information (PHI) as defined under HIPAA was among the data elements exposed. Determines applicability of HIPAA Breach Notification Rule and state health privacy laws.',
    `includes_ssn` BOOLEAN COMMENT 'Indicates whether Social Security Numbers (SSNs) were among the data elements exposed in the incident. SSN exposure triggers mandatory notification under virtually all 50 state data breach notification laws and heightens identity theft risk assessment.',
    `individual_notification_date` DATE COMMENT 'Date on which written notification was sent to affected individuals. Must occur within 60 days of discovery of a confirmed breach. Supports HIPAA compliance deadline tracking.',
    `individual_notification_required` BOOLEAN COMMENT 'Indicates whether written notification to affected individuals is required under the HIPAA Breach Notification Rule. Required for all confirmed breaches; must be sent within 60 days of discovery.',
    `involved_business_associate` BOOLEAN COMMENT 'Indicates whether a HIPAA Business Associate (BA) — such as a TPA, vendor, or service provider — was involved in or responsible for the privacy incident. Business associates have independent HIPAA breach notification obligations to the covered entity.',
    `is_breach_determined` BOOLEAN COMMENT 'Indicates whether the privacy incident has been formally determined to constitute a reportable breach under the HIPAA Breach Notification Rule following completion of the four-factor risk assessment. True = breach confirmed; False = not a breach (low probability of compromise).',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state code of the primary jurisdiction governing notification obligations for this incident. Determines which state data breach notification law applies and the applicable notification deadline.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the privacy incident record. Supports audit trail integrity and change management tracking.',
    `media_notification_date` DATE COMMENT 'Date on which notification was provided to prominent media outlets in the affected state(s). Required within 60 days of discovery for breaches affecting 500+ residents of a state.',
    `media_notification_required` BOOLEAN COMMENT 'Indicates whether notification to prominent media outlets is required. Triggered when a confirmed breach affects 500 or more residents of a single state or jurisdiction.',
    `multi_state_flag` BOOLEAN COMMENT 'Indicates whether the incident involves affected individuals across multiple states, triggering notification obligations under multiple state data breach notification laws simultaneously.',
    `no_breach_rationale` STRING COMMENT 'Documented justification when the incident is determined NOT to constitute a reportable breach, referencing the four-factor risk assessment outcome (nature/extent of PHI, unauthorized person, whether PHI was actually acquired/viewed, extent of risk mitigation). Required for HIPAA documentation obligations.',
    `notification_deadline_date` DATE COMMENT 'Calculated deadline by which all required notifications (HHS OCR, individuals, media, state AG, DOI) must be completed. Derived from discovery_date plus the applicable regulatory notification window (e.g., 60 days under HIPAA, 30–72 hours under NAIC model law). Stored for deadline monitoring and escalation.',
    `phi_data_elements_exposed` STRING COMMENT 'Comma-delimited list of PHI or PII data element categories involved in the incident (e.g., name, SSN, date_of_birth, diagnosis, policy_number, financial_account, biometric). Required for HHS OCR breach report and state AG notifications. [ENUM-REF-CANDIDATE: name|ssn|date_of_birth|diagnosis|treatment|policy_number|financial_account|biometric|address|email|phone — promote to reference product]',
    `remediation_actions_taken` STRING COMMENT 'Narrative description of corrective and remediation actions taken in response to the privacy incident (e.g., system access revoked, encryption implemented, workforce retrained, BA agreement updated, policy revised). Required for HIPAA documentation and regulatory examination.',
    `remediation_completed_date` DATE COMMENT 'Date on which all remediation actions were confirmed as completed. Supports closure of the incident record and regulatory documentation of corrective action.',
    `remediation_due_date` DATE COMMENT 'Target date by which all remediation actions must be completed. Used for compliance tracking and escalation management.',
    `reported_timestamp` TIMESTAMP COMMENT 'Date and time the privacy incident was formally reported to the compliance or privacy office. Establishes the internal reporting timeline for SOX controls and HIPAA workforce training obligations.',
    `risk_assessment_score` STRING COMMENT 'Overall risk level determined by the four-factor HIPAA breach risk assessment: (1) nature and extent of PHI involved, (2) identity of unauthorized person, (3) whether PHI was actually acquired or viewed, (4) extent to which risk has been mitigated. Drives breach determination and notification decisions.. Valid values are `low|moderate|high|critical`',
    `root_cause_category` STRING COMMENT 'High-level categorization of the root cause of the privacy incident. Used for trend analysis, remediation prioritization, and regulatory reporting to HHS OCR and state DOIs. [ENUM-REF-CANDIDATE: human_error|malicious_insider|external_attack|system_failure|vendor_error|process_failure|other — promote to reference product]',
    `state_ag_notification_date` DATE COMMENT 'Date on which notification was submitted to the State Attorney General. Deadline varies by state (e.g., 30 days in some states, 60 days in others).',
    `state_ag_notification_required` BOOLEAN COMMENT 'Indicates whether notification to the State Attorney General is required under applicable state data breach notification law. Requirements vary by state.',
    CONSTRAINT pk_privacy_incident PRIMARY KEY(`privacy_incident_id`)
) COMMENT 'Record of a HIPAA privacy incident, data breach, or unauthorized disclosure of Protected Health Information (PHI) or Personally Identifiable Information (PII). Captures incident type, discovery date, affected individuals count, data elements exposed, breach determination (yes/no), notification obligations triggered (HHS, state AG, affected individuals), notification dates, and remediation actions taken. Supports HIPAA Breach Notification Rule compliance and state data breach law reporting.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`sox_control` (
    `sox_control_id` BIGINT COMMENT 'Unique surrogate identifier for each SOX internal control over financial reporting (ICFR) record in the silver layer lakehouse.',
    `chart_of_accounts_id` BIGINT COMMENT 'Foreign key linking to finance.chart_of_accounts. Business justification: SOX controls are designed around specific GL accounts (e.g., revenue recognition control for account 4000). External auditors require control-to-account mapping for SOX 404 testing. Fundamental SOX co',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: SOX controls require named employee owners for accountability, audit trails, segregation of duties testing, and management assessment conclusions. Control ownership is fundamental to SOX 404 complianc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: SOX controls are often scoped to organizational units/cost centers (e.g., payroll controls for HR department). Auditors need to trace controls to responsible business units for testing and accountabil',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: SOX controls require documented evidence of performance, test work papers, and management sign-offs for external audit reliance. Essential for SOX 404 compliance testing and audit support. Replaces te',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: SOX controls are scoped to legal entities (only public/SOX-scope entities require SOX 404 controls). Fundamental SOX scoping requirement - controls must be mapped to in-scope entities.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: SOX controls govern investment valuation, trade authorization, portfolio accounting, and financial reporting. Real business process: SOX 404 testing, internal control assessment, audit support. Requir',
    `report_control_id` BIGINT COMMENT 'Foreign key linking to reporting.report_control. Business justification: SOX controls over financial reporting map to report-level controls (e.g., reserve calculation control links to statutory exhibit control). Enables SOX 404 control testing and financial reporting certi',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: SOX controls frequently test vendor-provided systems (policy admin, claims, financial reporting) or vendor-delivered services. Tracks vendor whose system or service is subject to SOX control testing a',
    `business_process` STRING COMMENT 'The core business process to which this control belongs (e.g., Policy Underwriting and Risk Assessment, Premium Billing and Collection, Claims Adjudication and Settlement, Actuarial Valuation and Reserving). Aligns to the enterprise process taxonomy.',
    `control_category` STRING COMMENT 'Indicates whether the control is executed manually by a person, fully automated by an IT system, relies on IT-generated reports (IT-dependent manual), or is a combination. Drives testing approach and reliance on IT general controls (ITGCs).. Valid values are `manual|automated|it_dependent_manual|hybrid`',
    `control_code` STRING COMMENT 'Externally-known alphanumeric control identifier used in audit workpapers, risk and control matrices (RCM), and regulatory filings. Follows the enterprise control numbering convention (e.g., SOX-PREM-0042 for premium billing controls).. Valid values are `^SOX-[A-Z]{2,6}-[0-9]{4}$`',
    `control_description` STRING COMMENT 'Detailed narrative describing the control objective, the specific procedure performed, the population covered, and the financial statement assertion addressed (existence, completeness, accuracy, valuation, presentation).',
    `control_level` STRING COMMENT 'Hierarchical level at which the control operates: entity_level covers company-wide controls (e.g., tone at the top, code of conduct); process_level covers a specific business process (e.g., premium billing); transaction_level covers individual transactions.. Valid values are `entity_level|process_level|transaction_level`',
    `control_name` STRING COMMENT 'Short, human-readable title of the internal control (e.g., Premium Revenue Recognition Review, DAC Amortization Approval). Used in dashboards, audit reports, and management attestation packages.',
    `control_owner_title` STRING COMMENT 'Job title of the control owner (e.g., VP of Actuarial, Controller, Chief Compliance Officer). Used for escalation routing and management attestation sign-off workflows.',
    `control_performer_name` STRING COMMENT 'Full name of the individual who executes the control on a day-to-day basis. May differ from the control owner (e.g., a senior analyst performs the control while the VP owns it).',
    `control_status` STRING COMMENT 'Current lifecycle state of the control. active indicates the control is in operation; inactive indicates it has been suspended; under_review indicates it is being reassessed; retired indicates it has been decommissioned.. Valid values are `active|inactive|under_review|retired`',
    `control_type` STRING COMMENT 'Classification of the control by its operational mechanism: preventive stops errors or fraud before they occur; detective identifies errors or irregularities after the fact; corrective remedies identified deficiencies.. Valid values are `preventive|detective|corrective`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this SOX control record was first created in the system. Provides audit trail for control inventory management and supports SOX Section 802 record retention requirements.',
    `deficiency_rating` STRING COMMENT 'Severity classification of any identified control deficiency: none (no deficiency), control_deficiency (minor gap), significant_deficiency (important enough to merit attention but not material), material_weakness (reasonable possibility of material misstatement — requires CEO/CFO disclosure under SOX Section 302/404).. Valid values are `none|control_deficiency|significant_deficiency|material_weakness`',
    `department` STRING COMMENT 'Business department or organizational unit responsible for executing and owning this control (e.g., Actuarial, Finance, Compliance, Claims, Underwriting, Investment Management).',
    `effective_date` DATE COMMENT 'The date on which this control became effective and operational. Used to determine the period of reliance for annual SOX assessments and to track control design changes over time.',
    `evidence_retention_years` STRING COMMENT 'Number of years that control evidence must be retained per SOX Section 802 and company records retention policy. SOX mandates a minimum of 7 years for audit workpapers and related records.',
    `exception_count` STRING COMMENT 'Number of exceptions or deviations identified during the most recent test of operating effectiveness. A non-zero value triggers deficiency evaluation and potential escalation to significant deficiency or material weakness classification.',
    `external_auditor_reliance` BOOLEAN COMMENT 'Indicates whether the external auditor (independent registered public accounting firm) has elected to rely on this control as part of their integrated audit under PCAOB AS 2201. Controls with reliance receive direct testing by the external auditor.',
    `financial_statement_area` STRING COMMENT 'The financial statement line item or account area that this control protects (e.g., Premium Revenue, Policy Reserves, DAC Asset, Claims Liability, Investment Income). Links the control to GAAP/SAP financial reporting. [ENUM-REF-CANDIDATE: premium_revenue|policy_reserves|dac_asset|claims_liability|investment_income|commission_expense|reinsurance_recoverable|annuity_liability — promote to reference product]',
    `financial_statement_assertion` STRING COMMENT 'The management assertion addressed by this control per PCAOB standards: existence (assets/liabilities exist), completeness (all transactions recorded), accuracy (correct amounts), valuation (appropriate measurement), cutoff (correct period), presentation (proper disclosure).. Valid values are `existence|completeness|accuracy|valuation|cutoff|presentation`',
    `frequency` STRING COMMENT 'How often the control is performed. Drives the testing sample size per PCAOB guidance (e.g., daily controls require larger samples than annual controls) and the scheduling of control execution reminders.. Valid values are `daily|weekly|monthly|quarterly|annually|ad_hoc`',
    `is_itgc` BOOLEAN COMMENT 'Indicates whether this control is an IT General Control (ITGC) covering access management, change management, computer operations, or program development. ITGCs underpin the reliability of automated application controls.',
    `is_key_control` BOOLEAN COMMENT 'Indicates whether this control is designated as a key control — one whose failure could result in a material misstatement in the financial statements. Key controls receive enhanced testing rigor and are included in the external auditors reliance scope.',
    `last_test_date` DATE COMMENT 'The most recent date on which this control was tested for operating effectiveness. Used to monitor testing currency and ensure controls are tested within required intervals per the annual SOX testing plan.',
    `last_test_result` STRING COMMENT 'The outcome of the most recent test of operating effectiveness: effective means the control operated as designed with no exceptions; ineffective means one or more exceptions were identified; not_tested means testing has not yet been completed for the current period.. Valid values are `effective|ineffective|not_tested`',
    `management_assessment_conclusion` STRING COMMENT 'Managements formal conclusion on the operating effectiveness of this control as part of the annual SOX Section 404(a) management assessment. effective supports the CEO/CFO certification; ineffective requires disclosure in the annual report.. Valid values are `effective|ineffective|not_assessed`',
    `next_scheduled_test_date` DATE COMMENT 'The planned date for the next test of operating effectiveness based on the annual SOX testing calendar and control frequency. Used by internal audit to manage workload scheduling and ensure all key controls are tested before year-end.',
    `related_policy_reference` STRING COMMENT 'Reference to the internal policy, procedure, or standard that this control implements or supports (e.g., FIN-POL-007 Reserve Estimation Policy, COMP-POL-012 AML Compliance Program). Links controls to the governance framework.',
    `remediation_completion_date` DATE COMMENT 'Actual date on which the remediation action was completed and validated. Null if remediation is still in progress. Compared against remediation_due_date to assess timeliness of corrective actions.',
    `remediation_description` STRING COMMENT 'Narrative description of the corrective action plan to address identified control deficiencies. Includes root cause analysis, specific remediation steps, and process or system changes required to restore control effectiveness.',
    `remediation_due_date` DATE COMMENT 'Target date by which the remediation action plan must be completed and the control must be retested to confirm effectiveness. Monitored by the compliance function and reported to the Audit Committee.',
    `remediation_required` BOOLEAN COMMENT 'Indicates whether a remediation action plan is required for this control based on identified deficiencies. True triggers the creation of a remediation tracking record and escalation to the control owner and compliance leadership.',
    `retirement_date` DATE COMMENT 'The date on which this control was retired or decommissioned. Null for active controls. Populated when a control is replaced, merged, or eliminated due to process changes or system automation.',
    `risk_rating` STRING COMMENT 'Inherent risk rating of the financial reporting area this control addresses. high risk areas (e.g., actuarial reserves, DAC) require more rigorous testing; low risk areas may qualify for reduced testing procedures.. Valid values are `high|medium|low`',
    `sample_size` STRING COMMENT 'Number of transactions or instances selected for testing in the most recent test execution. Sample sizes are determined by control frequency per PCAOB guidance (e.g., 25 for monthly, 60 for daily controls).',
    `sox_scope_year` STRING COMMENT 'The fiscal year for which this control is in scope for SOX Section 404 assessment and external auditor reliance. Controls may be added or removed from scope each year based on materiality and risk assessments.',
    `supporting_system` STRING COMMENT 'The operational system of record that generates the evidence or data relied upon by this control (e.g., Sapiens LifePro, AXIS Actuarial Valuation System, Guidewire ClaimCenter, Charles River IMS). Critical for ITGC scoping and system change impact assessment.',
    `test_approach` STRING COMMENT 'The audit testing methodology applied to evaluate operating effectiveness: inquiry (interviews), observation (watching the control), inspection (reviewing evidence), reperformance (independently re-executing), walkthrough (end-to-end process trace).. Valid values are `inquiry|observation|inspection|reperformance|walkthrough`',
    `tester_name` STRING COMMENT 'Full name of the individual (internal audit staff, external auditor, or co-sourced provider) who performed the most recent test of operating effectiveness. Required for audit trail and independence documentation.',
    `tester_type` STRING COMMENT 'Identifies who performed the test: internal_audit (companys internal audit function), external_auditor (independent registered public accounting firm), management (control owner self-assessment), co_sourced (third-party firm assisting internal audit).. Valid values are `internal_audit|external_auditor|management|co_sourced`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this SOX control record was most recently modified. Tracks changes to control design, ownership, scope, or test results. Essential for change management audit trails required under SOX.',
    CONSTRAINT pk_sox_control PRIMARY KEY(`sox_control_id`)
) COMMENT 'Master record of Sarbanes-Oxley (SOX) internal controls over financial reporting (ICFR) with integrated test execution history. Captures control ID, control description, control owner, control type, frequency, and all associated test execution records including test date, tester, test result, and remediation actions.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`attestation` (
    `attestation_id` BIGINT COMMENT 'Primary key for attestation',
    `employee_id` BIGINT COMMENT 'Identifier of the business officer, control owner, or business unit leader who formally signs and certifies the attestation. Typically a CEO, CFO, Chief Compliance Officer, or designated control owner.',
    `attestation_remediation_owner_employee_id` BIGINT COMMENT 'Identifier of the individual or role assigned accountability for executing the remediation plan associated with exceptions noted in this attestation.',
    `org_unit_id` BIGINT COMMENT 'Identifier of the business unit, division, or functional area responsible for the compliance obligation being attested. Enables domain-level compliance reporting and accountability tracking.',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Attestations require formal submission correspondence to regulators, external auditors, and internal stakeholders. Real business process: regulatory certification and compliance attestation submission',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_policy. Business justification: Attestations certify compliance with specific policies. The policy defines the regulatory framework and control domain being attested to.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Attestations are scoped to business units/cost centers (department heads attest to controls in their area). Standard SOX and regulatory compliance practice requires organizational unit attribution for',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Attestations generate signed certification documents, supporting schedules, and exception documentation required for regulatory filings and officer accountability. Critical for regulatory certificatio',
    `exam_finding_id` BIGINT COMMENT 'Reference to the examination finding that triggered this attestation, when the attestation is required as a remediation response to a market conduct or regulatory examination finding.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Compliance attestations certify portfolio compliance with investment guidelines and regulatory requirements. Real business process: quarterly compliance certification, investment committee attestation',
    `prior_attestation_id` BIGINT COMMENT 'Reference to the immediately preceding attestation for the same regulatory framework and business unit, enabling period-over-period comparison, trend analysis, and repeat exception identification.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Attestations certify compliance with regulatory obligations. The obligation defines the due date and regulatory framework being attested to.',
    `report_version_id` BIGINT COMMENT 'Foreign key linking to reporting.report_version. Business justification: Compliance attestations (actuarial opinions, CFO certifications) attach to specific report versions for regulatory filings. Links attestation to the certified report version for filing sign-off workfl',
    `reviewer_employee_id` BIGINT COMMENT 'Identifier of the compliance officer, internal auditor, or supervisor who reviewed and approved the attestation prior to submission. Supports segregation of duties and second-line-of-defense controls.',
    `sox_control_id` BIGINT COMMENT 'Foreign key linking to compliance.sox_control. Business justification: An attestation can attest to a specific SOX control. Currently, attestation has sox_control_reference (STRING) which is a weak reference. This should be converted to a proper FK relationship. The atte',
    `aml_program_element` STRING COMMENT 'Specific element of the AML/BSA compliance program being attested when attestation_type is AML_PROGRAM. Aligns to the five pillars of an effective AML program as required by FinCEN regulations.. Valid values are `CUSTOMER_IDENTIFICATION|TRANSACTION_MONITORING|SAR_FILING|TRAINING|INDEPENDENT_TESTING|DESIGNATED_BSA_OFFICER`',
    `attestation_status` STRING COMMENT 'Current lifecycle state of the attestation record, tracking progression from initial drafting through regulatory acceptance or rejection. Drives workflow routing and escalation.. Valid values are `DRAFT|PENDING_REVIEW|SUBMITTED|ACCEPTED|REJECTED|WITHDRAWN`',
    `attestation_type` STRING COMMENT 'Classification of the attestation by regulatory framework or internal control program. Drives the applicable regulatory citation, required signatories, and submission workflow. [ENUM-REF-CANDIDATE: SOX_302|SOX_906|ORSA|AML_PROGRAM|MARKET_CONDUCT|HIPAA_PRIVACY|DOL_FIDUCIARY|IRS_7702|STATE_DOI|FINRA_SUITABILITY — promote to reference product]',
    `attesting_officer_name` STRING COMMENT 'Full legal name of the officer or control owner who signed the attestation. Retained for audit trail and regulatory examination purposes independent of HR system changes.',
    `attesting_officer_title` STRING COMMENT 'Official job title of the attesting officer at the time of attestation (e.g., Chief Executive Officer, Chief Financial Officer, Chief Compliance Officer). Captured at point-in-time for regulatory record integrity.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the attestation record was first created in the compliance management system. Provides immutable audit trail entry point for regulatory examination and SOX audit purposes.',
    `electronic_signature_reference` STRING COMMENT 'Reference identifier or hash for the electronic signature applied by the attesting officer, providing cryptographic evidence of the officers certification. Supports non-repudiation requirements for regulatory examinations.',
    `exception_count` STRING COMMENT 'Total number of exceptions, deficiencies, or control gaps identified and documented within this attestation. Zero when exceptions_noted_flag is False. Supports risk severity scoring and trend analysis.',
    `exception_description` STRING COMMENT 'Narrative description of exceptions, deficiencies, or material weaknesses identified during the attestation review. Required when exceptions_noted_flag is True. Supports regulatory examination response and remediation planning.',
    `exceptions_noted_flag` BOOLEAN COMMENT 'Indicates whether the attesting officer identified any exceptions, deficiencies, or material weaknesses during the attestation process. True triggers mandatory exception documentation and remediation workflow.',
    `filing_reference_number` STRING COMMENT 'External reference number assigned by the regulatory authority upon receipt of the attestation filing (e.g., NAIC SERFF tracking number, SEC EDGAR accession number, state DOI filing ID). Enables cross-referencing with regulatory systems.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the regulatory jurisdiction to which this attestation applies. Null for federal-level attestations (SOX, AML/BSA, ERISA). Aligns with NAIC state DOI filing requirements.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording the most recent modification to the attestation record. Supports change tracking, audit trail completeness, and detection of unauthorized record alterations.',
    `line_of_business` STRING COMMENT 'Insurance line of business to which the attestation applies (e.g., Life, Annuity, Disability Income, Long-Term Care, Variable Products, Group). Supports product-level compliance segmentation and regulatory reporting.. Valid values are `LIFE|ANNUITY|DI|LTC|VARIABLE|GROUP`',
    `material_weakness_flag` BOOLEAN COMMENT 'Indicates whether any identified exception rises to the level of a material weakness in internal controls as defined under SOX/PCAOB standards. Material weaknesses require immediate escalation to the Audit Committee and external auditors.',
    `orsa_report_year` STRING COMMENT 'Calendar year of the ORSA report to which this attestation applies, when attestation_type is ORSA. The NAIC ORSA Model Act requires annual attestation by the Chief Risk Officer or equivalent.',
    `period_end_date` DATE COMMENT 'Last date of the compliance period covered by this attestation. Together with the start date, defines the full reporting window certified by the attesting officer.',
    `period_start_date` DATE COMMENT 'First date of the compliance period covered by this attestation. Defines the beginning of the reporting window for which the attesting officer is certifying adherence.',
    `rbc_ratio_attested` DECIMAL(18,2) COMMENT 'Risk-Based Capital ratio as attested by the officer for the relevant reporting period, when the attestation covers solvency or capital adequacy compliance. Expressed as a decimal ratio (e.g., 3.50 = 350% of authorized control level RBC).',
    `reference_number` STRING COMMENT 'Externally-known, human-readable business identifier for the attestation record, used in regulatory correspondence, audit trails, and examination submissions. Format: ATT-YYYY-NNNNNN.. Valid values are `^ATT-[0-9]{4}-[0-9]{6}$`',
    `regulatory_authority` STRING COMMENT 'The governing body or regulatory authority to which this attestation is directed or submitted. Determines submission channel, format requirements, and examination authority. [ENUM-REF-CANDIDATE: NAIC|STATE_DOI|SEC|FINRA|IRS|DOL|FINCEN|FASB|IAIS — 9 candidates stripped; promote to reference product]',
    `regulatory_citation` STRING COMMENT 'Specific statutory, regulatory, or rule citation that this attestation certifies compliance with (e.g., IRC Section 7702, SOX Section 302, 31 CFR Part 1010, HIPAA 45 CFR Part 164). Enables precise regulatory mapping.',
    `remediation_due_date` DATE COMMENT 'Target date by which all identified exceptions must be remediated and re-attested. Populated when remediation_required_flag is True. Drives compliance calendar and escalation management.',
    `remediation_required_flag` BOOLEAN COMMENT 'Indicates whether a formal remediation plan is required as a result of exceptions identified in this attestation. Triggers the remediation tracking workflow and assignment of a remediation owner.',
    `repeat_exception_flag` BOOLEAN COMMENT 'Indicates whether any exception noted in this attestation was also identified in the prior attestation period, signaling a persistent control deficiency. Repeat exceptions receive elevated regulatory scrutiny.',
    `review_date` DATE COMMENT 'Date on which the designated reviewer completed their review of the attestation prior to submission. Supports audit trail and segregation of duties documentation.',
    `scope_description` STRING COMMENT 'Narrative description of the specific compliance obligations, controls, processes, or regulatory requirements covered by this attestation. Provides context for audit examination and remediation tracking.',
    `sign_off_date` DATE COMMENT 'Date on which the final sign-off was granted or denied by the reviewing authority. Marks the completion of the internal approval workflow prior to regulatory submission.',
    `sign_off_status` STRING COMMENT 'Current approval status of the attestation sign-off workflow, reflecting whether the designated reviewer has approved, rejected, or escalated the attestation for further review.. Valid values are `PENDING|APPROVED|REJECTED|ESCALATED`',
    `significant_deficiency_flag` BOOLEAN COMMENT 'Indicates whether any identified exception constitutes a significant deficiency in internal controls, which is less severe than a material weakness but still requires communication to the Audit Committee under SOX/PCAOB standards.',
    `submission_date` DATE COMMENT 'Calendar date on which the completed attestation was formally submitted to the regulatory authority, internal audit committee, or designated compliance repository.',
    CONSTRAINT pk_attestation PRIMARY KEY(`attestation_id`)
) COMMENT 'Formal compliance attestation record submitted by business unit leaders, officers, or control owners certifying adherence to specific regulatory requirements or internal policies. Captures attestation type (SOX 302 CEO/CFO certification, ORSA attestation, state market conduct certification, AML program certification), attesting officer, attestation period, submission date, exceptions noted, and sign-off status. Supports audit trail for regulatory examinations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`training_course` (
    `training_course_id` BIGINT COMMENT 'Unique surrogate identifier for each compliance training course record in the master catalog. Serves as the primary key for the training_course data product.',
    `bonus_program_id` BIGINT COMMENT 'Foreign key linking to commission.bonus_program. Business justification: Training courses on specific bonus programs cover eligibility rules, compliance requirements, prohibited practices, and suitability standards. Real business process: producer education on incentive pr',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_policy. Business justification: Training courses implement compliance policy requirements. The policy defines the regulatory requirement and authority that mandates the training.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Compliance training content is frequently purchased from external vendors (CE providers, LMS vendors, content publishers). Tracks vendor providing course content for licensing, renewal, and vendor per',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Training program costs (course development, delivery platform, instructor fees) are allocated to cost centers for budgeting and expense management. Finance needs cost center attribution for training R',
    `employee_id` BIGINT COMMENT 'Identifier of the employee or licensed producer who completed or is enrolled in this training course. Links the completion record to the individuals HR or agent profile for compliance tracking, regulatory reporting, and license renewal management.',
    `guideline_id` BIGINT COMMENT 'Foreign key linking to investment.investment_guideline. Business justification: Training courses educate staff on investment guidelines and compliance requirements. Real business process: compliance training, investment policy education, staff certification. Standard insurance in',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Compliance training courses cover preparation of specific regulatory reports (e.g., NAIC Annual Statement training). Links course to the report it trains on for regulatory reporting competency managem',
    `aml_course_flag` BOOLEAN COMMENT 'Indicates whether this course satisfies Anti-Money Laundering (AML) and Bank Secrecy Act (BSA) training requirements under FinCEN regulations. True triggers AML compliance tracking and annual completion verification for all applicable employees and producers.',
    `approved_by` STRING COMMENT 'Name or identifier of the compliance officer or manager who approved a training waiver or exemption. Required for SOX control documentation and regulatory examination evidence when a mandatory training requirement is waived.',
    `attempt_number` STRING COMMENT 'Sequential attempt number for the learners assessment on this course version (1 = first attempt). Tracked against max_attempts_allowed to enforce compliance escalation rules when a learner repeatedly fails a mandatory regulatory training course.',
    `ce_approval_number` STRING COMMENT 'State-issued CE course approval number assigned by the Department of Insurance. Required for CE credit reporting to state regulators upon producer completion. May be a composite of state code and approval number (e.g., TX-CE-2024-00123).',
    `ce_credit_hours` DECIMAL(18,2) COMMENT 'Number of continuing education (CE) credit hours awarded upon successful completion of this course. Applicable to licensed insurance producers subject to state CE requirements. Zero for non-CE courses. Reported to state Departments of Insurance for producer license renewal compliance.',
    `certificate_number` STRING COMMENT 'Unique certificate number issued to the learner upon successful completion of the course. Serves as the primary evidence identifier for regulatory examinations, producer licensing audits, and AML/HIPAA compliance demonstrations.',
    `completion_certificate_template` STRING COMMENT 'Reference identifier or name of the certificate template used to generate completion certificates for this course. Certificates are issued to learners upon passing and may be required as evidence during regulatory examinations or producer licensing audits.',
    `completion_date` DATE COMMENT 'Date on which the learner successfully completed the training course and achieved a passing score. This is the principal business event date for compliance tracking, CE credit reporting, and renewal expiration calculation.',
    `course_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the training course in the compliance training catalog and on certificates of completion (e.g., AML-101, HIPAA-202, SUIT-301). Used for regulatory reporting and cross-system reference.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `course_description` STRING COMMENT 'Detailed narrative description of the course content, learning objectives, and regulatory topics covered (e.g., AML red flags, HIPAA minimum necessary standard, suitability analysis under NAIC Suitability in Annuity Transactions Model Regulation). Used in the compliance training catalog and regulatory examination documentation.',
    `course_name` STRING COMMENT 'Full descriptive title of the compliance training course as it appears in the learning management system and on certificates (e.g., Anti-Money Laundering Fundamentals for Insurance Producers, HIPAA Privacy and Security for Life Insurance Operations).',
    `course_status` STRING COMMENT 'Current lifecycle status of the training course in the compliance curriculum. active courses are available for enrollment; retired courses are superseded by newer versions; draft courses are under development; pending_approval courses await regulatory or compliance officer sign-off.. Valid values are `active|inactive|draft|retired|pending_approval`',
    `course_type` STRING COMMENT 'Classification of the course as mandatory (required for all or a defined audience by regulation or company policy), elective (optional professional development), remedial (assigned following a compliance finding or exam failure), or refresher (periodic renewal of a previously completed mandatory course).. Valid values are `mandatory|elective|remedial|refresher`',
    `course_version` STRING COMMENT 'Version identifier of the course content (e.g., 1.0, 2.1, 3.0). Tracks curriculum updates driven by regulatory changes, new NAIC model regulations, IRS rule changes, or updated AML/BSA guidance. Completion records must reference the version in effect at time of completion.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the training course record was first created in the compliance training catalog. Supports audit trail requirements under SOX, NAIC market conduct examination standards, and data lineage tracking in the Databricks Silver layer.',
    `delivery_method` STRING COMMENT 'The modality through which the training course is delivered to learners. Determines scheduling, platform requirements, and completion tracking mechanisms. assessment_only applies to courses where learners test out of content.. Valid values are `online_self_paced|instructor_led|webinar|blended|video|assessment_only`',
    `delivery_platform` STRING COMMENT 'Name of the learning management system (LMS) or platform through which the course is delivered and completion records are tracked (e.g., Cornerstone OnDemand, Workday Learning, SAP SuccessFactors, Absorb LMS). Used for system-of-record reconciliation and audit trail.',
    `duration_minutes` STRING COMMENT 'Estimated or required seat time for the training course expressed in minutes. Used for scheduling, continuing education (CE) credit hour calculations, and regulatory reporting of training hours completed.',
    `effective_date` DATE COMMENT 'Date on which this version of the training course becomes effective and available for enrollment. Completions recorded on or after this date are credited against the current version. Aligns with regulatory effective dates for updated compliance requirements.',
    `ethics_course_flag` BOOLEAN COMMENT 'Indicates whether this course satisfies ethics training requirements for licensed producers or employees. Ethics CE credits are separately tracked and reported to state Departments of Insurance for producer license renewal.',
    `expiration_date` DATE COMMENT 'Date on which the learners completion credit for this course expires and renewal is required to maintain compliance. Calculated as completion_date plus renewal_frequency_months. Null for one-time completion courses. Drives automated renewal reminder and compliance gap reporting.',
    `hipaa_course_flag` BOOLEAN COMMENT 'Indicates whether this course satisfies HIPAA Privacy and Security Rule training requirements under 45 CFR §164.530(b). True triggers HIPAA compliance tracking and periodic completion verification for all workforce members with access to protected health information (PHI).',
    `is_ce_approved` BOOLEAN COMMENT 'Indicates whether this course has been approved by one or more state Departments of Insurance for continuing education (CE) credit toward producer license renewal. True triggers CE credit reporting workflows upon completion.',
    `is_renewal_required` BOOLEAN COMMENT 'Indicates whether periodic renewal of this training course is required to maintain compliance. True for recurring mandatory courses such as annual AML/BSA and biennial HIPAA training; False for one-time completion courses.',
    `jurisdiction_applicability` STRING COMMENT 'Comma-separated list of US state codes or ALL indicating the jurisdictions for which this course satisfies a regulatory training requirement. Supports state-specific CE credit reporting to Departments of Insurance and multi-state compliance tracking.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the training course record was most recently modified. Tracks curriculum updates, version changes, and status transitions for audit trail and data lineage purposes in the Silver layer.',
    `line_of_business` STRING COMMENT 'The insurance line of business to which this training course applies. Determines which licensed producers or employees are required to complete the course. variable applies to variable life and variable annuity products subject to SEC/FINRA oversight.. Valid values are `life|annuity|disability|long_term_care|variable|all`',
    `max_attempts_allowed` STRING COMMENT 'Maximum number of times a learner may attempt the course assessment before escalation or remedial action is required. Null indicates unlimited attempts. Supports compliance enforcement workflows for mandatory regulatory training.',
    `pass_fail_status` STRING COMMENT 'Outcome of the learners course assessment. pass indicates the passing_score_threshold was met; fail triggers remedial assignment; incomplete indicates the course was started but not finished; waived indicates a regulatory or management-approved exemption from completion.. Valid values are `pass|fail|incomplete|waived`',
    `passing_score_threshold` DECIMAL(18,2) COMMENT 'Minimum assessment score (expressed as a percentage, e.g., 70.00 = 70%) required to achieve a passing status and receive credit for course completion. Used to validate compliance with regulatory training standards and to trigger remedial assignment if not met.',
    `renewal_frequency_months` STRING COMMENT 'Number of months after initial completion before the course must be retaken to maintain compliance (e.g., 12 for annual AML refresher, 24 for biennial HIPAA training). Null indicates a one-time completion requirement with no renewal obligation.',
    `retirement_date` DATE COMMENT 'Date on which this version of the training course is retired and no longer available for new enrollments. Completions after this date are not credited. Null if the course is currently active with no planned retirement.',
    `score_achieved` DECIMAL(18,2) COMMENT 'Percentage score achieved by the learner on the course assessment (e.g., 85.00 = 85%). Compared against passing_score_threshold to determine pass/fail status. Retained for regulatory examination evidence and remediation tracking.',
    `stoli_course_flag` BOOLEAN COMMENT 'Indicates whether this course covers Stranger-Originated Life Insurance (STOLI) awareness and prevention training. STOLI training is required for producers in states with NAIC Life Insurance Consumer Disclosure Model Regulation compliance obligations.',
    `suitability_course_flag` BOOLEAN COMMENT 'Indicates whether this course satisfies suitability training requirements for annuity and life insurance product sales under the NAIC Suitability in Annuity Transactions Model Regulation #275 or FINRA Rule 2111. True triggers suitability compliance tracking for licensed producers.',
    `target_audience` STRING COMMENT 'Description of the intended audience for this course, specifying roles, departments, or license types required to complete it (e.g., All licensed producers, Claims adjusters, New business underwriters, All employees with access to PHI). Used to drive automated training assignment workflows.',
    `variable_product_course_flag` BOOLEAN COMMENT 'Indicates whether this course is specific to variable life (VUL) or variable annuity products subject to SEC and FINRA oversight. True requires completion tracking for FINRA-registered representatives and broker-dealer compliance reporting.',
    `waiver_reason` STRING COMMENT 'Documented reason for waiving the training completion requirement for a specific learner (e.g., Equivalent training completed at prior employer, Subject matter expert exemption, Regulatory grandfather provision). Required when pass_fail_status is waived for audit trail purposes.',
    CONSTRAINT pk_training_course PRIMARY KEY(`training_course_id`)
) COMMENT 'Master catalog of compliance training courses with integrated individual completion records. Captures course name, regulatory requirement driving the training (AML, HIPAA, suitability, STOLI, ethics), target audience, delivery method, duration, passing score threshold, renewal frequency, and course version. Includes individual completion records: employee or agent identifier, completion date, score achieved, pass/fail status, certificate number, expiration date, training delivery platform, and renewal tracking. Serves as the single source of truth for both training curriculum management and regulatory demonstration that all required AML, HIPAA, suitability, and ethics training obligations are met for licensed producers and employees.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`compliance_training_completion` (
    `compliance_training_completion_id` BIGINT COMMENT 'Unique surrogate identifier for each compliance training completion record in the silver layer lakehouse. Primary key for this transactional entity.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Training completions generate CE certificates, course completion documentation, and credit reporting records required for license maintenance and regulatory compliance. Essential for producer licensin',
    `outbound_notice_id` BIGINT COMMENT 'Foreign key linking to correspondence.outbound_notice. Business justification: Training completions trigger certificate delivery notices and CE credit reporting communications to employees and state regulators. Real business process: compliance training certificate distribution ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: When training is vendor-delivered, tracking the vendor is essential for CE credit reporting, audit trails, and vendor performance evaluation. Tracks vendor delivering training for completion record va',
    `license_id` BIGINT COMMENT 'Foreign key linking to agent.license. Business justification: CE credits earned through training apply to specific state licenses for renewal. License_id links training completion to the license being renewed, enabling automated CE compliance tracking and renewa',
    `employee_id` BIGINT COMMENT 'Identifier of the individual (employee or licensed producer/agent) who completed the training course. Links to the party master for the trainee.',
    `training_course_id` BIGINT COMMENT 'Identifier of the compliance training course that was completed. Links to the course master record containing course details, regulatory mapping, and required passing criteria.',
    `attempt_number` STRING COMMENT 'Sequential attempt number for this training course by the trainee. A value greater than 1 indicates a retake following a prior failed attempt. Used to track remediation compliance and identify trainees requiring additional support.',
    `ce_credit_reported_date` DATE COMMENT 'Date on which the CE credit hours were reported to the state Department of Insurance or NIPR. Populated when ce_credit_reported_flag is True.',
    `ce_credit_reported_flag` BOOLEAN COMMENT 'Indicates whether the CE credit hours for this completion have been reported to the applicable state Department of Insurance or NIPR. True = reported; False = pending reporting. Drives CE reporting workflow and compliance gap identification.',
    `certificate_number` STRING COMMENT 'Unique certificate or credential number issued by the training platform or regulatory body upon successful course completion. Serves as the primary proof-of-completion identifier for regulatory audits and market conduct examinations.',
    `completion_date` DATE COMMENT 'Calendar date on which the trainee completed the training course. This is the principal business event date used for regulatory compliance demonstration, continuing education credit reporting, and obligation fulfillment tracking.',
    `completion_reference_number` STRING COMMENT 'Externally-known business identifier for this training completion record, typically generated by the Learning Management System (LMS) or compliance training platform. Used for audit trail and regulatory demonstration purposes.',
    `completion_status` STRING COMMENT 'Current lifecycle status of the training completion record. completed indicates the trainee passed; failed indicates the trainee did not meet the passing threshold; in_progress indicates the course is underway; waived indicates a regulatory waiver was granted; overdue indicates the deadline has passed without completion; withdrawn indicates the enrollment was cancelled.. Valid values are `completed|failed|in_progress|waived|overdue|withdrawn`',
    `course_category` STRING COMMENT 'Regulatory or functional category of the training course. Drives compliance obligation tracking and regulatory reporting. AML_BSA maps to FinCEN requirements; HIPAA maps to 45 CFR §164; suitability maps to NAIC Model Regulation; fiduciary maps to DOL ERISA. [ENUM-REF-CANDIDATE: AML_BSA|HIPAA|suitability|ethics|continuing_education|product_training|fiduciary|cybersecurity — promote to reference product]',
    `course_duration_minutes` STRING COMMENT 'Total seat time or duration of the training course in minutes as defined by the course design. Used for CE credit hour calculation and regulatory reporting of training hours.',
    `course_version` STRING COMMENT 'Version identifier of the training course content completed by the trainee. Ensures regulatory compliance is demonstrated against the correct content version, particularly important when course content is updated to reflect regulatory changes.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this training completion record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the audit trail creation point for SOX and regulatory examination purposes.',
    `credit_hours` DECIMAL(18,2) COMMENT 'Number of continuing education (CE) credit hours awarded upon successful completion of the course. Used for state DOI producer license renewal reporting and FINRA CE compliance tracking.',
    `delivery_method` STRING COMMENT 'Method by which the training was delivered to the trainee. Distinguishes between self-paced eLearning, virtual instructor-led, in-person classroom, blended, on-the-job, and externally-provided training. Relevant for CE credit eligibility and regulatory acceptance.. Valid values are `online_self_paced|instructor_led_virtual|instructor_led_classroom|blended|on_the_job|external_provider`',
    `delivery_platform` STRING COMMENT 'Name of the learning management system (LMS) or training delivery platform through which the course was administered (e.g., Cornerstone OnDemand, Workday Learning, LIMRA eLearning, RegEd, Kaplan Financial). Used for system-of-record reconciliation and audit trail.',
    `department_code` STRING COMMENT 'Organizational department or business unit code of the trainee at the time of training completion. Used for compliance reporting by department, cost allocation, and organizational analytics.',
    `due_date` DATE COMMENT 'Regulatory or organizational deadline by which the training must be completed. Used for overdue tracking, escalation workflows, and compliance gap reporting.',
    `enrollment_date` DATE COMMENT 'Date on which the trainee was enrolled or assigned to the training course. Used to calculate time-to-completion and to track compliance with mandatory enrollment deadlines.',
    `expiration_date` DATE COMMENT 'Date on which the training certification or credit expires and recertification is required. Drives renewal obligation scheduling and producer license maintenance tracking.',
    `is_mandatory` BOOLEAN COMMENT 'Indicates whether this training course is mandatory for the trainee based on their role, license type, or regulatory obligation. True = mandatory compliance training; False = voluntary or elective training.',
    `is_regulatory_required` BOOLEAN COMMENT 'Indicates whether this training completion satisfies a specific external regulatory requirement (True) as opposed to an internal organizational policy requirement only (False). Drives regulatory reporting and examination evidence packages.',
    `job_role_code` STRING COMMENT 'Code representing the trainees job role or position at the time of training completion (e.g., AGENT, UNDERWRITER, CLAIMS_ADJ, COMPLIANCE_OFFICER). Determines applicable mandatory training curriculum and regulatory obligations.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state code of the jurisdiction whose continuing education or compliance training requirement this completion satisfies. Relevant for state DOI-mandated producer continuing education and state-specific AML training requirements.. Valid values are `^[A-Z]{2}$`',
    `max_attempts_allowed` STRING COMMENT 'Maximum number of assessment attempts permitted for this course as defined by the training policy or regulatory requirement. Captured at completion for audit immutability.',
    `npn` STRING COMMENT 'NAIC-assigned National Producer Number (NPN) uniquely identifying the licensed producer across all states. Used for multi-state CE credit reporting to state DOIs and NIPR (National Insurance Producer Registry) reconciliation.. Valid values are `^[0-9]{1,10}$`',
    `pass_fail_status` STRING COMMENT 'Binary outcome of the training assessment indicating whether the trainee met the minimum passing score threshold. not_applicable is used for awareness-only courses with no scored assessment.. Valid values are `pass|fail|not_applicable`',
    `passing_score_threshold` DECIMAL(18,2) COMMENT 'Minimum score percentage required to pass the training course assessment, as defined by the regulatory body or organizational policy at the time of completion. Captured at completion for audit immutability.',
    `regulatory_framework` STRING COMMENT 'Primary regulatory framework or governing body whose training obligation this completion satisfies (e.g., AML_BSA for FinCEN requirements, HIPAA for privacy training, SOX for internal controls attestation, ERISA for fiduciary training). [ENUM-REF-CANDIDATE: AML_BSA|HIPAA|SOX|ERISA|FINRA|NAIC|IRS_7702|SEC|state_DOI|ORSA_ERM — promote to reference product]',
    `score` DECIMAL(18,2) COMMENT 'Numeric score achieved by the trainee on the course assessment, expressed as a percentage (0.00–100.00). Used to determine pass/fail status against the minimum passing score threshold and to document regulatory compliance.',
    `time_spent_minutes` STRING COMMENT 'Actual time in minutes the trainee spent engaged with the training course content, as recorded by the LMS. May differ from course duration for self-paced courses. Used for CE credit validation and engagement analytics.',
    `trainee_full_name` STRING COMMENT 'Full legal name of the individual who completed the training course. Captured at time of completion for audit and regulatory reporting purposes.',
    `trainee_type` STRING COMMENT 'Classification of the individual completing the training, distinguishing between internal employees, licensed producers/agents, registered representatives, TPAs, and contractors. Determines applicable regulatory training obligations. [ENUM-REF-CANDIDATE: employee|licensed_producer|broker|registered_representative|third_party_administrator|contractor — promote to reference product]. Valid values are `employee|licensed_producer|broker|registered_representative|third_party_administrator|contractor`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this training completion record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change tracking, data lineage, and audit trail in the silver layer.',
    `waiver_approved_by` STRING COMMENT 'Name or identifier of the compliance officer or supervisor who approved the training waiver. Required for SOX control documentation and regulatory examination evidence.',
    `waiver_flag` BOOLEAN COMMENT 'Indicates whether a formal waiver was granted exempting the trainee from completing this training course. When True, waiver_reason must be populated. Used for regulatory audit documentation.',
    `waiver_reason` STRING COMMENT 'Documented reason for granting a training waiver, such as equivalent prior certification, regulatory exemption, or role change. Required when waiver_flag is True. Supports regulatory examination evidence.',
    CONSTRAINT pk_compliance_training_completion PRIMARY KEY(`compliance_training_completion_id`)
) COMMENT 'Transactional record of an individuals completion of a required compliance training course. Captures the employee or agent, course completed, completion date, score achieved, pass/fail status, certificate number, expiration date, and training delivery platform. Supports regulatory demonstration that AML, HIPAA, suitability, and ethics training obligations are met for all licensed producers and employees.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`policy_form_approval` (
    `policy_form_approval_id` BIGINT COMMENT 'Unique surrogate identifier for each policy form or rate filing approval record. Primary key for the policy_form_approval data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Form filing costs (actuarial review, legal counsel, state filing fees) are tracked by product development cost center for product profitability analysis and budget management.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Form filing services (SERFF filing agents, actuarial consultants for rate justification, legal counsel for regulatory review) are commonly outsourced. Tracks vendor providing form filing and actuarial',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Form approvals require the actual policy form documents, rate manuals, actuarial certifications, and DOI approval letters. Essential for state form filing workflow and approved form library management',
    `ifrs17_contract_group_id` BIGINT COMMENT 'Foreign key linking to finance.ifrs17_contract_group. Business justification: Form approvals determine product features that drive IFRS 17 contract grouping (profitability classification, cohort year, measurement model, coverage period). Product design determines IFRS 17 accoun',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Form approvals are entity-specific (each legal entity must file for approval in each jurisdiction where it operates). Fundamental regulatory filing requirement for product distribution.',
    `plan_id` BIGINT COMMENT 'Foreign key linking to product.product_plan. Business justification: Form approvals are state-specific approvals of product plans for sale in each jurisdiction. Each approval record ties to the plan being approved. Critical for determining which plans can be sold in wh',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Form approvals are version-specific - when a plan version changes (benefits, rates, terms), new state approvals are required. More granular than plan-level linking. Essential for version control, stat',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Policy form approvals are regulatory filings that fulfill specific state DOI obligations. The obligation defines the filing type and requirements.',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Policy form approvals must comply with state-specific insurance regulations. The approval describes the filing, while the regulation describes the state-specific rules governing form approval.',
    `acord_form_reference` STRING COMMENT 'The ACORD standard form number or reference that corresponds to this filing, if the filed form is based on or aligned with an ACORD industry-standard form template. Supports interoperability with industry data exchange standards.',
    `actuarial_justification_reference` STRING COMMENT 'Reference identifier for the actuarial memorandum or actuarial certification document that supports the rate filing, including loss ratio analysis, experience data, and rate adequacy demonstration. Required for rate filings per state DOI requirements.',
    `approval_date` DATE COMMENT 'The date on which the state DOI formally approved the form or rate filing. Null if the filing is pending, disapproved, or withdrawn.',
    `approval_status` STRING COMMENT 'Current lifecycle status of the form or rate filing with the state DOI. Drives whether the form or rate may be used in the jurisdiction. Deemed approved applies when the DOI has not acted within the statutory review period.. Valid values are `pending|approved|disapproved|withdrawn|deemed_approved|conditionally_approved`',
    `company_filing_reference` STRING COMMENT 'Internal company-assigned reference number used to track the filing within the companys compliance and policy administration systems, independent of the SERFF or DOI reference numbers.',
    `company_response_date` DATE COMMENT 'The date on which the company submitted its formal response to DOI objections or requests for additional information. Tracks responsiveness within the regulatory review cycle.',
    `conditional_approval_conditions` STRING COMMENT 'Description of conditions or modifications required by the DOI as part of a conditional approval. The company must satisfy these conditions before or concurrent with use of the form or rate. Populated only when approval_status is conditionally_approved.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this policy form approval record was first created in the compliance data product, capturing the initial data entry or system ingestion event.',
    `deemed_approved_date` DATE COMMENT 'The date on which the filing is deemed approved by operation of law because the DOI did not act within the statutory review period. Calculated as submission_date plus review_period_days. Null if the DOI acted before the deadline.',
    `disapproval_reason` STRING COMMENT 'The stated reason provided by the state DOI for disapproving the form or rate filing. Populated only when approval_status is disapproved. Used to guide remediation and refiling efforts.',
    `doi_approval_reference` STRING COMMENT 'The official approval reference number, certificate number, or acknowledgment identifier issued by the state Department of Insurance (DOI) upon approval of the filing. Used to evidence regulatory compliance during market conduct examinations.',
    `doi_objection_details` STRING COMMENT 'Narrative description of objections, deficiency letters, or requests for additional information issued by the state DOI during the review process. Captures the substance of regulatory concerns requiring company response.',
    `effective_date` DATE COMMENT 'The date on which the approved form or rate schedule becomes effective for use in new policy issuance or in-force policy administration within the jurisdiction. For rate filings, this is the proposed or approved rate effective date.',
    `expiration_date` DATE COMMENT 'The date on which the form or rate approval expires or is superseded, after which the form or rate may no longer be used for new business. Null for approvals with no defined expiration.',
    `filing_description` STRING COMMENT 'Narrative description of the purpose and scope of the filing, including key changes from prior versions, new product features, benefit modifications, or regulatory compliance updates driving the submission.',
    `filing_method` STRING COMMENT 'The regulatory filing method required by the jurisdiction for this form or rate filing. Prior approval requires DOI approval before use; file-and-use allows use upon filing; use-and-file allows use before filing; informational is for notice only.. Valid values are `prior_approval|file_and_use|use_and_file|informational`',
    `filing_owner` STRING COMMENT 'Name or identifier of the internal compliance officer, actuary, or product manager responsible for managing this filing through the regulatory approval process.',
    `filing_reference_number` STRING COMMENT 'Externally-known unique reference number assigned to the filing submission, as issued by the state Department of Insurance (DOI) or the companys internal filing tracking system (e.g., SERFF tracking number or company-assigned filing ID).',
    `form_edition_date` DATE COMMENT 'The edition date printed on the form document, typically in MM-YYYY format, identifying the specific version of the form. Used to distinguish between successive revisions of the same form number.',
    `form_number` STRING COMMENT 'The official form number assigned by the company to uniquely identify the policy form, rider form, endorsement form, application form, or rate schedule document. Used to reference the specific document version in policy administration systems.',
    `form_title` STRING COMMENT 'The descriptive title of the policy form, rider, endorsement, or rate schedule as it appears on the filed document (e.g., Term Life Insurance Policy, Accidental Death Benefit (ADB) Rider, Long-Term Care (LTC) Inflation Protection Endorsement).',
    `form_type` STRING COMMENT 'Classification of the filed document indicating whether it is a base policy form, rider, endorsement, application form, rate schedule, or amendment. Determines the regulatory review pathway and approval requirements.. Valid values are `base_policy|rider|endorsement|application|rate_schedule|amendment`',
    `irc_7702_compliant_flag` BOOLEAN COMMENT 'Indicates whether the filed policy form has been reviewed and confirmed to comply with IRC Section 7702 life insurance tax qualification requirements, including the Cash Value Accumulation Test (CVAT) or Guideline Premium Test (GPT). Critical for life insurance tax treatment.',
    `is_currently_approved` BOOLEAN COMMENT 'Indicates whether the form or rate is currently approved and authorized for use in the jurisdiction as of the current date. Derived from approval_status and effective/expiration dates; serves as the operational compliance gate for policy issuance systems.',
    `is_in_use` BOOLEAN COMMENT 'Indicates whether the form or rate schedule is actively being used in new business issuance or in-force policy administration within the jurisdiction. Distinguishes approved-but-not-deployed forms from actively deployed ones.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the jurisdiction in which this form or rate filing was submitted to the Department of Insurance. Ensures only approved forms and rates are used in each specific jurisdiction.. Valid values are `^[A-Z]{2}$`',
    `ltc_rate_increase_percentage` DECIMAL(18,2) COMMENT 'For Long-Term Care (LTC) insurance rate increase filings, the specific percentage increase in LTC premiums requested from the DOI. Subject to heightened regulatory scrutiny and actuarial justification requirements under NAIC LTC model regulations.',
    `mec_test_type` STRING COMMENT 'Identifies the IRC Section 7702 compliance test methodology applied to the policy form: Cash Value Accumulation Test (CVAT) or Guideline Premium Test (GPT). Determines Modified Endowment Contract (MEC) status thresholds. Not applicable for annuity or non-life products.. Valid values are `cvat|gpt|not_applicable`',
    `naic_product_code` STRING COMMENT 'The NAIC standardized product code assigned to the insurance product type associated with this filing. Used for regulatory reporting, market conduct analysis, and cross-state filing coordination.',
    `outside_counsel_reference` STRING COMMENT 'Reference to the external legal counsel or regulatory affairs firm engaged to support the filing, if applicable. Used for complex or contested filings requiring specialized regulatory legal expertise.',
    `prior_form_number` STRING COMMENT 'The form number of the previously approved version that this filing supersedes or replaces. Enables traceability of form revision history and supports grandfathering analysis for in-force policies.',
    `product_line` STRING COMMENT 'The insurance product line to which the filed form or rate schedule applies (e.g., Term Life, Whole Life (WL), Universal Life (UL), Variable Universal Life (VUL), Annuity, Long-Term Care (LTC), Disability Income (DI), Group Life). [ENUM-REF-CANDIDATE: term_life|whole_life|universal_life|variable_life|indexed_universal_life|fixed_indexed_annuity|variable_annuity|ltc|disability_income|group_life|spia — promote to reference product]',
    `rate_change_percentage` DECIMAL(18,2) COMMENT 'For rate filings, the percentage change in premium rates proposed or approved relative to the current in-force rates. Positive values indicate a rate increase; negative values indicate a rate decrease. Null for form-only filings.',
    `rate_filing_type` STRING COMMENT 'For rate filings, classifies the nature of the rate action: new rate schedule introduction, revision to existing rates, Long-Term Care (LTC) rate increase filing, or withdrawal of a rate schedule. Null for pure form filings.. Valid values are `new_rate|rate_revision|ltc_rate_increase|rate_withdrawal`',
    `review_period_days` STRING COMMENT 'The statutory or regulatory maximum number of days the DOI has to review and act on the filing before it is deemed approved (for prior approval states). Varies by state and product line.',
    `sec_registration_number` STRING COMMENT 'For variable product filings, the SEC registration number (e.g., Form S-1, Form N-4 registration) associated with the product. Required for variable life and variable annuity products subject to SEC registration. Null for non-variable products.',
    `serff_tracking_number` STRING COMMENT 'The unique tracking number assigned by the NAICs System for Electronic Rate and Form Filing (SERFF) platform when the filing is submitted electronically. Primary cross-reference identifier for SERFF-based filings.',
    `submission_date` DATE COMMENT 'The date on which the form or rate filing was formally submitted to the state Department of Insurance. Marks the start of the regulatory review clock for prior approval filings.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this policy form approval record was most recently updated, reflecting any changes to filing status, approval dates, DOI responses, or other attributes.',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether the filed form or rate applies to a variable insurance or annuity product subject to SEC and FINRA oversight in addition to state DOI regulation. Triggers additional compliance requirements for variable product filings.',
    `withdrawal_date` DATE COMMENT 'The date on which the company voluntarily withdrew the filing from DOI review. Populated only when approval_status is withdrawn.',
    CONSTRAINT pk_policy_form_approval PRIMARY KEY(`policy_form_approval_id`)
) COMMENT 'Master record of state DOI filings for policy forms, rider forms, endorsement forms, and premium rate schedules. For form filings: captures form number, form type (base policy, rider, endorsement, application), product line, filing method (prior approval, file-and-use, use-and-file), state, submission/approval dates, approval reference, and form status. For rate filings: captures filing type (new rate, rate revision, LTC rate increase), actuarial justification reference, proposed effective date, approval status, rate change percentage, and DOI response details. Ensures only approved forms and rates are used in each jurisdiction, supports state rate regulation compliance, and serves as the single source of truth for all form and rate approval status across all jurisdictions.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`rate_filing` (
    `rate_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each rate filing record in the compliance domain. Primary key for the rate_filing data product.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Rate filings require actuarial certification, often from external consulting actuaries. Tracks third-party actuarial firm providing rate justification, loss ratio analysis, and actuarial memorandum fo',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Rate filing preparation costs (actuarial analysis, regulatory filings, legal review) are significant and tracked by cost center for product line profitability and pricing adequacy analysis.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Rate filings are made by specific legal entities in specific jurisdictions. Fundamental regulatory filing requirement - rates must be approved for each entity in each state.',
    `plan_id` BIGINT COMMENT 'Reference to the insurance product (e.g., term life, whole life, LTC, annuity) for which the rate filing is submitted. Links the filing to the specific product line subject to rate regulation.',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Rate filings reference specific approved policy forms (rate changes apply to approved form numbers). Links rate filing to the form approval for product launch coordination and regulatory compliance va',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Rate filings fulfill regulatory obligations for premium rate approval. The obligation defines the filing type and jurisdiction requirements.',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Rate filings must comply with state-specific rate filing regulations. The filing describes the submission, while the regulation describes the state-specific rules governing rate approval.',
    `affected_policy_count` STRING COMMENT 'Number of in-force policies in the filing jurisdiction that will be affected by the proposed rate change. Required for LTC rate increase filings and used by the DOI to assess consumer impact. Derived from policy administration system counts at time of filing.',
    `annual_premium_impact_amount` DECIMAL(18,2) COMMENT 'Estimated total annual premium impact (in USD) of the proposed rate change across all affected in-force policies in the filing jurisdiction. Used by the DOI to assess the financial impact on policyholders and by the company for financial planning.',
    `approved_effective_date` DATE COMMENT 'Date on which the DOI-approved rates become effective for use. May differ from the proposed effective date if the DOI modifies the requested effective date as a condition of approval. Null until the filing reaches approved status.',
    `approved_rate_change_percentage` DECIMAL(18,2) COMMENT 'The rate change percentage as finally approved by the state DOI, which may differ from the originally proposed rate_change_percentage if the DOI required modifications as a condition of approval. Null until the filing is approved.',
    `certifying_actuary_credential` STRING COMMENT 'Professional actuarial credential of the certifying actuary (e.g., FSA — Fellow of the Society of Actuaries, MAAA — Member of the American Academy of Actuaries). Validates the actuarys qualification to certify the rate filing.. Valid values are `FSA|MAAA|FSA_MAAA|ASA|FCAS`',
    `certifying_actuary_name` STRING COMMENT 'Full name of the qualified actuary (Fellow of the Society of Actuaries or equivalent) who certified the actuarial memorandum and rate justification supporting this filing. Required by most state DOIs as part of the rate filing package.',
    `consumer_notice_required_flag` BOOLEAN COMMENT 'Indicates whether the rate filing requires individual policyholder notification of the rate change (e.g., LTC rate increases, in-force rate revisions). Triggers the consumer notification workflow in the policy administration system.',
    `consumer_notice_sent_date` DATE COMMENT 'Date on which policyholder notification letters were sent for the rate change. Required for LTC rate increases and other in-force rate revisions requiring consumer notice. Null if consumer_notice_required_flag is false.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the rate filing record was first created in the compliance system. Supports audit trail requirements and data lineage tracking.',
    `disapproval_date` DATE COMMENT 'Date on which the state Department of Insurance (DOI) formally disapproved the rate filing. Null for filings that are approved, pending, or withdrawn. Triggers the companys obligation to respond or refile.',
    `disapproval_reason` STRING COMMENT 'Narrative description of the state DOIs stated reason(s) for disapproving the rate filing. Null for approved or pending filings. Used to guide refiling strategy and actuarial revisions.',
    `doi_approval_date` DATE COMMENT 'Date on which the state Department of Insurance (DOI) formally approved the rate filing. Null for filings that are pending, disapproved, or withdrawn. Distinct from the approved effective date, which is when rates go into use.',
    `doi_objection_count` STRING COMMENT 'Number of formal objections or deficiency letters issued by the state DOI during the review of this rate filing. Each objection requires a company response and may extend the review timeline. Tracks regulatory engagement complexity.',
    `doi_objection_response_date` DATE COMMENT 'Date on which the company submitted its response to the DOIs most recent objection or deficiency letter. Used to track compliance with DOI response deadlines and filing timeline management.',
    `doi_objection_response_due_date` DATE COMMENT 'Due date for the companys response to the most recent DOI objection or deficiency letter. Failure to respond by this date may result in automatic disapproval or withdrawal of the filing.',
    `experience_period_end_date` DATE COMMENT 'End date of the actuarial experience period used to develop the loss ratios, claim costs, and other actuarial assumptions supporting the rate filing. Together with the start date, defines the historical data window underlying the actuarial justification.',
    `experience_period_start_date` DATE COMMENT 'Start date of the actuarial experience period used to develop the loss ratios, claim costs, and other actuarial assumptions supporting the rate filing. Defines the historical data window underlying the actuarial justification.',
    `external_counsel_reference` STRING COMMENT 'Reference identifier or name of external legal counsel engaged to support the rate filing, if applicable. Relevant for contested filings, LTC rate increase hearings, or filings requiring regulatory negotiation.',
    `filing_description` STRING COMMENT 'Narrative description of the rate filing, summarizing the nature of the rate change, the affected policy forms, the actuarial basis, and any special circumstances (e.g., LTC rate stabilization, experience deterioration, regulatory mandate). Used for internal compliance tracking and DOI correspondence.',
    `filing_method` STRING COMMENT 'Regulatory filing method required by the state for this rate filing. Prior approval requires DOI approval before use; file-and-use allows immediate use upon filing; use-and-file requires filing after use; no-filing-required states are exempt. Determines the compliance timeline and approval workflow.. Valid values are `prior_approval|file_and_use|use_and_file|no_filing_required|informational`',
    `filing_number` STRING COMMENT 'Externally-known unique reference number assigned to the rate filing, typically generated by the company or the state DOI system (e.g., SERFF tracking number or company-assigned filing reference). Used for cross-referencing with state DOI portals and internal compliance tracking.',
    `filing_preparer_name` STRING COMMENT 'Name of the internal compliance or actuarial staff member responsible for preparing and submitting the rate filing. Used for accountability tracking and DOI correspondence.',
    `filing_status` STRING COMMENT 'Current lifecycle status of the rate filing with the state DOI. Tracks the filing from initial draft through submission, regulatory review, and final disposition (approved, disapproved, or withdrawn). [ENUM-REF-CANDIDATE: draft|submitted|pending_review|approved|disapproved|withdrawn|conditionally_approved — promote to reference product]',
    `hearing_date` DATE COMMENT 'Scheduled or actual date of the DOI public or administrative hearing for this rate filing. Null if hearing_required_flag is false. Tracks the regulatory hearing calendar for compliance management.',
    `hearing_required_flag` BOOLEAN COMMENT 'Indicates whether the state DOI has required a public hearing or administrative hearing as part of the rate filing review process. Hearings are common for large LTC rate increases and may significantly extend the approval timeline.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code identifying the state Department of Insurance (DOI) to which this rate filing is submitted. Each state has independent rate regulation authority; a single product rate change may require separate filings per state.. Valid values are `^[A-Z]{2}$`',
    `line_of_business` STRING COMMENT 'Regulatory line of business classification for the rate filing as defined by NAIC and state DOI reporting standards. Determines the applicable rate regulation statutes and actuarial certification requirements.. Valid values are `life|annuity|health|ltc|disability`',
    `loss_ratio_current` DECIMAL(18,2) COMMENT 'The current (pre-filing) loss ratio for the affected product line and policy forms, expressed as a decimal (e.g., 0.85 = 85%). A key actuarial metric supporting the rate change justification; high loss ratios indicate inadequate current rates.',
    `loss_ratio_projected` DECIMAL(18,2) COMMENT 'The projected loss ratio following implementation of the proposed rate change, expressed as a decimal. Demonstrates to the DOI that the revised rates will achieve actuarial adequacy and rate stability.',
    `ltc_rate_increase_flag` BOOLEAN COMMENT 'Indicates whether this filing is a Long-Term Care (LTC) rate increase filing, which is subject to heightened regulatory scrutiny, consumer notification requirements, and actuarial certification standards under the NAIC LTC Insurance Model Regulation.',
    `policy_form_numbers` STRING COMMENT 'Comma-separated list of policy form numbers (as approved by the DOI) to which the rate filing applies. Policy forms are the standardized contract templates approved by the state DOI; rate filings are tied to specific approved forms.',
    `prior_filing_number` STRING COMMENT 'Filing number of the immediately preceding approved rate filing for the same product line and jurisdiction. Establishes the rate revision history chain and allows comparison of current vs. prior approved rates.',
    `product_line` STRING COMMENT 'Broad insurance product line classification for the rate filing (e.g., Term Life, Whole Life (WL), Universal Life (UL), Long-Term Care (LTC), Annuity). Determines applicable regulatory framework and actuarial standards. [ENUM-REF-CANDIDATE: term_life|whole_life|universal_life|variable_life|ltc|annuity|disability_income|accidental_death — promote to reference product]',
    `proposed_effective_date` DATE COMMENT 'Date on which the company proposes the new or revised rates to become effective for new business or in-force policies. Subject to DOI approval for prior approval states; may differ from the approved effective date.',
    `rate_change_percentage` DECIMAL(18,2) COMMENT 'The percentage change in premium rates proposed in this filing relative to the currently approved rates. Positive values indicate a rate increase; negative values indicate a rate decrease. Critical metric for actuarial justification and DOI review. For LTC rate increase filings, subject to heightened regulatory scrutiny.',
    `rate_change_type` STRING COMMENT 'Directional classification of the rate change proposed in this filing. Distinguishes between rate increases, decreases, no-change filings (e.g., non-forfeiture value updates), and new rate filings for newly introduced products.. Valid values are `increase|decrease|no_change|new_rate`',
    `rate_stability_certification_flag` BOOLEAN COMMENT 'Indicates whether the filing includes an actuarial certification of rate stability as required by the NAIC LTC Insurance Model Regulation. Rate stability certifications attest that the proposed rates are not expected to require future increases.',
    `serff_tracking_number` STRING COMMENT 'Tracking number assigned by the NAIC System for Electronic Rate and Form Filing (SERFF) upon submission of the rate filing to the state DOI. Serves as the authoritative cross-reference between the companys internal records and the state regulatory portal.',
    `submission_date` DATE COMMENT 'Date on which the rate filing was formally submitted to the state Department of Insurance (DOI). Marks the start of the regulatory review clock for prior approval states and establishes the compliance timeline for file-and-use states.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the rate filing record was most recently updated in the compliance system. Supports audit trail requirements, change tracking, and data lineage for the Silver layer.',
    `withdrawal_date` DATE COMMENT 'Date on which the company voluntarily withdrew the rate filing from DOI review. Null for filings not withdrawn. Withdrawal may occur due to actuarial revisions, regulatory feedback, or business strategy changes.',
    CONSTRAINT pk_rate_filing PRIMARY KEY(`rate_filing_id`)
) COMMENT 'Record of premium rate and non-forfeiture value filings submitted to state DOIs for approval or notification. Captures product line, filing type (new rate, rate revision, LTC rate increase), filing method (prior approval, file-and-use), state, actuarial justification reference, proposed effective date, DOI submission date, approval status, approved effective date, and rate change percentage. Supports compliance with state rate regulation requirements.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`orsa_report` (
    `orsa_report_id` BIGINT COMMENT 'Unique surrogate identifier for the ORSA report record in the lakehouse silver layer. Primary key.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: ORSA reports frequently use external actuarial consultants for stress testing, capital modeling, ERM framework design, and report preparation. Tracks vendor providing ORSA actuarial and consulting ser',
    `embedded_value_id` BIGINT COMMENT 'Foreign key linking to finance.embedded_value. Business justification: ORSA risk assessment informs embedded value calculations (risk discount rates, required capital, cost of capital). Both are forward-looking valuation exercises requiring consistent risk assumptions.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: ORSA reports are filed by lead state for specific legal entities or insurance groups. Regulatory filing requirement - each entity must conduct own risk and solvency assessment.',
    `prior_year_report_orsa_report_id` BIGINT COMMENT 'Reference to the ORSA report record from the immediately preceding report year. Enables year-over-year comparison of risk profiles, capital adequacy conclusions, and stress test results for trend analysis and regulatory continuity review.',
    `rbc_calculation_id` BIGINT COMMENT 'Foreign key linking to finance.rbc_calculation. Business justification: ORSA reports cite RBC ratios and capital adequacy conclusions. Direct business relationship - ORSA is qualitative risk assessment, RBC is quantitative capital measurement. Both filed to same regulator',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: ORSA reports fulfill regulatory obligations for enterprise risk assessment reporting. The obligation defines the submission deadline.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: ORSA produces comprehensive risk assessment reports, board presentations, and regulatory submissions to lead state. Essential for enterprise risk reporting and regulatory compliance. Replaces text ref',
    `report_period_id` BIGINT COMMENT 'Foreign key linking to reporting.report_period. Business justification: ORSA reports are prepared for specific annual assessment periods aligned with report_period definitions. Links ORSA to the period for enterprise risk management reporting calendar. Replaces denormaliz',
    `report_version_id` BIGINT COMMENT 'Foreign key linking to reporting.report_version. Business justification: ORSA reports are versioned documents (draft, board-approved, filed). Links ORSA to the report version for approval workflow, version control, and regulatory submission tracking.',
    `actuarial_valuation_system` STRING COMMENT 'Name of the actuarial valuation system used to generate reserve calculations, cash flow projections, and capital adequacy models supporting the ORSA (e.g., MoSes, AXIS, Prophet). Supports model governance and audit trail requirements.. Valid values are `MoSes|AXIS|Prophet|other`',
    `board_approval_date` DATE COMMENT 'Date on which the companys Board of Directors formally approved the ORSA report. Board approval is a mandatory prerequisite for regulatory submission under the NAIC ORSA Model Act and demonstrates governance oversight of the ERM program.',
    `capital_adequacy_conclusion` STRING COMMENT 'Overall conclusion of the ORSA regarding the companys capital adequacy relative to its risk profile. Reflects the board-approved determination of whether current and projected capital levels are sufficient to support the risk exposures identified across all assessed risk categories.. Valid values are `adequate|adequate_with_conditions|inadequate|under_remediation`',
    `confidentiality_protection_requested` BOOLEAN COMMENT 'Indicates whether the company has requested confidential treatment of the ORSA report under NAIC ORSA Model Act Section 5, which provides that the ORSA report is a privileged and confidential document not subject to public disclosure or subpoena.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the ORSA report record was first created in the system. Supports audit trail and data lineage requirements under SOX controls and NAIC corporate governance standards.',
    `credit_risk_assessed` BOOLEAN COMMENT 'Indicates whether credit risk (counterparty default, reinsurer credit risk, bond issuer default) was formally assessed and documented in this ORSA report.',
    `erm_program_owner` STRING COMMENT 'Name or title of the senior executive responsible for the ERM program and the ORSA process (e.g., Chief Risk Officer). Establishes accountability for the risk assessment and capital adequacy conclusions documented in the report.',
    `insurance_risk_assessed` BOOLEAN COMMENT 'Indicates whether insurance risk (mortality, morbidity, longevity, lapse, catastrophe) was formally assessed and documented in this ORSA report. Insurance risk is a primary risk category under the NAIC ORSA Guidance Manual Section 2.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the ORSA report record was most recently modified. Tracks revisions through the drafting, review, and approval lifecycle for audit and compliance purposes.',
    `ldti_impact_disclosed` BOOLEAN COMMENT 'Indicates whether the ORSA report includes disclosure of the financial impact of FASB ASC 944 Long Duration Targeted Improvements (LDTI) on the companys capital position and reserve adequacy. Relevant for companies reporting under GAAP.',
    `lead_state_code` STRING COMMENT 'Two-letter US state code identifying the lead state Department of Insurance (DOI) to which the ORSA report is filed. The lead state is the domiciliary state of the insurance holding company group per NAIC ORSA Model Act.. Valid values are `^[A-Z]{2}$`',
    `liquidity_risk_assessed` BOOLEAN COMMENT 'Indicates whether liquidity risk (cash flow mismatches, surrender spikes, asset liquidation constraints) was formally assessed and documented in this ORSA report. Particularly relevant for life insurers with annuity and UL/IUL product lines.',
    `market_risk_assessed` BOOLEAN COMMENT 'Indicates whether market risk (interest rate, equity, credit spread, currency, real estate) was formally assessed and documented in this ORSA report. Critical for life insurers with significant investment portfolios and ALM exposures.',
    `material_risk_changes` STRING COMMENT 'Narrative description of material changes to the companys risk profile since the prior ORSA report, including new risk exposures, changes in risk concentrations, or significant shifts in the business mix (e.g., new FIA product launch, reinsurance treaty restructuring, ALM repositioning).',
    `naic_group_code` STRING COMMENT 'Five-digit NAIC-assigned group code identifying the insurance holding company group for which the ORSA is filed. Used for regulatory cross-referencing with NAIC financial filings and the NAIC Financial Data Repository.. Valid values are `^[0-9]{5}$`',
    `operational_risk_assessed` BOOLEAN COMMENT 'Indicates whether operational risk (process failures, system outages, fraud, third-party vendor risk, cyber risk) was formally assessed and documented in this ORSA report.',
    `pbr_compliance_confirmed` BOOLEAN COMMENT 'Indicates whether the ORSA report confirms compliance with NAIC Principle-Based Reserving (PBR) requirements under VM-20 (life) and VM-21 (annuities). PBR compliance is a key component of the ORSA capital adequacy assessment for life and annuity writers.',
    `projection_horizon_years` STRING COMMENT 'Number of years covered by the forward-looking capital adequacy projection in ORSA Section 3. NAIC guidance recommends a minimum 3-year projection horizon; life insurers with long-duration liabilities typically use 5 years.',
    `rbc_ratio_current` DECIMAL(18,2) COMMENT 'Current Risk-Based Capital (RBC) ratio as of the assessment period end date, expressed as a percentage of Total Adjusted Capital (TAC) to Authorized Control Level (ACL) RBC. A key capital adequacy metric required in ORSA Section 3 capital projections. Classified confidential as a sensitive financial indicator.',
    `rbc_ratio_projected` DECIMAL(18,2) COMMENT 'Projected RBC ratio over the forward-looking planning horizon (typically 3–5 years) under the base scenario. Supports ORSA Section 3 prospective solvency assessment requirements demonstrating capital adequacy under normal business conditions.',
    `regulatory_acceptance_date` DATE COMMENT 'Date on which the lead state DOI formally acknowledged acceptance of the ORSA report submission. Null if the report has not yet been accepted or was rejected.',
    `regulatory_feedback_notes` STRING COMMENT 'Narrative notes capturing the substance of regulatory feedback or follow-up inquiries received from the lead state DOI following ORSA report submission. Null if no feedback has been received.',
    `regulatory_feedback_received` BOOLEAN COMMENT 'Indicates whether the lead state DOI has provided formal feedback or follow-up inquiries regarding the submitted ORSA report. Triggers the regulatory response workflow when set to True.',
    `reinsurance_risk_mitigation_disclosed` BOOLEAN COMMENT 'Indicates whether the ORSA report includes disclosure of reinsurance arrangements used as risk mitigation tools, including YRT, coinsurance, and modified coinsurance treaties, and their impact on net retained risk and capital requirements.',
    `report_number` STRING COMMENT 'Externally-known business identifier for the ORSA report, typically formatted as ORSA-{YEAR}-{STATE}-{SEQUENCE}. Used for regulatory correspondence and filing tracking with the lead state Department of Insurance.. Valid values are `^ORSA-[0-9]{4}-[A-Z]{2}-[0-9]{4,8}$`',
    `report_status` STRING COMMENT 'Current lifecycle status of the ORSA report, tracking progression from internal drafting through board approval to regulatory submission and acceptance by the lead state DOI. [ENUM-REF-CANDIDATE: draft|under_review|board_approved|submitted|accepted|rejected|superseded — 7 candidates stripped; promote to reference product]',
    `report_version` STRING COMMENT 'Version number of the ORSA report document (e.g., 1.0, 2.1). Incremented when material revisions are made following board review, regulatory feedback, or resubmission after rejection.. Valid values are `^[0-9]+.[0-9]+$`',
    `report_year` STRING COMMENT 'Calendar year for which the ORSA assessment is conducted and reported. NAIC ORSA Model Act requires annual filing; this field identifies the reporting period year (e.g., 2024).',
    `reputational_risk_assessed` BOOLEAN COMMENT 'Indicates whether reputational risk (brand damage, regulatory sanctions, social media exposure, market conduct violations) was formally assessed and documented in this ORSA report.',
    `risk_appetite_statement_version` STRING COMMENT 'Version identifier of the Board-approved Risk Appetite Statement (RAS) referenced in this ORSA report. Links the ORSA risk assessment to the governing risk appetite framework, demonstrating alignment between risk tolerances and capital adequacy conclusions.',
    `risk_tolerance_breaches` STRING COMMENT 'Number of risk tolerance limit breaches identified during the ORSA assessment period. A non-zero value triggers mandatory disclosure in the ORSA report and requires documentation of management actions taken to remediate the breach.',
    `strategic_risk_assessed` BOOLEAN COMMENT 'Indicates whether strategic risk (competitive positioning, M&A execution, distribution channel risk, product development risk) was formally assessed and documented in this ORSA report.',
    `stress_test_count` STRING COMMENT 'Total number of stress test scenarios applied in the ORSA assessment. Includes both deterministic stress scenarios and stochastic scenario sets used to evaluate capital adequacy under adverse conditions per NAIC ORSA Guidance Manual Section 2.',
    `stress_test_scenarios_summary` STRING COMMENT 'Narrative summary of the key stress test scenarios applied in the ORSA, including scenario names and brief descriptions (e.g., Interest rate shock +300bps, Pandemic mortality shock 150% of base, Equity market decline -40%, Mass lapse event). Supports ERM documentation and regulatory review.',
    `submission_date` DATE COMMENT 'Date on which the ORSA report was formally submitted to the lead state Department of Insurance. Must occur within the regulatory deadline (typically within 60 days of fiscal year-end or upon request by the lead state commissioner).',
    `worst_case_rbc_ratio` DECIMAL(18,2) COMMENT 'Lowest RBC ratio observed across all stress test scenarios applied in the ORSA. Represents the most adverse capital position under the defined stress scenarios and is a key indicator of capital resilience for regulatory review.',
    CONSTRAINT pk_orsa_report PRIMARY KEY(`orsa_report_id`)
) COMMENT 'Own Risk and Solvency Assessment (ORSA) report record capturing the enterprises internal assessment of risk and capital adequacy per NAIC ORSA Model Act. Tracks report year, filing jurisdiction (lead state), risk categories assessed (insurance risk, market risk, credit risk, operational risk, liquidity risk), capital adequacy conclusion, stress test scenarios applied, board approval date, and submission date to lead state DOI. Supports ERM program documentation.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`erisa_plan_filing` (
    `erisa_plan_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each ERISA plan filing record in the compliance domain. Primary key for this data product.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: ERISA filings generate Form 5500 documents, plan documents, Schedule A, and DOL correspondence. Critical for ERISA compliance and DOL filing workflow. Replaces text reference with structured FK.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: ERISA filings are made by the legal entity that is the insurance carrier for the plan. DOL filing requirement is entity-specific - carrier entity must file Form 5500 Schedule A.',
    `party_id` BIGINT COMMENT 'Reference to the employer or organization that sponsors the ERISA-governed plan, responsible for plan administration and fiduciary obligations.',
    `regulatory_filing_id` BIGINT COMMENT 'Reference to the parent regulatory filing record in the compliance.regulatory_filing product that captures the broader DOL submission context for this ERISA plan filing.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: ERISA plan filings (Form 5500, etc.) fulfill specific DOL regulatory obligations. The obligation defines the due date and filing requirements.',
    `report_period_id` BIGINT COMMENT 'Foreign key linking to reporting.report_period. Business justification: ERISA plan filings (Form 5500) are prepared for specific plan years that map to report_period. Links filing to the period for employee benefit plan reporting calendar. Replaces denormalized dates.',
    `tax_provision_id` BIGINT COMMENT 'Foreign key linking to finance.tax_provision. Business justification: ERISA plan tax treatment (qualified vs non-qualified) affects tax provision. ERISA compliance impacts tax deductibility of contributions and tax treatment of plan assets.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: ERISA filings often involve third-party administrators (TPAs) for plan administration, Form 5500 preparation, and DOL filing. Tracks TPA vendor responsible for ERISA plan compliance and filing service',
    `active_participant_count` STRING COMMENT 'Number of currently employed participants actively accruing benefits or eligible to participate in the plan as of the plan year end date, as reported on Form 5500.',
    `approval_date` DATE COMMENT 'Date on which the authorized plan administrator or fiduciary approved the Form 5500 filing for submission to the DOL.',
    `approver_name` STRING COMMENT 'Name of the authorized plan administrator or fiduciary who reviewed and approved the Form 5500 filing prior to DOL submission, as required by ERISA Section 104.',
    `audit_firm_name` STRING COMMENT 'Name of the independent qualified public accounting firm engaged to perform the ERISA-required plan audit. Reported on Form 5500 Schedule H when audit is required.',
    `compliance_status` STRING COMMENT 'Overall compliance determination for this ERISA plan filing, reflecting whether all DOL, IRS, and fiduciary requirements have been satisfied or whether remediation actions are pending.. Valid values are `compliant|non_compliant|under_review|remediation_required|closed`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this ERISA plan filing record was first created in the compliance data product, supporting audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts reported in this filing record (e.g., USD). Supports multi-currency plan reporting for multinational plan sponsors.. Valid values are `^[A-Z]{3}$`',
    `days_late` STRING COMMENT 'Number of calendar days the filing was submitted past the applicable due date. Used to calculate DOL penalty exposure under the Delinquent Filer Voluntary Compliance (DFVC) program.',
    `dfvc_program_flag` BOOLEAN COMMENT 'Indicates whether this filing was submitted under the DOLs Delinquent Filer Voluntary Compliance (DFVC) program to reduce penalties for late Form 5500 filings.',
    `dol_acceptance_date` DATE COMMENT 'Date on which the Department of Labor formally accepted the Form 5500 filing as complete and compliant via the EFAST2 system.',
    `dol_filing_date` DATE COMMENT 'Date on which the Form 5500 or related ERISA filing was submitted to the Department of Labor via the EFAST2 electronic filing system.',
    `dol_rejection_date` DATE COMMENT 'Date on which the Department of Labor rejected the Form 5500 filing, requiring resubmission. Populated only when filing_status is rejected.',
    `erisa_bond_amount` DECIMAL(18,2) COMMENT 'Dollar amount of the fidelity bond required under ERISA Section 412 to protect the plan against losses due to fraud or dishonesty by plan officials who handle plan funds.',
    `extension_due_date` DATE COMMENT 'Extended deadline for Form 5500 submission when a Form 5558 extension has been granted. Applicable only when extension_filed_flag is True.',
    `extension_filed_flag` BOOLEAN COMMENT 'Indicates whether a Form 5558 extension of time to file was submitted to the IRS for this plan year, granting an additional 2.5 months beyond the original due date.',
    `fiduciary_designation` STRING COMMENT 'Classification of the fiduciary role assigned under ERISA for this plan. Identifies whether the company acts as named fiduciary, investment manager, plan administrator, trustee, or co-fiduciary, determining the scope of fiduciary liability.. Valid values are `named_fiduciary|investment_manager|plan_administrator|trustee|co_fiduciary`',
    `fiduciary_name` STRING COMMENT 'Name of the individual or entity designated as the named fiduciary for the plan under ERISA Section 402, responsible for plan management and investment decisions.',
    `filing_reference_number` STRING COMMENT 'Externally-known business identifier assigned to this ERISA plan filing, used for cross-referencing with DOL submissions, internal compliance tracking, and audit trails.',
    `filing_status` STRING COMMENT 'Current lifecycle status of the ERISA plan filing submission. Tracks the filing from initial preparation through DOL acceptance or rejection and any subsequent amendments.. Valid values are `draft|submitted|accepted|rejected|amended|closed`',
    `form_5500_type` STRING COMMENT 'Specific variant of the DOL Form 5500 filed for this plan. Form 5500 is for large plans (100+ participants), 5500-SF for small plans, and 5500-EZ for one-participant plans.. Valid values are `5500|5500-SF|5500-EZ`',
    `independent_audit_required_flag` BOOLEAN COMMENT 'Indicates whether an independent qualified public accountant (IQPA) audit is required for this plan filing. Required for large plans (generally 100+ participants) under ERISA Section 103(a)(3)(A).',
    `insurance_contract_type` STRING COMMENT 'Type of insurance or annuity contract held by the plan and reported on Form 5500 Schedule A (Insurance Information). Identifies the nature of the companys product involvement in the plan.. Valid values are `group_life|group_annuity|group_disability|group_health|combination`',
    `late_filing_flag` BOOLEAN COMMENT 'Indicates whether the Form 5500 was submitted after the applicable due date (original or extended), triggering potential DOL penalty assessment under ERISA Section 502(c)(2).',
    `participant_count` STRING COMMENT 'Total number of plan participants (active, retired, and separated with vested benefits) as of the beginning of the plan year, used to determine Form 5500 variant (large vs. small plan) and applicable audit requirements.',
    `penalty_amount` DECIMAL(18,2) COMMENT 'Monetary penalty assessed by the DOL for late or deficient Form 5500 filing under ERISA Section 502(c)(2). May be reduced through the DFVC program.',
    `plan_administrator_name` STRING COMMENT 'Name of the individual or entity designated as plan administrator under ERISA Section 3(16)(A), responsible for Form 5500 filing obligations and participant disclosures.',
    `plan_assets_amount` DECIMAL(18,2) COMMENT 'Total fair market value of plan assets as of the end of the plan year, as reported on Form 5500 Schedule H or I. Used for large-plan audit threshold determination and DOL financial reporting.',
    `plan_name` STRING COMMENT 'Official name of the ERISA-governed employer-sponsored plan as registered with the DOL and referenced in Form 5500 filings (e.g., ABC Corp Group Life Insurance Plan).',
    `plan_number` STRING COMMENT 'Three-digit plan number assigned by the plan sponsor to uniquely identify the plan within the sponsors portfolio, as required on DOL Form 5500 filings.. Valid values are `^[0-9]{3}$`',
    `plan_sponsor_ein` STRING COMMENT 'IRS-assigned Employer Identification Number (EIN) for the plan sponsor, required on Form 5500 filings and used for tax compliance and DOL identification purposes.. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `plan_sponsor_name` STRING COMMENT 'Legal name of the employer or organization sponsoring the ERISA-governed plan. Used for DOL filings, Form 5500 reporting, and fiduciary compliance documentation.',
    `plan_type` STRING COMMENT 'Classification of the ERISA-governed plan by benefit structure and product type. Determines applicable regulatory requirements, Form 5500 schedules, and fiduciary obligations. [ENUM-REF-CANDIDATE: group_life|group_annuity|401k_annuity|pension|defined_benefit|defined_contribution — promote to reference product]. Valid values are `group_life|group_annuity|401k_annuity|pension|defined_benefit|defined_contribution`',
    `preparer_name` STRING COMMENT 'Name of the individual or firm responsible for preparing the Form 5500 filing on behalf of the plan sponsor or plan administrator.',
    `pte_reference` STRING COMMENT 'Reference number(s) for any DOL Prohibited Transaction Exemption (PTE) applicable to this plan filing, permitting otherwise prohibited transactions under ERISA Section 406. Common PTEs include PTE 84-24 and PTE 2020-02.',
    `pte_type` STRING COMMENT 'Identifies the specific type or category of Prohibited Transaction Exemption (PTE) claimed for this plan, such as PTE 84-24 (insurance and annuity transactions) or PTE 2020-02 (investment advice fiduciary).',
    `rejection_reason` STRING COMMENT 'Description of the reason(s) provided by the DOL EFAST2 system for rejecting the Form 5500 filing, used to guide resubmission and remediation.',
    `schedule_a_required_flag` BOOLEAN COMMENT 'Indicates whether Form 5500 Schedule A (Insurance Information) must be attached to this filing because the plan holds insurance contracts or annuity contracts issued by an insurance company.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this ERISA plan filing record, used for change tracking, data lineage, and SOX audit trail compliance.',
    CONSTRAINT pk_erisa_plan_filing PRIMARY KEY(`erisa_plan_filing_id`)
) COMMENT 'Record of ERISA-governed employer-sponsored plan filings and compliance activities managed by the company for group life and annuity products. Captures plan sponsor, plan type (group life, 401k annuity, pension), Form 5500 filing reference, plan year, DOL filing date, fiduciary designation, prohibited transaction exemption (PTE) references, and compliance status. Supports DOL fiduciary rule compliance and ERISA reporting obligations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`jurisdiction_license` (
    `jurisdiction_license_id` BIGINT COMMENT 'Unique surrogate identifier for each jurisdiction license record in the Silver layer. Primary key for the jurisdiction_license data product.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Licenses are issued to legal entities. Fundamental regulatory relationship - each legal entity must be licensed in jurisdictions where it operates. Required for regulatory compliance tracking.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Jurisdiction licenses are maintained to satisfy regulatory obligations for authority to transact insurance business. The license describes the authority granted, while the obligation describes the req',
    `admitted_status` STRING COMMENT 'Indicates whether the company is admitted (licensed and subject to state guaranty fund protection), non-admitted, or writing on a surplus lines basis in the jurisdiction. Affects policyholder protections and regulatory requirements.. Valid values are `admitted|non_admitted|surplus_lines`',
    `annual_statement_filing_due_date` DATE COMMENT 'The date by which the company must file its NAIC Annual Statement (statutory financial statement) with the DOI for this jurisdiction. Typically March 1 for most states but may vary. Drives the regulatory filing calendar.',
    `authorized_lines_of_business` STRING COMMENT 'Comma-separated list or description of the specific lines of business authorized under this license (e.g., Life, Annuity, Variable Life, Variable Annuity, Accident and Health). Governs which product types may be sold in the jurisdiction.',
    `compliance_officer_name` STRING COMMENT 'Name of the companys designated compliance officer or regulatory contact responsible for managing the license and DOI relationship in this jurisdiction. Used for regulatory correspondence and examination coordination.',
    `domicile_state_code` STRING COMMENT 'Two-letter USPS code for the state in which the company is domiciled (chartered). Distinguishes the home state license from foreign state licenses and determines which states insurance laws govern the companys primary regulatory oversight.. Valid values are `^[A-Z]{2}$`',
    `effective_date` DATE COMMENT 'The date on which the Certificate of Authority or license became effective and the company was first authorized to transact the specified line of business in the jurisdiction. Marks the start of the binding authorization period.',
    `expiration_date` DATE COMMENT 'The date on which the current license term expires and renewal is required to maintain authorization. Null for perpetual licenses that do not require periodic renewal. Drives the renewal calendar and compliance alerts.',
    `fein` STRING COMMENT 'The Federal Employer Identification Number (FEIN) of the company as registered with the IRS. Required on certain state DOI filings and tax-related regulatory submissions. Also known as Taxpayer Identification Number (TIN).. Valid values are `^[0-9]{2}-[0-9]{7}$`',
    `guaranty_fund_member_flag` BOOLEAN COMMENT 'Indicates whether the company is a member of the state life and health guaranty association for this jurisdiction. Admitted carriers are typically required to be members. Relevant for policyholder protection disclosures and NAIC reporting.',
    `is_domestic` BOOLEAN COMMENT 'Indicates whether this license is a domestic (home state) license (True) or a foreign state license (False). Domestic licenses are issued by the state of domicile; foreign licenses are issued by other states where the company is admitted to transact business.',
    `issuing_authority` STRING COMMENT 'Name of the regulatory body that issued the license (e.g., California Department of Insurance, New York State Department of Financial Services). Identifies the specific DOI or equivalent authority responsible for the license.',
    `issuing_authority_contact` STRING COMMENT 'Contact information (address, phone, or email) for the issuing DOI or regulatory authority. Used for correspondence, renewal submissions, and regulatory inquiries.',
    `jurisdiction_name` STRING COMMENT 'Full legal name of the state or territory jurisdiction (e.g., California, New York, Puerto Rico, District of Columbia). Complements the state code for display and reporting purposes.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter USPS state or territory code identifying the jurisdiction in which the license is held (e.g., CA, NY, TX, PR, DC). Used to validate that the company is authorized to write business in the state before policy issuance.. Valid values are `^[A-Z]{2}$`',
    `last_examination_date` DATE COMMENT 'The date of the most recent market conduct or financial examination conducted by the DOI in this jurisdiction. Used to track examination cycles and anticipate upcoming examinations per NAIC examination standards.',
    `license_condition_flag` BOOLEAN COMMENT 'Indicates whether the DOI has imposed any conditions, restrictions, or limitations on this license. When True, the license_conditions field contains the details. Conditions may restrict product types, distribution channels, or require enhanced reporting.',
    `license_conditions` STRING COMMENT 'Free-text description of any conditions, restrictions, or limitations imposed by the DOI on this license. Examples include restrictions on writing new business, requirements for enhanced consumer disclosures, or limitations on specific product features. Populated only when license_condition_flag is True.',
    `license_number` STRING COMMENT 'The official license or Certificate of Authority (COA) number assigned by the state Department of Insurance (DOI) to the company for the given jurisdiction. This is the externally-known business identifier used in regulatory filings and correspondence with the DOI.',
    `license_status` STRING COMMENT 'Current lifecycle status of the jurisdiction license as maintained by the state DOI. Active indicates the company is authorized to transact business. Suspended or revoked statuses trigger immediate cessation of new business writing in the jurisdiction.. Valid values are `active|suspended|revoked|expired|pending|surrendered`',
    `license_type` STRING COMMENT 'Classification of the insurance license by product line authorized. Determines which lines of business the company is permitted to transact in the jurisdiction. Variable product types are subject to additional SEC/FINRA oversight. [ENUM-REF-CANDIDATE: life|annuity|variable_life|variable_annuity|accident_health|disability_income — promote to reference product if additional lines are added]. Valid values are `life|annuity|variable_life|variable_annuity|accident_health`',
    `minimum_capital_requirement` DECIMAL(18,2) COMMENT 'The minimum capital and surplus amount required by the jurisdictions DOI for the company to maintain its license, denominated in USD. Linked to Risk-Based Capital (RBC) requirements and solvency monitoring.',
    `naic_company_code` STRING COMMENT 'The five-digit NAIC company code assigned to the insurer. Used in all NAIC regulatory filings, state financial examinations, and market conduct reporting to uniquely identify the company across all jurisdictions.. Valid values are `^[0-9]{5}$`',
    `next_examination_due_date` DATE COMMENT 'The anticipated or scheduled date for the next DOI examination in this jurisdiction. Typically every 3-5 years per NAIC standards. Used for compliance planning and resource allocation.',
    `notes` STRING COMMENT 'Free-text field for additional compliance notes, DOI correspondence summaries, or internal observations related to the license. Used by the compliance team to document material events not captured in structured fields.',
    `original_issue_date` DATE COMMENT 'The date on which the company was first granted a license in this jurisdiction for this license type, regardless of subsequent renewals. Establishes the historical tenure of authorization in the jurisdiction.',
    `rbc_action_level` STRING COMMENT 'The current Risk-Based Capital (RBC) action level applicable to the company in this jurisdiction. Determines the degree of regulatory intervention required. Company Action Level triggers internal remediation; higher levels trigger DOI intervention.. Valid values are `no_action|company_action|regulatory_action|authorized_control|mandatory_control`',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp when this jurisdiction license record was first created in the compliance data product. Provides audit trail for record provenance in the Silver layer.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this jurisdiction license record was most recently updated in the compliance data product. Supports change tracking, audit trails, and incremental data pipeline processing.',
    `registered_agent_address` STRING COMMENT 'Physical address of the registered agent for service of process in the jurisdiction. Required for legal and regulatory correspondence. Maintained as confidential business contact information.',
    `registered_agent_name` STRING COMMENT 'Name of the companys registered agent for service of process in the jurisdiction. Required by most states as a condition of licensure. The registered agent receives legal notices and regulatory correspondence on behalf of the company.',
    `reinstatement_date` DATE COMMENT 'The date on which a previously suspended or lapsed license was reinstated by the DOI. Null if the license has never been reinstated. Marks the resumption of authorization to transact business.',
    `renewal_application_date` DATE COMMENT 'The date on which the company submitted the renewal application to the state DOI. Used to confirm timely filing and to calculate days-before-expiration for compliance reporting.',
    `renewal_date` DATE COMMENT 'The date by which the renewal application and associated fees must be submitted to the DOI to avoid lapse of authorization. May differ from expiration_date where the DOI requires advance filing.',
    `renewal_fee_amount` DECIMAL(18,2) COMMENT 'The monetary amount paid or payable to the state DOI for license renewal, denominated in USD. Tracked for budgeting, accounts payable, and regulatory expense reporting.',
    `renewal_status` STRING COMMENT 'Current status of the renewal process for the license. Tracks whether the renewal application has been submitted, is under DOI review, approved, or has lapsed. Critical for compliance monitoring to ensure continuous authorization.. Valid values are `not_due|submitted|approved|pending_review|rejected|lapsed`',
    `restriction_type` STRING COMMENT 'Categorical classification of the type of restriction or condition imposed on the license by the DOI. Enables structured reporting and monitoring of restricted licenses across jurisdictions.. Valid values are `none|product_restriction|distribution_restriction|geographic_restriction|reporting_requirement|consent_order`',
    `revocation_date` DATE COMMENT 'The date on which the DOI permanently revoked the license, if applicable. Null for active or suspended licenses. A revoked license requires a new application process to re-enter the jurisdiction.',
    `statutory_deposit_amount` DECIMAL(18,2) COMMENT 'The amount of securities or cash deposited with the state treasury or DOI as a condition of licensure in the jurisdiction, denominated in USD. Required by certain states as a financial security requirement for admitted carriers.',
    `statutory_deposit_type` STRING COMMENT 'Type of asset held on deposit with the state as a condition of licensure. Determines the nature of the financial security arrangement and applicable valuation methods under SAP.. Valid values are `cash|securities|letter_of_credit|none`',
    `suspension_date` DATE COMMENT 'The date on which the DOI suspended the license, if applicable. Null for licenses that have never been suspended. Triggers immediate cessation of new business writing and notification to the Policy Administration System.',
    `suspension_reason` STRING COMMENT 'Description of the reason provided by the DOI for suspending the license. Populated only when suspension_date is not null. Used for regulatory response planning and remediation tracking.',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether this license authorizes the sale of variable insurance products (variable life or variable annuity) that are subject to SEC and FINRA oversight in addition to state DOI regulation. True triggers additional compliance checks.',
    CONSTRAINT pk_jurisdiction_license PRIMARY KEY(`jurisdiction_license_id`)
) COMMENT 'Master record of the companys Certificate of Authority (COA) and licenses to transact insurance business in each state and territory. Captures jurisdiction, license type (life, annuity, variable life, variable annuity), license number, effective date, renewal date, renewal status, authorized lines of business, and any license conditions or restrictions imposed by the DOI. Ensures the company only writes business in jurisdictions where it is properly licensed.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`compliance_policy` (
    `compliance_policy_id` BIGINT COMMENT 'Reference to the compliance_policy_id of the newer policy that replaces this one when status is superseded. Enables forward-chaining of policy version history for audit and regulatory examination purposes.',
    `comm_template_id` BIGINT COMMENT 'Foreign key linking to correspondence.comm_template. Business justification: Compliance policies define required communication templates for privacy notices, disclosures, and regulatory notifications. Real business process: policy-driven communication standards ensuring consis',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Policy ownership by department implies cost center responsibility for compliance program costs (policy maintenance, training, monitoring). Finance needs cost attribution for compliance program budgeti',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Compliance policies are themselves documents requiring version control, approval documentation, and distribution tracking. Essential for policy lifecycle management and regulatory examination support.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Compliance policies are often entity-specific (different entities may have different policy versions based on domicile jurisdiction, lines of business, regulatory requirements). Required for policy go',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Compliance policies require employee ownership for review cycles, approval workflows, attestation management, and regulatory examination responses. Policy owner accountability is essential for governa',
    `secondary_prior_policy_compliance_policy_id` BIGINT COMMENT 'Reference to the compliance_policy_id of the immediately preceding version of this policy. Enables backward-chaining of policy version history for complete audit trail and regulatory examination evidence.',
    `aml_program_element` STRING COMMENT 'For AML/BSA category policies, identifies which of the five required BSA/AML program pillars this policy addresses: Internal Controls, Customer Due Diligence (CDD/KYC), Suspicious Activity Report (SAR) Reporting, Training, or Independent Testing. Null for non-AML policies.. Valid values are `Internal_Controls|Customer_Due_Diligence|SAR_Reporting|Training|Independent_Testing`',
    `approval_authority` STRING COMMENT 'The individual, role, or governance body authorized to approve this compliance policy (e.g., Board of Directors, Chief Compliance Officer, Audit Committee, Chief Risk Officer). Required for SOX and ORSA governance documentation.',
    `approval_date` DATE COMMENT 'The date on which the current version of this compliance policy was formally approved by the designated approval authority. Required for SOX control documentation and regulatory examination evidence.',
    `associated_procedure_reference` STRING COMMENT 'Document management reference or identifier for the operational procedures and standards that implement this compliance policy. Links the high-level policy to its supporting procedural documentation.',
    `attestation_frequency_months` STRING COMMENT 'The required frequency of compliance attestation associated with this policy, expressed in months (e.g., 12 for annual attestation). Null if attestation_required is False.',
    `attestation_required` BOOLEAN COMMENT 'Indicates whether periodic compliance attestation by designated employees, officers, or agents is required under this policy. Supports SOX Section 302 CEO/CFO certifications and annual compliance attestation workflows.',
    `board_approval_required` BOOLEAN COMMENT 'Indicates whether this compliance policy requires formal approval by the Board of Directors or its Audit/Risk Committee. True for policies mandated by ORSA, SOX, or state DOI requirements to have board-level governance.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this compliance policy record was first created in the enterprise compliance policy inventory system. Supports audit trail requirements and record lineage tracking.',
    `effective_date` DATE COMMENT 'The date on which this compliance policy becomes or became binding and enforceable across the enterprise. Marks the start of the policys active lifecycle.',
    `erisa_applicable` BOOLEAN COMMENT 'Indicates whether this compliance policy applies to employer-sponsored retirement plans and group products subject to DOL ERISA fiduciary standards. True for policies governing qualified plan products, fiduciary obligations, and prohibited transaction exemptions.',
    `expiration_date` DATE COMMENT 'The date on which this compliance policy ceases to be effective, if applicable. Null for open-ended policies. Used to manage policy sunset and replacement workflows.',
    `external_audit_subject` BOOLEAN COMMENT 'Indicates whether this compliance policy and its associated controls are subject to external audit review (e.g., SOX external auditor testing, state DOI market conduct examination, or independent AML program audit).',
    `hipaa_safeguard_type` STRING COMMENT 'For HIPAA category policies, classifies the type of HIPAA safeguard the policy implements: Administrative (workforce training, access management), Physical (facility access controls), or Technical (encryption, audit controls). Null for non-HIPAA policies.. Valid values are `Administrative|Physical|Technical`',
    `irc_7702_applicable` BOOLEAN COMMENT 'Indicates whether this compliance policy governs IRC Section 7702 life insurance tax qualification requirements, including the Guideline Premium Test (GPT) and Cash Value Accumulation Test (CVAT) for life insurance products.',
    `jurisdiction_scope` STRING COMMENT 'The geographic or regulatory jurisdictions to which this compliance policy applies. May be Federal, a specific state code (e.g., NY, CA), All States, or a comma-separated list of state codes. Supports multi-state compliance management.',
    `last_review_date` DATE COMMENT 'The date on which the most recent formal review of this compliance policy was completed and documented. Used to track review currency and regulatory compliance with review cycle requirements.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this compliance policy record was most recently modified in the enterprise compliance policy inventory system. Supports change tracking and audit trail requirements.',
    `lines_of_business_scope` STRING COMMENT 'The insurance lines of business or product types to which this compliance policy applies (e.g., Life Insurance, Annuity, Variable Products, All Lines). Enables targeted policy applicability filtering for underwriting, claims, and product teams.',
    `next_review_date` DATE COMMENT 'The scheduled date by which the next formal review of this compliance policy must be completed. Derived from last_review_date plus review_cycle_months but stored explicitly to support calendar-driven compliance workflows and escalation alerts.',
    `orsa_risk_category` STRING COMMENT 'The ORSA/ERM risk category to which this compliance policy is mapped, indicating which enterprise risk domain the policy governs. Supports ORSA reporting to state regulators and the enterprise ERM framework.. Valid values are `Insurance_Risk|Market_Risk|Credit_Risk|Operational_Risk|Liquidity_Risk|Strategic_Risk`',
    `owner_department` STRING COMMENT 'The organizational department or business unit responsible for owning and maintaining this compliance policy (e.g., Legal & Compliance, AML Compliance, Privacy Office, Internal Audit).',
    `policy_category` STRING COMMENT 'Primary regulatory or functional category governing the compliance policy. Classifies the policy by its principal regulatory driver. [ENUM-REF-CANDIDATE: AML_BSA|HIPAA|Suitability|SOX|ORSA_ERM|Market_Conduct|Tax_Compliance|Fiduciary_ERISA|Privacy|Fraud_Prevention — promote to reference product]',
    `policy_description` STRING COMMENT 'Narrative description of the compliance policys purpose, scope, and key requirements. Provides business context for the policy and supports search and discovery in the enterprise compliance policy inventory.',
    `policy_name` STRING COMMENT 'Official title of the compliance policy document as it appears in the enterprise policy register (e.g., Anti-Money Laundering Program Policy, HIPAA Privacy Policy, Suitability Review Policy).',
    `policy_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to the compliance policy document, used for cross-referencing in regulatory filings, audit reports, and examination responses. Distinct from insurance policy numbers.',
    `policy_status` STRING COMMENT 'Current lifecycle state of the compliance policy document. draft indicates the policy is being authored; active indicates it is in force; under_review indicates a scheduled or triggered review is in progress; retired indicates the policy has been decommissioned; superseded indicates it has been replaced by a newer version.. Valid values are `draft|active|under_review|retired|superseded`',
    `policy_type` STRING COMMENT 'Classifies the document type within the compliance policy hierarchy: policy (high-level directive), standard (specific requirements), procedure (step-by-step instructions), guideline (recommended practices), or framework (overarching governance structure).. Valid values are `policy|standard|procedure|guideline|framework`',
    `regulatory_authority` STRING COMMENT 'The primary governing body or regulatory authority whose requirements this policy addresses (e.g., NAIC, State DOI, SEC, FINRA, IRS, DOL, FinCEN). Drives routing of policy updates when regulatory guidance changes. [ENUM-REF-CANDIDATE: NAIC|State_DOI|SEC|FINRA|IRS|DOL|FASB|FinCEN|IAIS|ACORD — 10 candidates stripped; promote to reference product]',
    `regulatory_driver` STRING COMMENT 'The specific regulation, statute, or regulatory body requirement that mandates or drives this compliance policy (e.g., Bank Secrecy Act 31 U.S.C. 5318, HIPAA 45 CFR Part 164, IRC Section 7702, NAIC Model Regulation 275, DOL ERISA Section 404). Provides the authoritative legal basis for the policy.',
    `review_cycle_months` STRING COMMENT 'The mandated frequency of periodic policy review expressed in months (e.g., 12 for annual, 24 for biennial). Drives the compliance policy review calendar and next review date calculation.',
    `review_trigger` STRING COMMENT 'The event or condition that triggered the most recent policy review. scheduled for routine periodic reviews; regulatory_change for reviews driven by new or amended regulations; exam_finding for reviews triggered by market conduct examination findings; incident for reviews triggered by compliance incidents; merger_acquisition for reviews triggered by corporate transactions.. Valid values are `scheduled|regulatory_change|exam_finding|incident|merger_acquisition`',
    `risk_rating` STRING COMMENT 'The enterprise risk rating assigned to this compliance policy based on the severity of regulatory exposure and potential financial or reputational impact of non-compliance. Drives prioritization of monitoring, testing, and remediation activities.. Valid values are `critical|high|medium|low`',
    `training_frequency_months` STRING COMMENT 'The required frequency of compliance training associated with this policy, expressed in months (e.g., 12 for annual training). Null if training_required is False. Drives training calendar scheduling.',
    `training_required` BOOLEAN COMMENT 'Indicates whether mandatory compliance training is required for employees and/or agents as part of this policys implementation and ongoing compliance. Drives training curriculum assignment and completion tracking.',
    `variable_product_applicable` BOOLEAN COMMENT 'Indicates whether this compliance policy applies to variable life insurance or variable annuity products subject to SEC and FINRA oversight. True for policies governing VUL, variable annuity, and registered products.',
    `version_number` STRING COMMENT 'The version identifier of the compliance policy document following a major.minor versioning convention (e.g., 1.0, 2.3). Enables version tracking across the policy lifecycle and supports audit trail requirements.. Valid values are `^d+.d+$`',
    `violation_consequence` STRING COMMENT 'Description of the regulatory, financial, or disciplinary consequences for violation of this compliance policy, including potential penalties, fines, license revocation, or corrective action requirements. Supports risk-based prioritization of policy enforcement.',
    CONSTRAINT pk_compliance_policy PRIMARY KEY(`compliance_policy_id`)
) COMMENT 'Master record of internal compliance policies, procedures, and standards governing the enterprises regulatory obligations. Captures policy name, policy category (AML, HIPAA, suitability, SOX, ORSA, market conduct), regulatory driver, policy owner, effective date, review cycle, last review date, next review date, approval authority, and policy status (draft, active, under review, retired). Serves as the authoritative compliance policy inventory for the enterprise.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`regulatory_change` (
    `regulatory_change_id` BIGINT COMMENT 'Unique system-generated identifier for each regulatory change record. Primary key for the regulatory_change data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory change implementation costs (system changes, process redesign, training) are budgeted and tracked by responsible cost center for project accounting and budget variance analysis.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Regulatory changes often require vendor system updates, consulting services, or implementation support (e.g., LDTI, PBR, state regulation changes). Tracks vendor delivering regulatory change implement',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Regulatory changes impact specific legal entities based on domicile state, licensed jurisdictions, lines of business. Impact assessment and implementation tracking must be entity-specific.',
    `employee_id` BIGINT COMMENT 'Identifier of the internal employee or team lead responsible for overseeing the implementation of changes required to comply with this regulation.',
    `prior_change_regulatory_change_id` BIGINT COMMENT 'Reference to the predecessor regulatory change record that this change amends, supersedes, or replaces. Enables version lineage tracking for evolving regulations.',
    `report_definition_id` BIGINT COMMENT 'Foreign key linking to reporting.report_definition. Business justification: Regulatory changes (new NAIC requirements) trigger updates to report definitions. Links change to the affected report for regulatory change impact assessment and report redesign tracking.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Regulatory changes require impact assessments, implementation plans, and regulatory guidance documents for change management. Essential for regulatory change tracking and implementation workflow. Repl',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: A regulatory_change tracks amendments to regulations. When the change is state-specific (jurisdiction_type = STATE and jurisdiction_state_code is populated), it should reference the specific state_r',
    `actuarial_impact_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change requires updates to actuarial reserving methodologies, valuation assumptions, or cash flow projections (e.g., LDTI, PBR, ORSA changes affecting reserve calculations in systems such as MoSes, AXIS, or Prophet).',
    `aml_bsa_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change relates to Anti-Money Laundering (AML) or Bank Secrecy Act (BSA) compliance obligations governed by FinCEN, including Know Your Customer (KYC) requirements.',
    `board_notification_required_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change requires notification to or approval by the companys Board of Directors or a Board committee (e.g., Audit Committee for SOX-related changes, Risk Committee for ORSA/ERM changes).',
    `change_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to the regulatory change, such as a docket number, rulemaking identifier, or bulletin number issued by the governing body (e.g., NAIC Model Law #XXX, SEC Release No. XX-XXXXX, IRS Notice 2024-XX).',
    `change_status` STRING COMMENT 'Current lifecycle status of the regulatory change record within the companys regulatory change management workflow. [ENUM-REF-CANDIDATE: identified|under_review|impact_assessed|implementation_in_progress|implemented|closed|deferred — promote to reference product]',
    `change_type` STRING COMMENT 'Classification of the nature of the regulatory change. Indicates whether this is a new regulation, an amendment to existing rules, informal guidance, a model law adoption, a regulatory bulletin, or a proposed/final rulemaking. [ENUM-REF-CANDIDATE: new_regulation|amendment|guidance|model_law_adoption|bulletin|interpretive_letter|final_rule|proposed_rule — promote to reference product]',
    `citation_reference` STRING COMMENT 'Official legal or regulatory citation for the change, such as a statute number, code section, model law number, or rulemaking docket (e.g., IRC Section 7702, NAIC Model #830, SEC Release No. IA-6383, DOL PTE 2020-02).',
    `comment_period_deadline` DATE COMMENT 'The deadline by which the company or industry participants may submit formal comments to the issuing regulatory body during the public comment period for proposed rules or model law adoptions.',
    `comment_submitted_flag` BOOLEAN COMMENT 'Indicates whether the company submitted formal comments to the issuing regulatory body during the public comment period for this proposed regulation or rule amendment.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this regulatory change record was first created in the system. Used for audit trail and data lineage purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated_compliance_cost amount (e.g., USD).. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'The date on which the regulatory change becomes legally effective and binding on the companys operations. This is the primary compliance deadline for implementation.',
    `estimated_compliance_cost` DECIMAL(18,2) COMMENT 'Estimated total cost to the company of implementing the required changes to comply with this regulation, including system development, process redesign, training, and legal/consulting fees. Expressed in USD.',
    `hipaa_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change involves HIPAA privacy or security requirements affecting the handling of protected health information (PHI) in underwriting, claims, or policy servicing.',
    `identified_date` DATE COMMENT 'The date on which the companys compliance team first identified and logged this regulatory change into the regulatory change management system.',
    `impact_assessment_date` DATE COMMENT 'The date on which the formal impact assessment for this regulatory change was completed and approved by the responsible compliance team.',
    `impact_assessment_status` STRING COMMENT 'Current status of the formal impact assessment process for this regulatory change. Tracks whether the company has completed its analysis of operational, financial, and system impacts.. Valid values are `not_started|in_progress|completed|approved`',
    `impact_severity` STRING COMMENT 'Assessment of the severity of the regulatory changes impact on the companys operations, systems, and financials. Critical indicates potential for significant financial penalty, operational disruption, or license risk; High indicates major process or system changes required.. Valid values are `critical|high|medium|low`',
    `impact_summary` STRING COMMENT 'Narrative summary describing the assessed business, operational, financial, and system impacts of the regulatory change on the company. Includes key compliance obligations and required actions.',
    `impacted_business_areas` STRING COMMENT 'Pipe-delimited list of business domains or functional areas impacted by this regulatory change (e.g., Policy Underwriting|Claims|Billing|Annuity|Actuarial|Agent Distribution). Derived from the companys core business process taxonomy.',
    `impacted_product_lines` STRING COMMENT 'Pipe-delimited list of insurance product lines affected by this regulatory change (e.g., Whole Life (WL)|Universal Life (UL)|Fixed Indexed Annuity (FIA)|Variable Universal Life (VUL)|Long-Term Care (LTC)|Disability Income (DI)).',
    `impacted_states` STRING COMMENT 'Pipe-delimited list of two-letter US state codes affected by this regulatory change when the change spans multiple states (e.g., NY|CA|TX|FL). Used for multi-state regulatory change tracking.',
    `implementation_deadline` DATE COMMENT 'The internal or regulatory deadline by which the company must complete all operational, system, and process changes required to comply with the regulatory change. May differ from the effective date if a transition period is granted.',
    `implementation_owner_name` STRING COMMENT 'Name of the internal employee or team lead responsible for overseeing the implementation of changes required to comply with this regulation.',
    `issuing_body` STRING COMMENT 'The regulatory authority or governing body that issued the change (e.g., National Association of Insurance Commissioners (NAIC), State Department of Insurance (DOI), Securities and Exchange Commission (SEC), Financial Industry Regulatory Authority (FINRA), Internal Revenue Service (IRS), Department of Labor (DOL), Financial Crimes Enforcement Network (FinCEN), Financial Accounting Standards Board (FASB)). [ENUM-REF-CANDIDATE: NAIC|state_doi|SEC|FINRA|IRS|DOL|FinCEN|FASB|IAIS|ACORD|other — 11 candidates stripped; promote to reference product]',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter US state or territory code for the primary jurisdiction of the regulatory change (e.g., NY, CA, TX). Populated when jurisdiction_type is state. Null for federal or international changes.. Valid values are `^[A-Z]{2}$`',
    `jurisdiction_type` STRING COMMENT 'Indicates whether the regulatory change applies at the federal level, a specific state level, across multiple states, or internationally.. Valid values are `federal|state|multi_state|international`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this regulatory change record was most recently modified. Used for change tracking and audit trail purposes.',
    `publication_date` DATE COMMENT 'The date the regulatory change was officially published or announced by the issuing body in the Federal Register, state bulletin, or equivalent official publication.',
    `regulation_description` STRING COMMENT 'Detailed description of the regulatory change, including the specific requirements, obligations, prohibitions, or standards introduced or modified by the regulation.',
    `regulation_name` STRING COMMENT 'Official name or title of the regulation, legislation, rule, or guidance document (e.g., NAIC Life Insurance Illustrations Model Regulation, SEC Regulation Best Interest, IRS IRC Section 7702 Compliance Update, LDTI ASC 944 Amendment).',
    `regulatory_framework` STRING COMMENT 'The primary regulatory or compliance framework under which this change falls. Examples include NAIC Model Law, IRC Section 7702 (life insurance tax compliance), ERISA (DOL fiduciary), AML/BSA (FinCEN), HIPAA, SOX, GAAP ASC 944, Long Duration Targeted Improvements (LDTI), Principle-Based Reserving (PBR), or Own Risk and Solvency Assessment (ORSA). [ENUM-REF-CANDIDATE: NAIC_model_law|state_insurance_code|SEC_regulation|FINRA_rule|IRC_7702|IRC_72|ERISA|AML_BSA|HIPAA|SOX|IFRS|GAAP_ASC944|LDTI|PBR|ORSA|other — promote to reference product]',
    `responsible_department` STRING COMMENT 'The internal business department or division primarily responsible for implementing the regulatory change (e.g., Compliance, Actuarial, Legal, IT, Finance, Underwriting, Claims).',
    `sox_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change has implications for Sarbanes-Oxley Act (SOX) internal controls over financial reporting, requiring updates to SOX control documentation or testing procedures.',
    `system_change_required_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change requires modifications to one or more operational systems of record (e.g., Policy Administration System, Billing System, Annuity Platform, Actuarial Valuation System).',
    `transition_period_end_date` DATE COMMENT 'The end date of any regulatory-granted transition or phase-in period during which the company may operate under old rules while implementing the new requirements (e.g., LDTI transition period, PBR phase-in).',
    `variable_product_flag` BOOLEAN COMMENT 'Indicates whether this regulatory change applies to variable insurance or annuity products (Variable Universal Life (VUL), Variable Annuities) subject to SEC and FINRA oversight in addition to state insurance regulation.',
    CONSTRAINT pk_regulatory_change PRIMARY KEY(`regulatory_change_id`)
) COMMENT 'Master record tracking regulatory changes, new legislation, and rule amendments that impact the companys operations. Captures regulation name, issuing body (NAIC, state DOI, SEC, FINRA, IRS, DOL, FinCEN, FASB), change type (new regulation, amendment, guidance, model law adoption), effective date, comment period deadline, impacted business areas, impact assessment status, implementation owner, and implementation deadline. Enables proactive regulatory change management.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`exception` (
    `exception_id` BIGINT COMMENT 'Unique identifier for the compliance exception record. Primary key for the compliance exception entity.',
    `employee_id` BIGINT COMMENT 'Identifier of the employee or executive who approved or denied the compliance exception request.',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Exception requests and approvals require documented correspondence trails for audit and governance. Real business process: exception approval workflow documentation ensuring proper authorization and c',
    `compliance_policy_id` BIGINT COMMENT 'Reference to the internal compliance policy from which an exception is being requested.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Exceptions require documented business justification, risk assessments, and approval documentation for exception approval workflow. Critical for compliance exception tracking and audit support. Replac',
    `exception_employee_id` BIGINT COMMENT 'Identifier of the employee who submitted the compliance exception request.',
    `guideline_id` BIGINT COMMENT 'Foreign key linking to investment.investment_guideline. Business justification: Exceptions waive specific investment guidelines (concentration limits, credit quality requirements, asset class restrictions). Real business process: guideline exception management, temporary relief a',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Compliance exceptions grant temporary relief from investment guideline limits for specific portfolios. Real business process: exception request, investment committee approval, temporary limit waiver. ',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Exceptions to compensation policies may be granted for specific commission schedules (non-standard rates for special markets, temporary promotional rates, legacy schedule grandfathering). Business pro',
    `renewed_exception_id` BIGINT COMMENT 'Self-referencing FK on exception (renewed_exception_id)',
    `affected_business_process` STRING COMMENT 'Name of the business process or operational workflow affected by this compliance exception.',
    `affected_product_lines` STRING COMMENT 'Comma-separated list of product lines or lines of business affected by this compliance exception (e.g., Term Life, Universal Life (UL), Variable Universal Life (VUL), Fixed Indexed Annuity (FIA)).',
    `approval_authority_level` STRING COMMENT 'Level of authority required to approve this compliance exception based on its risk rating and scope.. Valid values are `department_head|compliance_officer|chief_compliance_officer|chief_risk_officer|executive_committee|board_of_directors`',
    `approval_date` DATE COMMENT 'Date on which the compliance exception was approved by the designated authority. Null if denied or still pending.',
    `approver_name` STRING COMMENT 'Full name of the individual who approved or denied the compliance exception request.',
    `approver_title` STRING COMMENT 'Job title or role of the individual who approved or denied the compliance exception request.',
    `board_notification_date` DATE COMMENT 'Date on which the Board of Directors was notified of this compliance exception. Null if board notification was not required or has not yet occurred.',
    `board_notification_required` BOOLEAN COMMENT 'Indicates whether this compliance exception requires notification to the Board of Directors due to its materiality or risk level.',
    `business_justification` STRING COMMENT 'Detailed business rationale and justification for requesting the compliance exception, including operational necessity and business impact.',
    `compensating_controls` STRING COMMENT 'Description of compensating controls, alternative procedures, or risk mitigation measures that will be implemented while the exception is in effect.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance exception record was first created in the system.',
    `denial_date` DATE COMMENT 'Date on which the compliance exception request was formally denied. Null if approved or still pending.',
    `denial_reason` STRING COMMENT 'Detailed explanation of why the compliance exception request was denied, including regulatory or risk concerns.',
    `effective_date` DATE COMMENT 'Date on which the approved compliance exception becomes effective and the deviation from standard compliance is permitted.',
    `exception_description` STRING COMMENT 'Detailed narrative description of the compliance exception, including the specific deviation from policy or regulation being requested.',
    `exception_number` STRING COMMENT 'Business-facing unique reference number assigned to the compliance exception for tracking and communication purposes.',
    `exception_status` STRING COMMENT 'Current status of the compliance exception in its approval and lifecycle workflow. [ENUM-REF-CANDIDATE: requested|under_review|approved|denied|expired|revoked|closed — 7 candidates stripped; promote to reference product]',
    `exception_type` STRING COMMENT 'Classification of the type of compliance exception being requested or granted. Defines the nature of the deviation from standard compliance requirements.. Valid values are `policy_waiver|regulatory_safe_harbor|temporary_non_compliance|control_override|process_deviation|system_limitation`',
    `expiration_date` DATE COMMENT 'Date on which the compliance exception expires and standard compliance requirements are reinstated. Null for indefinite exceptions subject to periodic review.',
    `financial_exposure_amount` DECIMAL(18,2) COMMENT 'Estimated financial exposure or potential monetary impact associated with granting this compliance exception, expressed in US dollars (USD).',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code identifying the regulatory jurisdiction affected by this exception. Null if federal or multi-state.',
    `last_review_date` DATE COMMENT 'Date of the most recent periodic review of this compliance exception.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance exception record was most recently modified or updated.',
    `next_review_date` DATE COMMENT 'Date on which the next periodic review of this compliance exception is scheduled to occur.',
    `regulator_notification_date` DATE COMMENT 'Date on which regulatory authorities were formally notified of this compliance exception. Null if notification was not required or has not yet occurred.',
    `regulator_notification_required` BOOLEAN COMMENT 'Indicates whether this compliance exception requires formal notification to regulatory authorities.',
    `regulatory_citation` STRING COMMENT 'Specific citation or section reference of the regulation or compliance requirement affected by this exception.',
    `regulatory_framework` STRING COMMENT 'Name of the regulatory framework or requirement affected by this exception (e.g., NAIC Model Regulation, SEC Rule, IRS Section 7702, HIPAA Privacy Rule).',
    `request_date` DATE COMMENT 'Date on which the compliance exception was formally requested.',
    `requesting_business_unit` STRING COMMENT 'Name of the business unit, department, or division that initiated the compliance exception request.',
    `requestor_name` STRING COMMENT 'Full name of the individual who submitted the compliance exception request.',
    `requestor_title` STRING COMMENT 'Job title or role of the individual who submitted the compliance exception request.',
    `review_frequency_months` STRING COMMENT 'Number of months between periodic reviews of this compliance exception to reassess its continued necessity and appropriateness.',
    `revocation_date` DATE COMMENT 'Date on which the compliance exception was revoked prior to its scheduled expiration date. Null if not revoked.',
    `revocation_reason` STRING COMMENT 'Explanation of why the compliance exception was revoked before its expiration date, including any triggering events or changed circumstances.',
    `risk_assessment_summary` STRING COMMENT 'Summary of the risk assessment conducted to evaluate the potential impact and exposure associated with granting this exception.',
    `risk_rating` STRING COMMENT 'Overall risk rating assigned to this compliance exception based on the risk assessment (low, medium, high, critical).. Valid values are `low|medium|high|critical`',
    CONSTRAINT pk_exception PRIMARY KEY(`exception_id`)
) COMMENT 'Record of approved exceptions, waivers, or temporary deviations from compliance policies or regulatory requirements. Captures exception type (policy waiver, regulatory safe harbor, temporary non-compliance), requesting business unit, compliance policy or regulation affected, risk assessment, approval authority, approval date, expiration date, compensating controls required, and exception status (requested, approved, denied, expired, revoked). Essential for audit trail demonstrating deliberate risk acceptance decisions.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`issue` (
    `issue_id` BIGINT COMMENT 'Unique identifier for the compliance issue record. Primary key.',
    `asset_holding_id` BIGINT COMMENT 'Foreign key linking to investment.asset_holding. Business justification: Compliance issues may reference specific problematic holdings (impaired assets, non-compliant securities, valuation disputes). Real business process: asset-level issue tracking, remediation, dispositi',
    `communication_id` BIGINT COMMENT 'Foreign key linking to correspondence.communication. Business justification: Compliance issues generate investigation correspondence, remediation discussions, and closure notifications with regulators and internal stakeholders. Real business process: issue resolution tracking ',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_policy. Business justification: Compliance issues often relate to violations of specific internal compliance policies. The issue describes the violation, while the policy describes the rule that was violated.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Issue remediation costs are tracked by responsible cost center for accountability and budget variance analysis. Finance needs cost attribution for compliance risk management reporting.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Compliance issues require documented root cause analysis, corrective action plans, and closure evidence. Essential for issue remediation tracking and regulatory closure. Replaces text reference with s',
    `exam_finding_id` BIGINT COMMENT 'Identifier linking the issue to a specific examination finding record, if the issue originated from a regulatory exam.',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: Compliance issues are often identified on specific policies (e.g., suitability violations, illustration errors, misrepresentation). Linking enables remediation tracking at policy level, supports regul',
    `employee_id` BIGINT COMMENT 'Identifier of the individual assigned primary accountability for managing and resolving the compliance issue.',
    `issue_executive_sponsor_employee_id` BIGINT COMMENT 'Identifier of the executive-level sponsor providing oversight and escalation support for the issue resolution.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Compliance issues are tracked by legal entity for regulatory reporting, management accountability, and financial statement disclosure (penalties, restitution accruals).',
    `market_conduct_exam_id` BIGINT COMMENT 'Identifier linking the issue to a specific regulatory market conduct examination, if applicable.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Compliance issues track investment-related problems (guideline breaches, valuation disputes, custody issues, reporting errors). Real business process: issue tracking, remediation management, investmen',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Compliance issues may relate to failures to meet regulatory obligations. The issue describes the problem, while the obligation describes the requirement that was not met.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: Compliance issues frequently stem from vendor service failures (system defects, process errors, data quality issues) or require vendor remediation. Tracks vendor responsible for issue or required for ',
    `schedule_id` BIGINT COMMENT 'Foreign key linking to commission.commission_schedule. Business justification: Compliance issues may be identified with specific commission schedules (anti-rebating violations, excessive compensation, unsuitable incentives, unlicensed product compensation). Business process: iss',
    `root_cause_issue_id` BIGINT COMMENT 'Self-referencing FK on issue (root_cause_issue_id)',
    `actual_completion_date` DATE COMMENT 'The actual date on which all remediation activities were completed.',
    `actual_penalty_amount` DECIMAL(18,2) COMMENT 'The actual monetary penalty or fine assessed by the regulatory authority for the compliance issue.',
    `affected_business_area` STRING COMMENT 'The business function, department, or operational area impacted by the compliance issue (e.g., Underwriting, Claims, Billing, Agent Licensing, Annuity Administration).',
    `affected_data_domain` STRING COMMENT 'The data domain or subject area impacted by the issue (e.g., Policyholder, Policy, Claims, Billing, Compliance, Agent).',
    `affected_product_line` STRING COMMENT 'The insurance product line or line of business affected by the issue (e.g., Term Life, Whole Life, Universal Life (UL), Indexed Universal Life (IUL), Variable Universal Life (VUL), Fixed Annuity, Variable Annuity, Fixed Indexed Annuity (FIA)).',
    `closure_date` DATE COMMENT 'The date on which the compliance issue was formally closed after successful remediation and validation.',
    `corrective_action_description` STRING COMMENT 'Detailed description of the corrective actions and remediation steps planned or implemented to resolve the compliance issue.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the compliance issue record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts (e.g., USD).. Valid values are `^[A-Z]{3}$`',
    `due_date` DATE COMMENT 'The target date by which the compliance issue must be resolved or remediated, often driven by regulatory deadlines or internal commitments.',
    `estimated_financial_exposure` DECIMAL(18,2) COMMENT 'The estimated financial impact or exposure associated with the compliance issue, including potential fines, penalties, restitution, and remediation costs.',
    `identified_date` DATE COMMENT 'The date on which the compliance issue was first identified or discovered.',
    `impacted_policy_count` STRING COMMENT 'The number of insurance policies or annuity contracts affected by the compliance issue.',
    `issue_description` STRING COMMENT 'Detailed narrative description of the compliance issue, including the specific deficiency, violation, or gap identified.',
    `issue_source` STRING COMMENT 'Channel or mechanism through which the compliance issue was identified. [ENUM-REF-CANDIDATE: internal_audit|regulatory_exam|self_assessment|external_audit|whistleblower|consumer_complaint|sox_testing|aml_review — 8 candidates stripped; promote to reference product]',
    `issue_status` STRING COMMENT 'Current lifecycle status of the compliance issue in the remediation workflow.. Valid values are `identified|assessed|remediating|closed|escalated|reopened`',
    `issue_type` STRING COMMENT 'Classification of the compliance issue by its nature and origin.. Valid values are `regulatory_violation|control_deficiency|policy_breach|audit_finding|examination_finding|self_identified`',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code identifying the primary regulatory jurisdiction where the issue applies. Multi-state issues may reference the lead state.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when the compliance issue record was last modified.',
    `priority_level` STRING COMMENT 'Operational priority assigned to the issue for remediation sequencing and resource allocation.. Valid values are `urgent|high|medium|low`',
    `reference_number` STRING COMMENT 'Business-facing unique reference number for the compliance issue, used for tracking and communication with regulators and internal stakeholders.',
    `regulatory_acceptance_date` DATE COMMENT 'The date on which the regulatory authority formally accepted the remediation.',
    `regulatory_acceptance_status` STRING COMMENT 'Indicates whether the regulatory authority has accepted the remediation as satisfactory.. Valid values are `accepted|rejected|pending|not_required`',
    `regulatory_authority` STRING COMMENT 'The governing body or regulatory agency with jurisdiction over the issue (e.g., State DOI, NAIC, SEC, FINRA, IRS, FinCEN, DOL).',
    `regulatory_citation` STRING COMMENT 'Specific statute, regulation, rule, or code section that was violated or not met, including section and subsection references.',
    `regulatory_deadline_date` DATE COMMENT 'The mandatory deadline imposed by the regulatory authority for issue resolution or corrective action plan submission.',
    `regulatory_framework` STRING COMMENT 'The governing regulatory framework or statute under which the issue was identified (e.g., NAIC Model Regulation, state insurance code, SEC Rule, IRS Section 7702, HIPAA, AML/BSA, SOX, ERISA).',
    `regulatory_reporting_required_flag` BOOLEAN COMMENT 'Indicates whether the compliance issue triggers a mandatory regulatory reporting obligation (e.g., Suspicious Activity Report (SAR), breach notification, market conduct report).',
    `remediation_status` STRING COMMENT 'Current status of the remediation plan execution for the compliance issue.. Valid values are `planned|in_progress|completed|validated|deferred`',
    `responsible_department` STRING COMMENT 'The department or business unit responsible for remediating the compliance issue.',
    `restitution_amount` DECIMAL(18,2) COMMENT 'The total amount of consumer restitution or remediation payments required as a result of the compliance issue.',
    `root_cause_category` STRING COMMENT 'High-level classification of the root cause type for trending and analysis. [ENUM-REF-CANDIDATE: process_failure|system_defect|control_weakness|human_error|policy_gap|training_deficiency|vendor_issue — 7 candidates stripped; promote to reference product]',
    `root_cause_description` STRING COMMENT 'Detailed analysis of the underlying root cause(s) that led to the compliance issue, including process, system, or control failures.',
    `severity_level` STRING COMMENT 'Risk-based severity classification of the compliance issue indicating potential impact to the organization and consumers.. Valid values are `critical|major|moderate|minor|low`',
    `target_completion_date` DATE COMMENT 'The originally planned target date for completing all remediation activities.',
    `title` STRING COMMENT 'Brief descriptive title summarizing the nature of the compliance issue.',
    `validation_date` DATE COMMENT 'The date on which the remediation was validated as effective.',
    `validation_method` STRING COMMENT 'The approach or methodology used to validate that the remediation was effective and the issue is resolved (e.g., testing, audit, regulatory review, control re-testing).',
    `validation_outcome` STRING COMMENT 'The result of the remediation validation testing or review.. Valid values are `passed|failed|partial|pending`',
    CONSTRAINT pk_issue PRIMARY KEY(`issue_id`)
) COMMENT 'Consolidated record of compliance issues, violations, and deficiencies identified through any channel — internal monitoring, self-assessments, regulatory examinations, audit findings, or whistleblower reports. Captures issue source, severity, regulatory citation, affected business area, issue owner, due date, status (identified, assessed, remediating, closed, escalated), and regulatory reporting obligation triggered. Includes full remediation plan details: root cause analysis, corrective actions, responsible owner, target and actual completion dates, remediation status (planned, in-progress, completed, validated), validation method, regulatory acceptance status, and remediation evidence references. Serves as the single compliance issue and remediation tracking inventory enabling enterprise-wide compliance health reporting, gap closure tracking, and regulatory examination response.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`state_regulation` (
    `state_regulation_id` BIGINT COMMENT 'Unique identifier for the state-specific insurance regulation record. Primary key.',
    `superseded_by_regulation_state_regulation_id` BIGINT COMMENT 'Reference to the newer state regulation that replaces this regulation, if applicable. Null if not superseded.',
    `superseded_state_regulation_id` BIGINT COMMENT 'Self-referencing FK on state_regulation (superseded_state_regulation_id)',
    `accelerated_death_benefit_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing accelerated death benefit riders. True if ADB regulations apply, False if not.',
    `best_interest_standard_flag` BOOLEAN COMMENT 'Indicates whether the state has adopted a best interest standard for annuity sales (similar to Regulation Best Interest). True if best interest standard applies, False if not.',
    `compliance_notes` STRING COMMENT 'Internal notes documenting compliance considerations, implementation guidance, or special handling requirements for this state regulation.',
    `contestability_period_months` STRING COMMENT 'Number of months during which the insurer may contest a life insurance policy for material misrepresentation, as mandated by state law. Typically 24 months but may vary by state.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this state regulation record was first created in the system.',
    `effective_date` DATE COMMENT 'Date when the state-specific regulation becomes enforceable and applicable to insurance operations.',
    `expiration_date` DATE COMMENT 'Date when the state regulation ceases to be in effect, if applicable. Null for regulations with no defined end date.',
    `form_filing_method` STRING COMMENT 'State-mandated method for submitting and approving policy forms (prior approval required before use, file and use after DOI review, use and file with post-use notification, no filing required).. Valid values are `prior_approval|file_and_use|use_and_file|no_filing`',
    `free_look_period_days` STRING COMMENT 'Number of days the policyholder has to review and cancel a newly issued policy without penalty, as mandated by state regulation. Varies by state and product type.',
    `grace_period_days` STRING COMMENT 'Number of days after premium due date during which coverage remains in force without lapse, as required by state regulation. Typically 30-31 days but varies by state.',
    `illustration_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing life insurance policy illustrations. True if illustration rules apply, False if not.',
    `insurable_interest_requirement` STRING COMMENT 'State-specific definition and requirements for establishing insurable interest in life insurance transactions. Describes when insurable interest must exist (at inception, at death, etc.).',
    `interest_rate_guarantee_minimum` DECIMAL(18,2) COMMENT 'State-mandated minimum guaranteed interest rate for cash value accumulation in life insurance and annuity products. Expressed as a decimal (e.g., 0.0200 for 2%).',
    `issuing_authority` STRING COMMENT 'Name of the state regulatory body that issued or enforces this regulation (e.g., California Department of Insurance, New York Department of Financial Services).',
    `jurisdiction_name` STRING COMMENT 'Full name of the state or territory regulatory jurisdiction (e.g., California, New York, Texas).',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code identifying the regulatory jurisdiction (e.g., CA, NY, TX). Aligns with NAIC state codes.. Valid values are `^[A-Z]{2}$`',
    `last_amended_date` DATE COMMENT 'Date when the state regulation was last amended or revised. Null if no amendments have been made since original enactment.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this state regulation record was last modified in the system.',
    `long_term_care_partnership_flag` BOOLEAN COMMENT 'Indicates whether the state participates in the Long-Term Care Partnership Program, allowing policyholders to protect assets while qualifying for Medicaid. True if partnership state, False if not.',
    `minimum_cash_surrender_value_percentage` DECIMAL(18,2) COMMENT 'State-mandated minimum cash surrender value as a percentage of premiums paid or reserves, as required by nonforfeiture laws. Null if no state-specific requirement.',
    `minimum_death_benefit_amount` DECIMAL(18,2) COMMENT 'State-mandated minimum death benefit amount for life insurance policies issued in the jurisdiction. Null if no state-specific minimum applies.',
    `nonforfeiture_method` STRING COMMENT 'State-mandated method for calculating nonforfeiture values (Commissioners Reserve Valuation Method, Commissioners Extended Term Method, Cash Surrender Value Method).. Valid values are `commissioners_reserve|commissioners_extended|cash_surrender`',
    `nonforfeiture_requirement_flag` BOOLEAN COMMENT 'Indicates whether the state mandates nonforfeiture benefits (cash surrender value, reduced paid-up insurance, extended term insurance) for this product type. True if required, False if not.',
    `product_line` STRING COMMENT 'Insurance product line(s) to which this state regulation applies (e.g., Life, Annuity, Variable Life, Variable Annuity, Long-Term Care). May contain multiple values separated by semicolons.',
    `rate_filing_method` STRING COMMENT 'State-mandated method for submitting and approving insurance rates (prior approval required before use, file and use after DOI review, use and file with post-use notification, no filing required).. Valid values are `prior_approval|file_and_use|use_and_file|no_filing`',
    `regulation_citation` STRING COMMENT 'Official citation reference to the state statute, regulation, or administrative code section that establishes this requirement (e.g., California Insurance Code Section 10113.71).',
    `regulation_description` STRING COMMENT 'Detailed description of the state-specific regulatory requirement, including key provisions, applicability conditions, and compliance obligations.',
    `regulation_status` STRING COMMENT 'Current lifecycle status of the state regulation (active, superseded by newer regulation, pending approval, withdrawn).. Valid values are `active|superseded|pending|withdrawn`',
    `regulation_type` STRING COMMENT 'Category of state-specific insurance regulation (policy form approval, rate filing requirements, nonforfeiture standards, free look period, grace period, replacement regulations).. Valid values are `policy_form|rate_filing|nonforfeiture|free_look|grace_period|replacement`',
    `replacement_notice_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires written notice to the existing insurer when a policy replacement is proposed. True if notice required, False if not.',
    `replacement_regulation_flag` BOOLEAN COMMENT 'Indicates whether the state has specific regulations governing policy replacement transactions (1035 exchanges, internal replacements). True if state has replacement rules, False if not.',
    `serff_filing_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires rate and form filings to be submitted through the NAIC SERFF system. True if SERFF required, False if alternative methods allowed.',
    `stoli_prohibition_flag` BOOLEAN COMMENT 'Indicates whether the state has enacted specific prohibitions against stranger-originated life insurance transactions. True if STOLI prohibited, False if not.',
    `suicide_exclusion_period_months` STRING COMMENT 'Number of months during which death by suicide is excluded from life insurance coverage, as mandated by state law. Typically 24 months but may vary by state.',
    `suitability_review_required_flag` BOOLEAN COMMENT 'Indicates whether the state mandates suitability reviews and documentation for annuity sales. True if suitability review required, False if not.',
    `variable_product_registration_required_flag` BOOLEAN COMMENT 'Indicates whether the state requires separate registration or approval for variable life and variable annuity products beyond standard form filing. True if additional registration required, False if not.',
    CONSTRAINT pk_state_regulation PRIMARY KEY(`state_regulation_id`)
) COMMENT 'Reference table of state-specific insurance regulatory requirements, variations, and effective dates by jurisdiction. Captures state DOI-specific rules for policy forms, rate filings, nonforfeiture requirements, free look periods, grace periods, and replacement regulations that vary by state.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`sar_filing` (
    `sar_filing_id` BIGINT COMMENT 'Unique identifier for the SAR filing record. Primary key.',
    `aml_case_id` BIGINT COMMENT 'Reference to the AML case investigation that resulted in this SAR filing.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to vendor.vendor. Business justification: SAR filings may involve third-party AML technology vendors for transaction monitoring, case management, or SAR preparation and filing. Tracks vendor providing AML compliance technology or consulting s',
    `employee_id` BIGINT COMMENT 'Reference to the senior compliance officer or manager who approved the SAR filing for submission.',
    `in_force_policy_id` BIGINT COMMENT 'Reference to the life insurance or annuity policy involved in the suspicious activity, if applicable.',
    `party_id` BIGINT COMMENT 'Reference to the policyholder who is the subject of the suspicious activity report.',
    `primary_sar_employee_id` BIGINT COMMENT 'Reference to the compliance officer or employee who prepared the SAR filing.',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: SAR filings fulfill FinCEN AML/BSA regulatory obligations. The obligation defines the filing deadline and requirements.',
    `report_run_id` BIGINT COMMENT 'Foreign key linking to reporting.report_run. Business justification: SAR filings are generated through report runs that compile transaction data and narrative descriptions. Links SAR to the report run for BSA/AML reporting automation and audit trail.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: SAR filings are formal FinCEN documents with narrative descriptions and supporting evidence required by BSA/AML regulations. Critical for AML regulatory reporting and FinCEN submission tracking in Lif',
    `trade_id` BIGINT COMMENT 'Foreign key linking to investment.trade. Business justification: SAR filings report suspicious trading activity (structuring, unusual patterns, STOLI indicators). Real business process: suspicious transaction reporting, FinCEN filing, AML compliance. Required for i',
    `prior_sar_filing_id` BIGINT COMMENT 'Self-referencing FK on sar_filing (prior_sar_filing_id)',
    `acknowledgment_date` DATE COMMENT 'Date when FinCEN acknowledged receipt of the SAR filing. Format: yyyy-MM-dd.',
    `activity_end_date` DATE COMMENT 'Date when the suspicious activity ended or was last observed. May be null for ongoing activity. Format: yyyy-MM-dd.',
    `activity_start_date` DATE COMMENT 'Date when the suspicious activity began or was first observed. Format: yyyy-MM-dd.',
    `approval_date` DATE COMMENT 'Date when the SAR filing was approved for submission to FinCEN. Format: yyyy-MM-dd.',
    `approver_name` STRING COMMENT 'Full name of the senior compliance officer or manager who approved the SAR filing for submission.',
    `confidentiality_flag` BOOLEAN COMMENT 'Indicates that this SAR filing is subject to strict confidentiality requirements under the Bank Secrecy Act. Always True for SAR filings.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this SAR filing record was first created in the system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the transaction amount (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `detection_method` STRING COMMENT 'Method by which the suspicious activity was detected: automated monitoring system, manual review, customer complaint, law enforcement inquiry, regulatory examination, or other.. Valid values are `automated_monitoring|manual_review|customer_complaint|law_enforcement_inquiry|regulatory_exam|other`',
    `filing_date` DATE COMMENT 'Date when the SAR was filed with FinCEN. Format: yyyy-MM-dd.',
    `filing_reference_number` STRING COMMENT 'Internal reference number assigned to this SAR filing for tracking and audit purposes.',
    `filing_status` STRING COMMENT 'Current status of the SAR filing in the internal workflow: draft (being prepared), pending_review (awaiting compliance review), approved (ready for submission), submitted (sent to FinCEN), acknowledged (FinCEN confirmation received), rejected (FinCEN rejected submission).. Valid values are `draft|pending_review|approved|submitted|acknowledged|rejected`',
    `filing_type` STRING COMMENT 'Type of SAR filing: initial (first report of suspicious activity), continuing (follow-up to prior SAR), corrected (correction to previously filed SAR), or amended (substantive change to prior SAR).. Valid values are `initial|continuing|corrected|amended`',
    `fincen_bsa_number` STRING COMMENT 'Unique identifier assigned by FinCEN upon successful submission of the SAR. Also known as the BSA Identifier or acknowledgment number.',
    `jurisdiction_state_code` STRING COMMENT 'Two-letter state code where the suspicious activity occurred or where the policy was issued.. Valid values are `^[A-Z]{2}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this SAR filing record was last modified. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `law_enforcement_agency` STRING COMMENT 'Name of the law enforcement agency contacted regarding this suspicious activity, if applicable.',
    `law_enforcement_contact_flag` BOOLEAN COMMENT 'Indicates whether law enforcement has been contacted regarding this suspicious activity. True if contacted, False otherwise.',
    `narrative_description` STRING COMMENT 'Detailed narrative description of the suspicious activity, including facts, circumstances, and reasons for suspicion. This is the core content of the SAR filing.',
    `preparer_name` STRING COMMENT 'Full name of the compliance officer or employee who prepared the SAR filing.',
    `prior_sar_reference` STRING COMMENT 'Reference to a prior SAR filing if this is a continuing, corrected, or amended SAR. Contains the FinCEN BSA ID of the prior SAR.',
    `product_type` STRING COMMENT 'Type of insurance or annuity product involved in the suspicious activity. [ENUM-REF-CANDIDATE: life_insurance|annuity|variable_life|variable_annuity|universal_life|whole_life|term_life|other — 8 candidates stripped; promote to reference product]',
    `rejection_date` DATE COMMENT 'Date when FinCEN rejected the SAR filing due to errors or incomplete information. Format: yyyy-MM-dd.',
    `rejection_reason` STRING COMMENT 'Reason provided by FinCEN for rejecting the SAR filing, if applicable.',
    `subject_address` STRING COMMENT 'Full address of the subject involved in the suspicious activity.',
    `subject_date_of_birth` DATE COMMENT 'Date of birth of the individual subject, if applicable. Format: yyyy-MM-dd.',
    `subject_name` STRING COMMENT 'Full legal name of the individual or entity that is the subject of the suspicious activity report.',
    `subject_tax_number` STRING COMMENT 'Tax identification number of the subject: Social Security Number (SSN) for individuals or Employer Identification Number (EIN) for entities.',
    `subject_type` STRING COMMENT 'Type of subject involved in the suspicious activity: individual (natural person), entity (organization/business), or unknown.. Valid values are `individual|entity|unknown`',
    `submission_timestamp` TIMESTAMP COMMENT 'Precise date and time when the SAR was electronically submitted to FinCEN. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `suspicious_activity_type` STRING COMMENT 'Category or type of suspicious activity being reported (e.g., structuring, money laundering, terrorist financing, fraud, identity theft). May contain multiple types separated by semicolons. [ENUM-REF-CANDIDATE: structuring|money_laundering|terrorist_financing|fraud|identity_theft|elder_financial_exploitation|insurance_fraud|premium_financing_abuse|stoli|tax_evasion|bribery|embezzlement — promote to reference product]',
    `transaction_amount` DECIMAL(18,2) COMMENT 'Total dollar amount of the transaction(s) involved in the suspicious activity. Aggregate amount if multiple transactions.',
    CONSTRAINT pk_sar_filing PRIMARY KEY(`sar_filing_id`)
) COMMENT 'Transactional record of Suspicious Activity Reports (SARs) filed with FinCEN under the Bank Secrecy Act (BSA) for life insurance and annuity transactions. Captures SAR type (initial/continuing), filing date, FinCEN BSA ID, suspicious activity date range, transaction amounts, subject information, narrative description, filing status, and acknowledgment receipt. Required for AML/BSA compliance.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`policy_obligation_coverage` (
    `policy_obligation_coverage_id` BIGINT COMMENT 'Unique surrogate identifier for each policy-obligation coverage mapping record',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key to compliance_policy',
    `policy_compliance_policy_id` BIGINT COMMENT 'Foreign key linking to the compliance policy that provides coverage for the regulatory obligation',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation being addressed by the compliance policy',
    `attestation_frequency` STRING COMMENT 'How often compliance attestation is required for this specific policy-obligation coverage. Drives the compliance calendar and attestation workflow.',
    `attestation_owner` STRING COMMENT 'Full name or employee identifier of the individual responsible for attesting to the adequacy of this policys coverage of this obligation.',
    `compliance_status` STRING COMMENT 'Current compliance status of this specific policy-obligation coverage relationship. Indicates whether the policy adequately addresses the obligation requirements.',
    `coverage_gap_identified` BOOLEAN COMMENT 'Indicates whether a coverage gap has been identified in this policy-obligation relationship, requiring remediation or additional policy development.',
    `coverage_notes` STRING COMMENT 'Free-text notes documenting specific aspects of how this policy addresses this obligation, including any limitations, dependencies, or special considerations.',
    `coverage_scope` STRING COMMENT 'Indicates the extent to which this policy addresses this obligation. Full = policy completely addresses obligation; Partial = policy addresses some requirements; Supplemental = policy provides additional guidance; Primary = main policy for this obligation; Secondary = supporting policy.',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this policy-obligation coverage mapping was first created in the system.',
    `effective_date` DATE COMMENT 'The date on which this compliance policy began providing coverage for this specific regulatory obligation. May differ from the policys overall effective date if the policy was extended to cover additional obligations.',
    `expiration_date` DATE COMMENT 'The date on which this compliance policy ceased or will cease to provide coverage for this regulatory obligation. Null indicates ongoing coverage.',
    `gap_remediation_plan` STRING COMMENT 'Narrative description of the remediation plan to address any identified coverage gaps in this policy-obligation relationship.',
    `last_modified_by` STRING COMMENT 'User identifier of the compliance personnel who most recently modified this coverage mapping record.',
    `last_modified_date` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this coverage mapping record.',
    `last_review_date` DATE COMMENT 'The date on which the adequacy of this policys coverage of this obligation was most recently reviewed by compliance personnel.',
    `next_attestation_date` DATE COMMENT 'The scheduled date by which the next compliance attestation for this policy-obligation coverage must be completed.',
    `created_by` STRING COMMENT 'User identifier of the compliance personnel who created this coverage mapping record.',
    CONSTRAINT pk_policy_obligation_coverage PRIMARY KEY(`policy_obligation_coverage_id`)
) COMMENT 'This association product represents the Coverage Mapping between compliance_policy and regulatory_obligation. It captures which internal compliance policies address which regulatory obligations, enabling compliance teams to track coverage gaps, maintain attestation records, and demonstrate regulatory compliance. Each record links one compliance_policy to one regulatory_obligation with attributes that exist only in the context of this coverage relationship.. Existence Justification: In life insurance compliance operations, a single compliance policy typically addresses multiple regulatory obligations (e.g., an AML policy covers BSA filing requirements, SAR reporting, CIP procedures, and ongoing monitoring obligations). Conversely, a single regulatory obligation often requires multiple policies working together (e.g., NAIC Annual Statement filing requires policies for data governance, actuarial standards, financial reporting, and disclosure controls). Compliance teams actively manage these coverage mappings to track gaps, maintain attestation records, and demonstrate regulatory compliance during examinations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`policy_control_mapping` (
    `policy_control_mapping_id` BIGINT COMMENT 'Unique surrogate identifier for each policy-control mapping record',
    `compliance_policy_id` BIGINT COMMENT 'Foreign key to compliance_policy',
    `policy_compliance_policy_id` BIGINT COMMENT 'Foreign key linking to the compliance policy being implemented by this control',
    `sox_control_id` BIGINT COMMENT 'Foreign key linking to the SOX control that implements this compliance policy',
    `control_effectiveness_rating` STRING COMMENT 'Assessment of how effectively this control implements the requirements of the associated compliance policy. Values: effective, ineffective, not_tested, design_deficiency, operating_deficiency',
    `coverage_scope` STRING COMMENT 'Description of which aspects or requirements of the compliance policy are covered by this specific control (e.g., segregation of duties requirement, approval authority validation, documentation retention)',
    `exception_count` STRING COMMENT 'Number of exceptions or deviations identified during testing of this controls implementation of this specific policy',
    `last_review_date` DATE COMMENT 'The date on which this policy-control mapping was most recently reviewed for continued appropriateness and effectiveness',
    `last_test_date` DATE COMMENT 'The most recent date on which this control was tested specifically for its effectiveness in implementing this compliance policy',
    `mapped_by_user` STRING COMMENT 'Name or identifier of the compliance analyst or auditor who established this policy-control mapping',
    `mapping_effective_date` DATE COMMENT 'The date on which this control was formally designated as implementing this compliance policy',
    `mapping_status` STRING COMMENT 'Current lifecycle state of this policy-control mapping. Values: active (control currently implements policy), inactive (mapping no longer in effect), under_review (mapping being evaluated), superseded (replaced by different control)',
    `next_review_date` DATE COMMENT 'The scheduled date by which this policy-control mapping must be reviewed again',
    `remediation_status` STRING COMMENT 'Current status of any remediation actions required to address deficiencies in this controls implementation of this policy. Values: not_required, planned, in_progress, completed, overdue',
    `test_result` STRING COMMENT 'Outcome of the most recent test of this controls implementation of this policy. Values: passed, failed, passed_with_exceptions, not_applicable',
    CONSTRAINT pk_policy_control_mapping PRIMARY KEY(`policy_control_mapping_id`)
) COMMENT 'This association product represents the implementation relationship between compliance policies and SOX controls. It captures which SOX controls implement which compliance policies, tracking control effectiveness, test results, and remediation status for each policy-control pairing. Each record links one compliance_policy to one sox_control with attributes that exist only in the context of this implementation relationship.. Existence Justification: In SOX compliance operations, one compliance policy (e.g., AML policy, HIPAA safeguards policy) is typically implemented by multiple SOX controls across different business processes, and conversely, one SOX control (e.g., premium revenue reconciliation) often implements requirements from multiple compliance policies (e.g., SOX financial reporting policy, revenue recognition policy, state insurance regulation policy). Compliance teams actively manage these mappings, track control effectiveness for each policy requirement, maintain test results, and monitor remediation status for each policy-control pairing.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`course_approval` (
    `course_approval_id` BIGINT COMMENT 'Unique surrogate identifier for each course approval mapping record',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation that this training course satisfies',
    `training_course_id` BIGINT COMMENT 'Foreign key linking to the training course that has been approved to satisfy the regulatory obligation',
    `approval_authority` STRING COMMENT 'Name of the regulatory body or department that granted this approval (e.g., state Department of Insurance, FINRA, internal compliance committee).',
    `approval_date` DATE COMMENT 'Date on which this training course was approved to satisfy this specific regulatory obligation. Explicitly identified in detection reasoning.',
    `approval_number` STRING COMMENT 'State or regulatory body issued approval or CE course number specific to this course-obligation mapping. Explicitly identified in detection reasoning.',
    `approval_status` STRING COMMENT 'Current lifecycle status of this approval mapping: active (currently valid), expired (past expiration date), pending (submitted for approval), revoked (approval withdrawn), superseded (replaced by newer version).',
    `ce_credit_hours` DECIMAL(18,2) COMMENT 'Number of continuing education credit hours awarded for completing this course in the context of satisfying this specific regulatory obligation. May vary by obligation. Explicitly identified in detection reasoning.',
    `course_version` STRING COMMENT 'Specific version of the training course that is approved for this obligation. When course content is updated, re-approval may be required. Explicitly identified in detection reasoning.',
    `expiration_date` DATE COMMENT 'Date on which this approval expires and the course must be re-approved or replaced to continue satisfying the obligation. Explicitly identified in detection reasoning.',
    `jurisdiction_applicability` STRING COMMENT 'Comma-separated list of US state codes or ALL indicating which jurisdictions recognize this course as satisfying this obligation. Approval may be jurisdiction-specific. Explicitly identified in detection reasoning.',
    `last_review_date` DATE COMMENT 'Date on which this approval mapping was last reviewed for continued validity and accuracy.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of this approval mapping to ensure continued compliance.',
    `regulatory_citation` STRING COMMENT 'Specific regulatory rule, statute, or model act citation that mandates this training (e.g., FinCEN 31 CFR §1010.210, HIPAA 45 CFR §164.530(b), NAIC Suitability in Annuity Transactions Model Regulation #275, FINRA Rule 1240). Used in regulatory examination responses and compliance attestations. [Moved from training_course: While a course may satisfy multiple regulatory obligations, the specific citation is tied to the obligation being satisfied, not the course itself. This creates redundancy in the course table and should be managed through the approval relationship.]',
    CONSTRAINT pk_course_approval PRIMARY KEY(`course_approval_id`)
) COMMENT 'This association product represents the regulatory approval mapping between training courses and regulatory obligations. It captures which training courses satisfy which regulatory obligations, including jurisdiction-specific approval details, CE credit mappings, approval lifecycle dates, and version tracking. Each record links one training course to one regulatory obligation with attributes that exist only in the context of this approval relationship. Serves as the authoritative source for demonstrating regulatory compliance through approved training curriculum.. Existence Justification: In life insurance compliance operations, training courses are designed to satisfy multiple regulatory obligations (e.g., a single ethics course may satisfy state insurance department requirements, FINRA rules, and internal policy mandates), and regulatory obligations are typically satisfied by multiple approved courses (e.g., AML obligations can be met through various approved training programs). Compliance teams actively manage course approval mappings, track jurisdiction-specific approvals, monitor expiration dates, and maintain version-specific approval records as a core business process.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`contract_regulatory_compliance` (
    `contract_regulatory_compliance_id` BIGINT COMMENT 'Unique surrogate identifier for each contract-obligation compliance tracking record',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation that applies to this vendor contract',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to the vendor contract subject to this regulatory obligation',
    `assigned_compliance_officer` STRING COMMENT 'Name or employee identifier of the compliance officer assigned to monitor and verify this specific contract-obligation compliance relationship.',
    `attestation_required_flag` BOOLEAN COMMENT 'Indicates whether this specific contract-obligation combination requires formal attestation by an officer or compliance manager. May differ from the general obligation attestation requirement based on contract scope.',
    `compliance_notes` STRING COMMENT 'Free-text notes documenting compliance findings, remediation actions, waiver justifications, or special circumstances for this contract-obligation pair.',
    `compliance_status` STRING COMMENT 'Current compliance status of this vendor contract with respect to this specific regulatory obligation. Tracks whether the contract meets the obligation requirements.',
    `compliance_verification_date` DATE COMMENT 'The date on which compliance with this regulatory obligation was last verified for this vendor contract. Used to track verification currency and trigger re-verification schedules.',
    `effective_date` DATE COMMENT 'The date on which this regulatory obligation became applicable to this specific vendor contract. May differ from the obligations general effective date based on contract execution timing.',
    `expiration_date` DATE COMMENT 'The date on which this regulatory obligation ceases to apply to this vendor contract, typically aligned with contract expiration or obligation sunset. Null if ongoing.',
    `last_audit_date` DATE COMMENT 'The date on which this contract-obligation compliance relationship was last audited by internal audit or external regulators. Tracks audit history for this specific pairing.',
    `next_review_date` DATE COMMENT 'The scheduled date for the next compliance review of this vendor contract against this regulatory obligation. Drives proactive compliance monitoring workflows.',
    CONSTRAINT pk_contract_regulatory_compliance PRIMARY KEY(`contract_regulatory_compliance_id`)
) COMMENT 'This association product represents the compliance relationship between regulatory obligations and vendor contracts. It captures which regulatory obligations apply to which vendor contracts and tracks the compliance verification status, audit history, and attestation requirements for each obligation-contract pair. Each record links one regulatory obligation to one vendor contract with compliance tracking attributes that exist only in the context of this specific regulatory relationship.. Existence Justification: In life insurance operations, a single vendor contract (e.g., TPA administration agreement, data license, custodian agreement) is typically subject to multiple regulatory obligations simultaneously (HIPAA data protection, state insurance filing requirements, SOX financial controls, ERISA fiduciary standards). Conversely, a single regulatory obligation (e.g., HIPAA privacy rule) applies to multiple vendor contracts across different service providers. Compliance officers actively manage this many-to-many relationship by tracking verification status, audit dates, and attestation requirements for each unique obligation-contract pairing.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`entity_license` (
    `entity_license_id` BIGINT COMMENT 'Unique identifier for this legal entity state license record. Primary key.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to the legal entity holding this state license',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to the state-specific insurance regulation that applies to this license',
    `compliance_status` STRING COMMENT 'Current compliance status of this legal entity with respect to this specific state regulation (compliant, non_compliant, pending_review, exempted, suspended, revoked)',
    `effective_date` DATE COMMENT 'Date when this specific legal entitys license became effective in this state jurisdiction. This is entity-specific and may differ from the regulations general effective_date.',
    `exemption_flag` BOOLEAN COMMENT 'Indicates whether this legal entity has been granted an exemption from this specific state regulation',
    `exemption_reason` STRING COMMENT 'Business or regulatory justification for why this entity is exempt from this regulation, if exemption_flag is true',
    `expiration_date` DATE COMMENT 'Date when this legal entitys license expires in this state jurisdiction, requiring renewal',
    `last_compliance_review_date` DATE COMMENT 'Date of the most recent compliance review conducted for this entity against this state regulation',
    `license_number` STRING COMMENT 'The specific license or certificate of authority number issued by this state to this legal entity',
    `license_status` STRING COMMENT 'Current operational status of this license (active, inactive, suspended, revoked, pending, expired)',
    `next_compliance_review_date` DATE COMMENT 'Scheduled date for the next compliance review of this entity against this state regulation',
    CONSTRAINT pk_entity_license PRIMARY KEY(`entity_license_id`)
) COMMENT 'This association product represents the License/Registration relationship between state_regulation and legal_entity. It captures the state-specific licensing and regulatory compliance status for each legal entity operating in each jurisdiction. Each record links one state_regulation to one legal_entity with attributes that exist only in the context of this regulatory license relationship.. Existence Justification: In life insurance operations, each legal entity (insurer) must obtain licenses and comply with regulations in every state where it conducts business. A multi-state insurer like MetLife or Prudential is subject to regulations in all 50+ jurisdictions, and each state regulation applies to dozens of licensed insurers operating in that state. The business actively manages these licenses with entity-specific effective dates, compliance statuses, exemptions, and review schedules.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`course_communication` (
    `course_communication_id` BIGINT COMMENT 'Unique surrogate identifier for each training course communication template assignment record',
    `comm_template_id` BIGINT COMMENT 'Foreign key linking to the communication template used for this training course',
    `training_course_id` BIGINT COMMENT 'Foreign key linking to the training course that requires this communication template',
    `certificate_template_flag` BOOLEAN COMMENT 'Indicates whether this template is used to generate completion certificates for learners who pass this training course',
    `completion_notice_flag` BOOLEAN COMMENT 'Indicates whether this template is used to send completion confirmation notices when a learner completes this training course',
    `created_date` TIMESTAMP COMMENT 'Timestamp when this course communication assignment record was created',
    `effective_date` DATE COMMENT 'Date when this communication template assignment becomes effective for this training course. Allows for template changes over time as regulatory requirements evolve.',
    `enrollment_notice_flag` BOOLEAN COMMENT 'Indicates whether this template is used to send enrollment confirmation notices when a learner is enrolled in this training course',
    `expiration_date` DATE COMMENT 'Date when this communication template assignment expires and is no longer used for this training course. NULL indicates no expiration.',
    `is_required` BOOLEAN COMMENT 'Indicates whether this communication is mandatory for regulatory compliance (true) or optional/supplemental (false)',
    `reminder_notice_flag` BOOLEAN COMMENT 'Indicates whether this template is used to send reminder notices to learners who have not yet completed this training course',
    `trigger_timing` STRING COMMENT 'Specifies when this communication should be triggered relative to the training course lifecycle event (e.g., immediate upon enrollment, 7 days before expiration)',
    `created_by` STRING COMMENT 'User or system identifier that created this course communication assignment record',
    CONSTRAINT pk_course_communication PRIMARY KEY(`course_communication_id`)
) COMMENT 'This association product represents the operational assignment between compliance training courses and the communication templates required to support the training lifecycle. It captures which templates are required for each course (enrollment notices, completion certificates, reminder emails, CE credit reports) and when each template becomes effective for that course. Each record links one training course to one communication template with flags indicating the business purpose of that template in the training workflow.. Existence Justification: In life insurance compliance operations, a single training course requires multiple communication templates to support its lifecycle (enrollment confirmation, completion certificate, reminder emails, CE credit reports). Conversely, a single communication template (e.g., a completion certificate template) is reused across multiple training courses. The compliance team actively manages which templates are assigned to each course and when those assignments become effective.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`compliance`.`aml_alert` (
    `aml_alert_id` BIGINT COMMENT 'Primary key for aml_alert',
    `employee_id` BIGINT COMMENT 'Identifier of the compliance analyst or investigator to whom the alert is currently assigned.',
    `party_id` BIGINT COMMENT 'Identifier of the policyholder or customer who is the subject of the AML alert.',
    `in_force_policy_id` BIGINT COMMENT 'Identifier of the insurance policy associated with the alert, if applicable.',
    `qa_reviewer_user_employee_id` BIGINT COMMENT 'Identifier of the QA reviewer who performed the quality assurance review.',
    `transaction_id` BIGINT COMMENT 'Identifier of the specific transaction that triggered the alert, if applicable.',
    `escalated_from_aml_alert_id` BIGINT COMMENT 'Self-referencing FK on aml_alert (escalated_from_aml_alert_id)',
    `aggregated_amount` DECIMAL(18,2) COMMENT 'Total aggregated amount across multiple related transactions within the detection period, if applicable.',
    `alert_amount` DECIMAL(18,2) COMMENT 'Monetary amount associated with the transaction or activity that triggered the alert.',
    `alert_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the alert amount.',
    `alert_number` STRING COMMENT 'Externally-known unique business identifier for the AML alert, used for tracking and regulatory reporting.',
    `alert_severity` STRING COMMENT 'Risk severity classification assigned to the alert based on scoring model and business rules.',
    `alert_status` STRING COMMENT 'Current state of the AML alert in the investigation and disposition workflow.',
    `alert_type` STRING COMMENT 'Classification of the AML alert based on the detection scenario or rule that triggered it. [ENUM-REF-CANDIDATE: transaction_monitoring|customer_screening|sanctions_match|pep_match|adverse_media|structuring|rapid_movement|layering|integration|smurfing|trade_based — promote to reference product]',
    `assigned_timestamp` TIMESTAMP COMMENT 'Date and time when the alert was assigned to an investigator.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the alert record was first created in the system.',
    `detection_period_end_date` DATE COMMENT 'End date of the time window used for transaction aggregation or pattern analysis.',
    `detection_period_start_date` DATE COMMENT 'Start date of the time window used for transaction aggregation or pattern analysis.',
    `detection_scenario_code` STRING COMMENT 'Code identifying the specific AML monitoring rule or scenario that triggered the alert.',
    `detection_scenario_name` STRING COMMENT 'Human-readable name of the AML monitoring rule or scenario that triggered the alert.',
    `detection_timestamp` TIMESTAMP COMMENT 'Date and time when the AML monitoring system detected and generated the alert.',
    `disposition_code` STRING COMMENT 'Code representing the final disposition or outcome of the alert investigation.',
    `disposition_reason` STRING COMMENT 'Detailed explanation of the rationale for the alert disposition decision.',
    `escalation_flag` BOOLEAN COMMENT 'Indicates whether the alert was escalated to senior management or compliance officer for review.',
    `escalation_reason` STRING COMMENT 'Explanation of why the alert was escalated for higher-level review.',
    `escalation_timestamp` TIMESTAMP COMMENT 'Date and time when the alert was escalated.',
    `false_positive_flag` BOOLEAN COMMENT 'Indicates whether the alert was determined to be a false positive after investigation.',
    `false_positive_reason` STRING COMMENT 'Explanation of why the alert was classified as a false positive.',
    `investigation_notes` STRING COMMENT 'Detailed notes and findings documented by the investigator during the alert review process.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the alert record was last updated.',
    `qa_review_outcome` STRING COMMENT 'Outcome of the quality assurance review of the alert disposition.',
    `qa_review_timestamp` TIMESTAMP COMMENT 'Date and time when the quality assurance review was completed.',
    `quality_assurance_review_flag` BOOLEAN COMMENT 'Indicates whether the alert disposition was subject to quality assurance review.',
    `regulatory_jurisdiction` STRING COMMENT 'Two or three-letter code identifying the regulatory jurisdiction applicable to this alert.',
    `review_completed_timestamp` TIMESTAMP COMMENT 'Date and time when the alert review and investigation were completed.',
    `review_start_timestamp` TIMESTAMP COMMENT 'Date and time when the investigator began reviewing the alert.',
    `risk_score` DECIMAL(18,2) COMMENT 'Numerical risk score assigned to the alert by the AML monitoring system, typically ranging from 0 to 100.',
    `sar_bsa_identifier` STRING COMMENT 'Unique 14-digit BSA identifier assigned by FinCEN upon SAR submission.',
    `sar_filed_flag` BOOLEAN COMMENT 'Indicates whether a Suspicious Activity Report was filed with FinCEN as a result of this alert.',
    `sar_filing_date` DATE COMMENT 'Date when the SAR was filed with FinCEN, if applicable.',
    `source_system_code` STRING COMMENT 'Code identifying the AML monitoring system or platform that generated the alert.',
    `transaction_count` STRING COMMENT 'Number of transactions included in the alert aggregation or pattern detection.',
    CONSTRAINT pk_aml_alert PRIMARY KEY(`aml_alert_id`)
) COMMENT 'Master reference table for aml_alert. Referenced by alert_id.';

